# Cache for click IPs - refreshes every 60 seconds (2026-05 — lowered
# from 5 min so newly-burnt IPs from rut_burnt_ips get picked up by
# the next RUT job within ~1 minute instead of up to 5 minutes).
# 2026-01 update — cache is now keyed by user_id (or "__all__" for the
# legacy "scan every DB" caller). This is THE critical fix for the
# "false-positive duplicate IP" bug: previously the dup-IP set
# included clicks from OTHER users' databases too, so user A's RUT
# job would flag IPs that only user B had ever used. Now each user's
# RUT job only checks their OWN per-tenant DB (sub-users share the
# parent's DB automatically via get_db_for_user, so sub-user clicks
# correctly count against the parent's duplicate set — and ONLY the
# parent's).
_click_ips_cache: dict = {
    # legacy global key for the old "scan all DBs" callers
    "__all__": {"ips": set(), "last_updated": 0, "ttl": 60},
}
_CLICK_IPS_CACHE_TTL = 60  # seconds

# Link cache for high traffic - refreshes every 60 seconds
_link_cache = {}
_link_cache_ttl = 30  # Reduced to 30 seconds for more accurate status checking

# NO VPN cache - check fresh every time for accuracy

async def get_cached_link(short_code: str):
    """Get link from cache or database - cache is short-lived for accuracy"""
    global _link_cache
    current_time = time.time()
    
    # Check cache
    if short_code in _link_cache:
        cached = _link_cache[short_code]
        if current_time - cached["time"] < _link_cache_ttl:
            return cached["link"]
    
    # Fetch from database
    link = await db.links.find_one({"short_code": short_code}, {"_id": 0})
    
    # Cache the result (even if None)
    _link_cache[short_code] = {"link": link, "time": current_time}
    
    # Clean old cache entries (keep max 10000)
    if len(_link_cache) > 10000:
        sorted_keys = sorted(_link_cache.keys(), key=lambda k: _link_cache[k]["time"])
        for k in sorted_keys[:5000]:
            del _link_cache[k]
    
    return link

# Helper function to get user-specific database
def get_user_db(user_id: str):
    """Get database for specific main user - sub-users use parent's database"""
    db_name = f"krexion_user_{user_id.replace('-', '_')[:20]}"
    return client[db_name]

def get_db_for_user(user: dict):
    """
    Get the correct database for a user (main user or sub-user).
    - Main users: get their own database
    - Sub-users: get their parent's database
    """
    if user.get("is_sub_user"):
        # Sub-user uses parent's database
        parent_id = user.get("parent_user_id") or user.get("id")
        return get_user_db(parent_id)
    else:
        # Main user uses their own database
        return get_user_db(user["id"])


# ─── Per-user-DB index bootstrap (runs once per process per user) ──────
# Each user has their own MongoDB database (`krexion_user_<id>`). The
# heavy collections (`uploaded_resources`, `items`, `realuser_jobs`) need
# indexes for the queries that run on every request — without these,
# the find+sort on uploads becomes a full collection scan once a user
# accumulates a few thousand uploads.
_user_db_indexed: set = set()
_user_db_index_lock = asyncio.Lock()


async def ensure_user_db_indexes(user_id: str) -> None:
    """Create the hot-path indexes for a user's per-tenant DB. Idempotent
    + cached — the actual `create_index` calls only fire the FIRST time
    a given user_id hits this process. Called from list_uploads and any
    other hot-path endpoint before its first query."""
    if not user_id or user_id in _user_db_indexed:
        return
    async with _user_db_index_lock:
        if user_id in _user_db_indexed:
            return
        try:
            udb = get_user_db(user_id)
            await asyncio.gather(
                # uploaded_resources — list + find by id/type
                udb["uploaded_resources"].create_index([("user_id", 1), ("created_at", -1)]),
                udb["uploaded_resources"].create_index([("user_id", 1), ("type", 1)]),
                udb["uploaded_resources"].create_index([("id", 1)], unique=True, sparse=True),
                # items — RUT/CPI consumption queries
                udb["items"].create_index([("user_id", 1), ("created_at", -1)]),
                udb["items"].create_index([("upload_id", 1)]),
                # clicks — per-user analytics
                udb["clicks"].create_index([("link_id", 1), ("created_at", -1)]),
                udb["clicks"].create_index([("created_at", -1)]),
                udb["clicks"].create_index([("ip_address", 1)]),
                # links — short-code is critical for /r/<code> redirects
                udb["links"].create_index([("user_id", 1)]),
                udb["links"].create_index([("short_code", 1)], unique=True, sparse=True),
                # proxies — picker queries
                udb["proxies"].create_index([("user_id", 1), ("status", 1)]),
                # realuser_jobs / cpi_jobs — list + status polling
                udb["realuser_jobs"].create_index([("user_id", 1), ("created_at", -1)]),
                udb["realuser_jobs"].create_index([("job_id", 1)], unique=True, sparse=True),
                return_exceptions=True,
            )
            _user_db_indexed.add(user_id)
        except Exception as e:  # noqa: BLE001
            logger.warning(f"ensure_user_db_indexes failed for {user_id}: {e}")

async def get_all_click_ips_from_entire_database(
    force_refresh: bool = False,
    user_id: Optional[str] = None,
):
    """Collect click IPs used for duplicate detection.

    2026-01 — `user_id` parameter (CRITICAL FIX):
        When `user_id` is provided (the normal case for any RUT job /
        proxy upload / proxy refresh), we ONLY scan THAT user's own
        per-tenant database (`krexion_user_<id>`). Sub-users share
        the parent's DB by design (see `get_db_for_user`), so a
        sub-user's clicks correctly count against the parent's
        duplicate set — and only the parent's.

        Before this fix the function scanned EVERY `krexion_user_*`
        database and merged their IPs into one global set. That meant
        user A's RUT job got "duplicate IP" rejections for IPs that
        only user B had ever clicked from — completely cross-polluting
        the duplicate detection between tenants. The user reported
        this as "offer-side duplicate" but it was actually our own
        panel's check, fed a poisoned set.

        When `user_id` is None (only the legacy admin debug endpoint
        and the global proxy refresh keep using this path), the old
        "scan all DBs" behavior is preserved.

    Also loads the persistent `rut_burnt_ips` blocklist. When scoped
    to a user, only rows whose `user_ids` array contains this user
    are loaded (see `_persist_burnt_ip` which writes that field).
    """
    cache_key = user_id or "__all__"
    current_time = time.time()
    cached = _click_ips_cache.get(cache_key)

    if (not force_refresh
            and cached
            and cached["ips"]
            and (current_time - cached["last_updated"]) < _CLICK_IPS_CACHE_TTL):
        logger.info(
            f"Using cached IPs for {cache_key}: {len(cached['ips'])} IPs "
            f"(cached {int(current_time - cached['last_updated'])}s ago)"
        )
        return cached["ips"]

    logger.info(f"Refreshing click IPs cache for {cache_key}…")
    all_click_ips: set = set()

    # Fields to check - MUST match link redirect duplicate check fields
    single_ip_fields = ["ip_address", "ipv4", "detected_ip"]
    array_ip_fields = ["proxy_ips", "all_ips"]

    async def extract_ips_from_db(database, db_name=""):
        """Extract all IPs from a database's clicks collection"""
        extracted = set()
        try:
            for field in single_ip_fields:
                try:
                    distinct_ips = await database.clicks.distinct(field)
                    for ip in distinct_ips:
                        if ip and ip != "unknown" and isinstance(ip, str):
                            extracted.add(ip)
                except Exception:
                    pass

            for field in array_ip_fields:
                try:
                    pipeline = [
                        {"$match": {field: {"$exists": True, "$nin": [None, []]}}},
                        {"$unwind": f"${field}"},
                        {"$group": {"_id": f"${field}"}}
                    ]
                    async for doc in database.clicks.aggregate(pipeline):
                        ip = doc.get("_id")
                        if ip and ip != "unknown" and isinstance(ip, str):
                            extracted.add(ip)
                except Exception:
                    pass
        except Exception as e:
            if db_name:
                logger.warning(f"Error extracting IPs from {db_name}: {e}")
        return extracted

    if user_id:
        # ── Per-user (CORRECT for any RUT/proxy duplicate check) ──
        try:
            user_db_instance = get_user_db(user_id)
            user_ips = await extract_ips_from_db(
                user_db_instance, f"krexion_user_{user_id}"
            )
            all_click_ips.update(user_ips)
        except Exception as e:
            logger.error(f"Error fetching IPs from user DB {user_id}: {e}")

        # Also peek at MAIN db.clicks because VERY old accounts may
        # still have content there (pre-per-tenant migration). Scoped
        # by user_id so we don't pick up other users' rows.
        try:
            legacy_links = await db.links.find(
                {"user_id": user_id}, {"_id": 0, "id": 1},
            ).to_list(100000)
            legacy_link_ids = [l["id"] for l in legacy_links if l.get("id")]
            if legacy_link_ids:
                for field in single_ip_fields:
                    try:
                        cursor = db.clicks.find(
                            {"link_id": {"$in": legacy_link_ids}, field: {"$exists": True}},
                            {"_id": 0, field: 1},
                        )
                        async for doc in cursor:
                            ip = doc.get(field)
                            if ip and ip != "unknown" and isinstance(ip, str):
                                all_click_ips.add(ip)
                    except Exception:
                        pass
        except Exception as e:
            logger.warning(f"Legacy main-db scan failed for {user_id}: {e}")

        # Per-user rut_burnt_ips: STRICTLY only rows this user
        # contributed to. Earlier this query also included rows with
        # missing/empty `user_ids` as a "legacy compatibility" path —
        # but those rows (left over from before user-scoping was
        # introduced) get loaded for EVERY user, re-introducing the
        # exact cross-tenant pollution the user reported as
        # "duplicates with no data". Strict scoping is the only
        # correct behavior.
        try:
            burnt_count = 0
            async for doc in db.rut_burnt_ips.find({"user_ids": user_id}, {"ip": 1, "_id": 0}):
                ip = doc.get("ip")
                if ip and isinstance(ip, str):
                    all_click_ips.add(ip.strip())
                    burnt_count += 1
            if burnt_count:
                logger.info(f"Loaded {burnt_count} burnt IPs for user {user_id}")
        except Exception as e:
            logger.warning(f"Could not load rut_burnt_ips for {user_id}: {e}")
    else:
        # ── Legacy "all users" path (kept for debug + global refresh) ──
        try:
            main_ips = await extract_ips_from_db(db, "main_db")
            all_click_ips.update(main_ips)
        except Exception as e:
            logger.error(f"Error fetching IPs from main_db: {e}")

        try:
            db_names = await client.list_database_names()
            user_dbs = [name for name in db_names if name.startswith("krexion_user_")]
            for db_name in user_dbs[:20]:
                try:
                    user_db_instance = client[db_name]
                    user_ips = await extract_ips_from_db(user_db_instance, db_name)
                    all_click_ips.update(user_ips)
                except Exception as e:
                    logger.warning(f"Error fetching IPs from {db_name}: {e}")
        except Exception as e:
            logger.warning(f"Could not list user databases: {e}")

        try:
            burnt_count = 0
            async for doc in db.rut_burnt_ips.find({}, {"ip": 1, "_id": 0}):
                ip = doc.get("ip")
                if ip and isinstance(ip, str):
                    all_click_ips.add(ip.strip())
                    burnt_count += 1
            if burnt_count:
                logger.info(f"Loaded {burnt_count} burnt IPs (global)")
        except Exception as e:
            logger.warning(f"Could not load rut_burnt_ips: {e}")

    # Update cache (per-key)
    _click_ips_cache[cache_key] = {
        "ips": all_click_ips,
        "last_updated": current_time,
    }

    logger.info(f"Cached {len(all_click_ips)} unique IPs for {cache_key}")
    return all_click_ips

app = FastAPI(
    # Use orjson for response serialization — 3-5x faster than stdlib
    # json.dumps, especially for the big jobs / clicks listings.
    # ORJSONResponse also serializes datetime / UUID / set natively, so
    # we never have to manually .isoformat() before returning.
    default_response_class=__import__("fastapi.responses", fromlist=["ORJSONResponse"]).ORJSONResponse,
)

# v1.0.19: clean way to return a body from inside a FastAPI Depends.
# require_local_mode (used as a Depends) needs to short-circuit the
# request with the desktop bridge's response body. We cannot just
# `return` it because Depends results don't replace the response. And
# raising HTTPException(200, detail=body) makes FastAPI wrap it as
# {"detail": body} which breaks frontends that read top-level keys
# like `total` or `job_id`. So we raise this custom exception and
# register a handler below that returns the body VERBATIM.
class _BridgeDone(Exception):
    def __init__(self, status, body):
        self.status = status
        self.body = body


@app.exception_handler(_BridgeDone)
async def _bridge_done_handler(_request, exc: _BridgeDone):
    from fastapi.responses import JSONResponse as _JR
    return _JR(content=exc.body, status_code=exc.status)



