# ─── Cloud vs Local mode gating ───────────────────────────────────────
# When KREXION_MODE=cloud, the server is the public krexion.com edge.
# Heavy CPU/bandwidth features (proxy batch tests, real-user-traffic,
# form-filler, visual-recorder live engine) are blocked and customers
# are pointed to the desktop installer that runs everything on their
# own PC. Cloud handles ONLY: auth, licensing, link redirects, sync API,
# admin panel, marketing site, and light dashboard read-only views.
KREXION_MODE = os.environ.get("KREXION_MODE", "local").lower().strip()
IS_CLOUD = KREXION_MODE == "cloud"

# ─── v2.1.15: Cloud-Auth Bridge ───────────────────────────────────────
# On the DESKTOP install (KREXION_MODE in {"native","local"}) we install
# a middleware that intercepts /api/auth/*, /api/admin/*, /api/license/*,
# /api/links/* and forwards them to krexion.com. Everything else
# (clicks, RUT, conversions, settings, heavy automation) stays local.
# The middleware short-circuits on the cloud itself (no infinite loop).
# See cloud_proxy_module.py for the full design rationale.
try:
    from cloud_proxy_module import install_cloud_proxy, verify_cloud_token
    install_cloud_proxy(app)
except Exception as _cp_err:  # noqa: BLE001
    # Never let a proxy import error kill the whole backend — the
    # local engine still has value even if cloud auth is down.
    logging.getLogger("krexion.cloud_proxy").error(
        f"[cloud_proxy] install failed: {_cp_err}"
    )
    verify_cloud_token = None  # type: ignore


async def _resolve_cloud_user_dict(authorization_header: str) -> Optional[dict]:
    """v2.1.16 — Cloud-Auth Bridge helper for INLINE JWT decode sites
    (RUT screenshot endpoint, Visual Recorder screenshot endpoint,
    WebSocket /ws/clicks). Wraps `verify_cloud_token` + local-mirror
    lookup so each call site stays a one-liner.

    Returns the mirrored local user dict on success, else None. Safe to
    call on the cloud itself (returns None — local JWT path handles it)."""
    if IS_CLOUD or verify_cloud_token is None:
        return None
    try:
        cloud_user = await verify_cloud_token(authorization_header)
    except Exception:  # noqa: BLE001
        return None
    if not cloud_user:
        return None
    try:
        local_user = await main_db.users.find_one(
            {"id": cloud_user.get("id")},
            {"_id": 0, "password_hash": 0},
        )
        if not local_user and cloud_user.get("email"):
            local_user = await main_db.users.find_one(
                {"email": cloud_user.get("email")},
                {"_id": 0, "password_hash": 0},
            )
        if local_user:
            return local_user
        # First sighting on this PC — thin mirror with cloud features.
        mirror = {
            "id": cloud_user.get("id"),
            "email": cloud_user.get("email"),
            "name": cloud_user.get("name") or (cloud_user.get("email") or "").split("@")[0],
            "is_admin": bool(cloud_user.get("is_admin")),
            "status": cloud_user.get("status") or "active",
            "features": cloud_user.get("features") or {},
            "subscription_expires": cloud_user.get("subscription_expires"),
            "created_at": cloud_user.get("created_at") or datetime.utcnow().isoformat(),
            "cloud_synced": True,
        }
        try:
            await main_db.users.insert_one(mirror.copy())
        except Exception:  # noqa: BLE001
            pass
        return mirror
    except Exception:  # noqa: BLE001
        return None


# 2026-05 — strict mode for cloud edge. When true (the NEW DEFAULT as
# of 2026-05 after VPS overload incidents), heavy endpoints (RUT, Form
# Filler, Visual Recorder, bulk proxy tests, bulk click imports) refuse
# to execute on the VPS and force the customer to run them via the
# desktop app. This prevents the cloud server from being overloaded by
# 45+ Chromium browsers when many customers run RUT simultaneously.
#
# Admin opt-OUT path: set STRICT_CLOUD_HEAVY_BLOCK=false in the VPS
# .env (e.g. during a customer rollout window when not everyone has
# the desktop app yet). When false, heavy endpoints fall back to legacy
# cloud-fallback execution (same as pre-2026-05 behaviour).
#
# Pure cloud-edge concern: this flag is ignored entirely on local
# installs (KREXION_MODE != "cloud").
STRICT_CLOUD_HEAVY_BLOCK = (
    os.environ.get("STRICT_CLOUD_HEAVY_BLOCK", "true").lower().strip()
    in ("true", "1", "yes", "on")
)

# ── 2026-05: Runtime DB-backed override for STRICT_CLOUD_HEAVY_BLOCK ──
# Why this exists:
#   Editing the VPS .env + restarting docker-compose every time the
#   admin wants to flip strict-mode is painful (SSH, vim, restart,
#   30s downtime). For an URGENT toggle ("a customer's PC died,
#   temporarily allow VPS fallback for them") this is unworkable.
#   This DB-backed override stores the admin's last-chosen value in
#   `runtime_settings` and overrides the env var at REQUEST time —
#   takes effect instantly across all worker pods (Mongo is shared).
#
# Document shape (single doc in `runtime_settings`):
#   { _id: "strict_heavy_block",
#     enabled: bool | None,           # None == "use env var"
#     updated_at: datetime, updated_by: str (admin_email) }
#
# Resolution order at request time:
#   1. DB override (if `enabled` is True or False)
#   2. STRICT_CLOUD_HEAVY_BLOCK env var
async def get_effective_strict_heavy_block() -> bool:
    """Return the effective strict-heavy-block flag. DB override beats
    env var; on any error (DB down, etc.) we DEFAULT TO STRICT — the
    whole point is to protect the VPS, so failing-open would defeat it."""
    if not IS_CLOUD:
        # Local installs always run heavy work locally — flag is moot.
        return False
    try:
        doc = await db["runtime_settings"].find_one(
            {"_id": "strict_heavy_block"}, {"enabled": 1, "_id": 0}
        )
        if doc and isinstance(doc.get("enabled"), bool):
            return doc["enabled"]
    except Exception as _e:
        # Mongo unreachable etc. — fall through to env var.
        pass
    return STRICT_CLOUD_HEAVY_BLOCK

