async def _inline_upload_refs(user_id: str, kv: list) -> list:
    """v2.1.9 — Resolve any `upload_ua_id` / `upload_ua_ids` /
    `upload_proxy_id` / `upload_proxy_ids` references in a bridge-
    bound form payload by loading the underlying text items from the
    cloud's USER-scoped `uploaded_resources` Mongo collection and
    inlining them as newline-separated `user_agents` / `proxies`
    form values.  The upload-id fields are then DROPPED from the
    payload so the desktop's RUT endpoint takes the paste-text
    branch instead of trying (and failing) to look up the upload in
    its empty local DB.

    Returns the new (key, value) list — order-preserving for
    everything that wasn't touched, with `user_agents` / `proxies`
    appended/merged at the end.  Best-effort: a missing upload or a
    DB error is logged and the original kv is left alone.
    """
    try:
        # Find all keys we care about
        d = dict(kv)
        ua_ids: list = []
        if d.get("upload_ua_ids"):
            ua_ids.extend([s.strip() for s in d["upload_ua_ids"].split(",") if s.strip()])
        if d.get("upload_ua_id"):
            ua_ids.append(d["upload_ua_id"].strip())
        px_ids: list = []
        if d.get("upload_proxy_ids"):
            px_ids.extend([s.strip() for s in d["upload_proxy_ids"].split(",") if s.strip()])
        if d.get("upload_proxy_id"):
            px_ids.append(d["upload_proxy_id"].strip())
        # 2026-06: also resolve automation_json upload ref. The desktop's
        # local DB has NO copy of the cloud's automation JSON templates
        # (they live in cloud's uploaded_resources only), so without
        # inlining the desktop's RUT endpoint fails immediately with
        # "Selected automation JSON is invalid" — silently 500ing the
        # whole bridged job.
        aj_id = (d.get("upload_automation_json_id") or "").strip()

        # 2026-06-25 — also resolve data_file upload ref. Same problem as
        # automation_json above but with a different failure mode: the
        # desktop's BG task can't find the upload doc in its local
        # `uploaded_resources` and fails with "DB doc missing (re-upload
        # required)". The file bytes themselves live ONLY on cloud disk
        # (UPLOADS_DATA_DIR), so we MUST read them here on the cloud edge
        # and inline as base64 in the bridge payload. The desktop's RUT
        # endpoint has been taught (same patch) to decode `data_file_b64`
        # / `data_file_b64_name` form fields back into a file the BG task
        # can consume via the existing inline-file path. Behaviour for
        # `upload_data_file_id` lookups that fail (file vanished from
        # disk, depleted upload, gsheet refetch error) is to log + leave
        # the upload_data_file_id untouched so the desktop surfaces the
        # original error to the user — never silent.
        df_id = (d.get("upload_data_file_id") or "").strip()

        if not ua_ids and not px_ids and not aj_id and not df_id:
            return kv, []

        user_db = get_user_db(user_id)

        async def _load(upload_id: str, expected_type: str) -> list:
            if not upload_id:
                return []
            doc = await user_db["uploaded_resources"].find_one(
                {"id": upload_id, "user_id": user_id, "type": expected_type},
                {"_id": 0},
            )
            if not doc:
                return []
            # Live Google Sheet → re-fetch first column
            gsheet_url = (doc.get("gsheet_url") or "").strip()
            if gsheet_url:
                try:
                    items = await _fetch_gsheet_first_column(gsheet_url)
                except Exception:  # noqa: BLE001
                    items = []
            else:
                items = doc.get("items") or []
            return [str(x).strip() for x in items if str(x).strip()]

        async def _load_aj_text(upload_id: str) -> str:
            """Load an automation_json upload's full text payload."""
            if not upload_id:
                return ""
            doc = await user_db["uploaded_resources"].find_one(
                {"id": upload_id, "user_id": user_id, "type": "automation_json"},
                {"_id": 0},
            )
            if not doc:
                return ""
            # automation_json uploads store the full template either as
            # a single `automation_json` string field OR as `items` list
            # (one big JSON string element) depending on the upload
            # endpoint version. Try both.
            txt = doc.get("automation_json") or ""
            if not txt:
                items = doc.get("items") or []
                if items and isinstance(items, list):
                    # join with newline OR take first if single
                    if len(items) == 1:
                        txt = str(items[0])
                    else:
                        # multiple steps stored as list of dicts → re-serialize
                        try:
                            import json as _json
                            txt = _json.dumps(items)
                        except Exception:
                            txt = ""
            return str(txt or "").strip()

        ua_items: list = []
        for uid_ in ua_ids:
            ua_items.extend(await _load(uid_, "user_agents"))
        # de-dupe while preserving order
        seen = set()
        ua_items = [x for x in ua_items if not (x in seen or seen.add(x))]

        px_items: list = []
        for uid_ in px_ids:
            px_items.extend(await _load(uid_, "proxies"))
        seen = set()
        px_items = [x for x in px_items if not (x in seen or seen.add(x))]

        aj_text: str = ""
        if aj_id:
            aj_text = await _load_aj_text(aj_id)

        # 2026-06-25 — Resolve data_file upload → multipart file attachment
        # for bridge replay. We rebuild the bridge body as multipart so the
        # desktop's existing `file: Optional[UploadFile]` Form param picks
        # up the data file natively — NO new endpoint code needed on the
        # desktop side. Avoids the urlencoded body limitation (multipart
        # files were getting stripped by the bridge body-capture loop).
        df_bytes: bytes = b""
        df_name: str = ""
        if df_id:
            try:
                pair = await _load_upload_data_file(user_id, df_id)
                if pair:
                    df_path, _df_name_loaded = pair
                    try:
                        with open(df_path, "rb") as _dfh:
                            df_bytes = _dfh.read()
                        df_name = (_df_name_loaded or "data.xlsx")[:200]
                    except Exception as _df_read_err:  # noqa: BLE001
                        logger.warning(
                            f"[bridge] data_file read failed for upload {df_id[:8]}: {_df_read_err}"
                        )
                        df_bytes = b""
                else:
                    logger.warning(
                        f"[bridge] _load_upload_data_file returned None for "
                        f"user={user_id[:8]} id={df_id[:8]} — leaving "
                        f"upload_data_file_id untouched so desktop surfaces "
                        f"the original error."
                    )
            except Exception as _df_err:  # noqa: BLE001
                logger.warning(f"[bridge] data_file inline load failed: {_df_err}")

        # Rebuild kv: drop the upload_*_id keys, merge inline lines
        # into user_agents / proxies, AND inline the automation JSON
        # text so the desktop's RUT endpoint sees `automation_json=...`
        # instead of an unresolvable upload reference.
        DROP = {
            "upload_ua_id", "upload_ua_ids",
            "upload_proxy_id", "upload_proxy_ids",
            "upload_automation_json_id",
        }
        # 2026-06-25 — Only drop upload_data_file_id when we SUCCESSFULLY
        # loaded the file bytes. If load failed (e.g. file vanished from
        # disk), keep the upload_data_file_id in the payload so the
        # desktop's existing "DB doc missing" diagnostic still surfaces
        # the same error to the user instead of silently dropping the
        # data-file reference entirely.
        if df_bytes:
            DROP = DROP | {"upload_data_file_id"}
        new_kv = []
        merged_user_agents_pushed = False
        merged_proxies_pushed = False
        replaced_aj_pushed = False
        for k, v in kv:
            if k in DROP:
                continue
            if k == "user_agents" and ua_items:
                # merge paste lines + inlined upload lines
                existing = [ln.strip() for ln in (v or "").splitlines() if ln.strip()]
                combined = list(dict.fromkeys(existing + ua_items))
                new_kv.append(("user_agents", "\n".join(combined)))
                merged_user_agents_pushed = True
                continue
            if k == "proxies" and px_items:
                existing = [ln.strip() for ln in (v or "").splitlines() if ln.strip()]
                combined = list(dict.fromkeys(existing + px_items))
                new_kv.append(("proxies", "\n".join(combined)))
                merged_proxies_pushed = True
                continue
            if k == "automation_json" and aj_text:
                # paste-text wins; if both present, keep the paste-text
                # so the user's last manual edit is honoured.
                existing_aj = (v or "").strip()
                new_kv.append(("automation_json", existing_aj or aj_text))
                replaced_aj_pushed = True
                continue
            new_kv.append((k, v))
        if ua_items and not merged_user_agents_pushed:
            new_kv.append(("user_agents", "\n".join(ua_items)))
        if px_items and not merged_proxies_pushed:
            new_kv.append(("proxies", "\n".join(px_items)))
        if aj_text and not replaced_aj_pushed:
            new_kv.append(("automation_json", aj_text))

        # 2026-06-25 — Build the optional file-attachments list. The
        # bridge handler will switch the body encoding to multipart and
        # attach these as real `file` upload parts so the desktop's
        # existing `file: Optional[UploadFile]` Form param picks them
        # up — no desktop-side decoding required.
        file_attachments: list = []
        if df_bytes:
            file_attachments.append(("file", df_name or "data.xlsx", df_bytes))

        logger.info(
            f"[bridge] inlined uploads for user={user_id[:8]} "
            f"ua_ids={len(ua_ids)} ua_items={len(ua_items)} "
            f"px_ids={len(px_ids)} px_items={len(px_items)} "
            f"aj_id={'yes' if aj_id else 'no'} aj_chars={len(aj_text)} "
            f"df_id={'yes' if df_id else 'no'} df_bytes_kb={len(df_bytes)//1024 if df_bytes else 0}"
        )
        return new_kv, file_attachments
    except Exception as e:  # noqa: BLE001
        logger.warning(f"[bridge] _inline_upload_refs failed: {e}")
        return kv, []


async def require_local_mode(request: Request):
    """FastAPI dependency for heavy operations (RUT, Form Filler, etc).

    Decision matrix (2026-06 — STRICT enforcement):

      • Bridge worker call (X-Krexion-Bridge-Job header set)
            → ALWAYS allow. This is the customer's own desktop app
              fulfilling a queued job — it MUST execute or the bridge
              loop breaks.

      • KREXION_MODE != "cloud" (i.e. a local install)
            → ALWAYS allow. The whole point of the local install is to
              run heavy work locally.

      • Cloud edge + STRICT_CLOUD_HEAVY_BLOCK=false (legacy opt-out)
            → allow (the endpoint may still try to bridge first; if the
              bridge fails it falls back to cloud execution as before).

      • Cloud edge + STRICT_CLOUD_HEAVY_BLOCK=true (default)
            → ALWAYS REFUSE on cloud. Heavy work (RUT, Form Filler,
              Visual Recorder, bulk proxy tests) must run on the
              customer's desktop app. Even if their PC is currently
              heart-beating, we refuse cloud execution — this is the
              customer's explicit ask:
              "abi pure load docker k throw chalna chahye sab".
              The 503 response carries `local_status` so the frontend
              modal can show the right copy:
                 - PC online → "Switch to your desktop app to start"
                 - PC stale  → "Turn on your PC and the desktop app"
                 - No PC yet → "Install the Krexion desktop app"
    """
    if request.headers.get("X-Krexion-Bridge-Job"):
        return True
    if not IS_CLOUD:
        return True
    # 2026-05: use the DB-backed override so the admin's last UI-toggle
    # decision wins over the env var without needing a restart.
    if not await get_effective_strict_heavy_block():
        return True

    # ── 2026-06 (replaces 2026-05 online-bypass) ──
    # Previous behaviour:
    #   Cloud + strict + PC ONLINE → ALLOWED VPS execution.
    # This caused exactly the VPS-overload the customer reported when
    # they kicked off a big RUT job — the heavy Chromium fleet ran on
    # the cloud VPS even though their PC was connected, because the
    # gate considered "online PC = customer accountable" sufficient.
    #
    # New behaviour:
    #   Cloud + strict = REFUSE inline cloud execution period.
    #   The customer's desktop app is the only legitimate executor.
    # We still surface `local_status` so the frontend can render the
    # most relevant 503 modal copy.
    local_status: Dict[str, Any] = {"online": False, "reason": "status_unknown"}
    try:
        from bridge_module import is_user_local_online as _is_online
        auth = request.headers.get("Authorization") or ""
        token = auth[7:] if auth.lower().startswith("bearer ") else ""
        if token:
            try:
                _payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
                # JWT `sub` is the user's EMAIL (see get_current_user
                # line ~1220). Heartbeats key on `user_id` (the doc
                # UUID), so resolve email→user_id before lookup.
                _uid = _payload.get("user_id")
                if not _uid:
                    _email = _payload.get("sub")
                    if _email:
                        _u = await db.users.find_one(
                            {"email": _email}, {"id": 1, "_id": 0}
                        )
                        if _u:
                            _uid = _u.get("id")
                if _uid:
                    local_status = await _is_online(_uid)
            except Exception:
                pass
    except Exception:
        pass

    # Pick the most actionable hint for the frontend's "open desktop
    # app" modal. Customers with an online PC are the easiest case —
    # they just need to launch the desktop app instead of clicking the
    # cloud UI button.
    if local_status.get("online"):
        actionable_hint = "use_desktop_app"
    elif local_status.get("reason") == "stale_heartbeat":
        actionable_hint = "turn_on_pc"
    else:
        actionable_hint = "install_desktop_app"

    # v1.0.14 NEW: bridge auto-route.
    # If the customer's PC is currently ONLINE (heart-beating in the
    # last 90 s), don't refuse with 503 - instead AUTO-ENQUEUE this
    # heavy job into the bridge queue so the desktop app picks it up
    # and executes locally. This is the customer's explicit ask:
    #   "heavy job customer k pc k throw chalne chahye krexion.com pr
    #    koi error ni ana chahye"
    # The bridge worker on the customer's machine polls /api/bridge/next
    # every few seconds, runs the job, and posts results back, so the
    # cloud just becomes a thin router. The original endpoint's
    # response is short-circuited via this exception, so the frontend
    # sees a 202-style success instead of a 503 refusal.
    #
    # We attempt this BEFORE refusing - if enqueue fails for any reason
    # (bridge module not loaded, race condition, etc.) we still fall
    # through to the 503 so the user gets a clear message.
    if local_status.get("online"):
        try:
            try:
                from bridge_module import enqueue_bridge_job as _enq  # type: ignore
            except Exception:
                _enq = None
            if _enq is not None and _uid:
                # v1.0.18 FIX: previously we only called request.json() to
                # capture the body. That silently returned {} for ANY
                # multipart/form-data request — i.e. EVERY RUT / Form-Filler
                # / Visual-Recorder submission. The desktop bridge worker
                # then replayed an empty JSON body against its local
                # backend, which immediately 422'd because those endpoints
                # require Form(...) fields. Net result: heavy job vanished
                # silently. Now we capture the raw body bytes + the
                # original content-type so the bridge worker can replay
                # multipart EXACTLY as the cloud received it. We also
                # forward the user's Authorization (JWT) header so the
                # local backend's get_current_user dependency succeeds
                # (it would otherwise 401 because sync_client only sets
                # X-Krexion-License which most heavy endpoints don't read).
                import base64 as _b64
                # v2.1.6: DO NOT await request.body() — Starlette
                # caches the bytes in _body but FastAPI Form() parser
                # reads from request.stream() which is then EXHAUSTED
                # → server returns 422 "Field required (body.link_id)".
                # Instead capture via request.form() for multipart (it
                # populates _form cache so downstream Form() parser
                # uses the same data) and serialise back to raw bytes
                # for bridge replay.
                content_type = request.headers.get("content-type", "")
                auth_hdr = request.headers.get("Authorization", "")
                raw_body = b""
                body_json: dict = {}
                ct_lower = content_type.lower()
                try:
                    if "multipart/form-data" in ct_lower or "application/x-www-form-urlencoded" in ct_lower:
                        form = await request.form()
                        # Rebuild a tiny urlencoded representation for the
                        # bridge - desktop side reconstructs FormData from
                        # body_json fields. Files in multipart are best-effort.
                        from urllib.parse import urlencode as _urlencode
                        kv = []
                        for k, v in form.multi_items():
                            if hasattr(v, "filename") and v.filename:
                                # skip files - they should pre-upload anyway
                                continue
                            kv.append((k, str(v)))

                        # v2.1.9 INLINE-UPLOADS: the cloud's
                        # `uploaded_resources` collection lives in
                        # USER-scoped Mongo on the cloud only.  The
                        # desktop's bundled v2.1.4 server.py has NO
                        # /api/sync/uploads endpoint, so we can't push
                        # the upload doc across.  Instead, RESOLVE the
                        # upload contents here at the cloud edge and
                        # inline them as `user_agents` / `proxies`
                        # text lines, then strip the
                        # `upload_*_id(s)` fields.  The desktop's RUT
                        # endpoint already accepts paste-text input,
                        # so it sees a fully self-contained payload
                        # and never queries its own (empty) uploads
                        # collection.  Works against ANY desktop
                        # client version, no rebuild needed.
                        try:
                            kv, file_attachments = await _inline_upload_refs(_uid, kv)
                        except Exception as _inline_err:  # noqa: BLE001
                            logger.warning(f"[bridge] upload inline failed: {_inline_err}")
                            file_attachments = []

                        # 2026-06-25 — If `_inline_upload_refs` produced
                        # any file attachments (e.g. the saved data_file
                        # was resolved into bytes), rebuild the body as
                        # multipart/form-data with those files attached.
                        # The desktop's existing endpoint signature
                        # already has `file: Optional[UploadFile] =
                        # File(None)` so it picks them up natively — no
                        # desktop-side code change required.  Otherwise
                        # stick with the urlencoded body (smaller +
                        # backwards-compatible).
                        if file_attachments:
                            try:
                                from urllib3.filepost import encode_multipart_formdata as _enc_mp
                                fields_for_mp: list = []
                                for k_, v_ in kv:
                                    fields_for_mp.append((k_, str(v_)))
                                for fname, filename, fbytes in file_attachments:
                                    fields_for_mp.append(
                                        (fname, (filename, fbytes, "application/octet-stream"))
                                    )
                                raw_body, content_type = _enc_mp(fields_for_mp)
                                # body_json is a best-effort dict for any
                                # bridge consumer that prefers JSON; we
                                # exclude binary file bytes from it.
                                body_json = {k: v for k, v in kv}
                                logger.info(
                                    f"[bridge] multipart-mode body built "
                                    f"fields={len(kv)} attachments={len(file_attachments)} "
                                    f"body_bytes={len(raw_body)}"
                                )
                            except Exception as _mp_err:  # noqa: BLE001
                                logger.warning(
                                    f"[bridge] multipart build failed, "
                                    f"falling back to urlencoded: {_mp_err}"
                                )
                                raw_body = _urlencode(kv).encode("utf-8")
                                body_json = {k: v for k, v in kv}
                                content_type = "application/x-www-form-urlencoded"
                        else:
                            # No file attachments — urlencoded as before
                            raw_body = _urlencode(kv).encode("utf-8")
                            body_json = {k: v for k, v in kv}
                            content_type = "application/x-www-form-urlencoded"
                    elif "application/json" in ct_lower:
                        try:
                            body_json = await request.json()
                        except Exception:
                            body_json = {}
                        if not isinstance(body_json, dict):
                            body_json = {}
                        import json as _j
                        raw_body = _j.dumps(body_json).encode("utf-8")
                except Exception as _bc_err:
                    logger.warning(f"[bridge] body capture failed: {_bc_err}")
                # Use the URL path (minus /api/) as the feature key so
                # the desktop bridge worker knows which local endpoint
                # to replay against.
                feature = request.url.path
                if feature.startswith("/api/"):
                    feature = feature[5:]
                feature = feature.strip("/")
                payload = {
                    "method": request.method.upper(),
                    "path": request.url.path,
                    "body": body_json,
                    "query": dict(request.query_params),
                    # NEW v1.0.18: raw body + content-type + auth for
                    # faithful multipart replay on the desktop bridge.
                    "raw_body_b64": _b64.b64encode(raw_body).decode("ascii") if raw_body else "",
                    "content_type": content_type,
                    "authorization": auth_hdr,
                }
                logger.info(
                    f"[bridge] auto-route {feature} → user={_uid[:8]} "
                    f"method={payload['method']} ct={content_type[:40]} "
                    f"body_bytes={len(raw_body)}"
                )

                # v2.1.7 PRE-SYNC: The desktop's local Mongo is a
                # separate DB from the cloud. When a user creates a
                # link on the krexion.com UI it lands ONLY in the
                # cloud DB. The desktop's RUT/Form-Filler endpoint
                # then 404s with "Link not found" because the link
                # doesn't exist locally yet. Sync_client only PUSHES
                # links cloud-ward, never the other way.
                #
                # Fix: when the bridged request carries a `link_id`,
                # FIRST enqueue a tiny /api/sync/links POST bridge
                # job so the desktop's local DB is populated, THEN
                # enqueue the actual heavy job. Both run on the same
                # desktop worker that's already heartbeating, total
                # added latency is ~1 polling cycle (~5s).
                _link_id = (body_json or {}).get("link_id")
                if _link_id and isinstance(_link_id, str):
                    try:
                        _link = await db.links.find_one(
                            {"id": _link_id, "user_id": _uid},
                            {"_id": 0},
                        )
                        if _link and _link.get("short_code"):
                            # Build a minimal link doc with the cloud's
                            # `id` so the desktop's lookup
                            # (db.links.find_one({"id": link_id,
                            # "user_id": user.id})) matches exactly.
                            _sync_body = {
                                "links": [{
                                    "id": _link.get("id"),
                                    "short_code": _link.get("short_code"),
                                    "offer_url": _link.get("offer_url") or _link.get("destination_url") or "",
                                    "name": _link.get("name", ""),
                                    "status": _link.get("status", "active"),
                                    "allowed_countries": _link.get("allowed_countries", []) or [],
                                    "allowed_os": _link.get("allowed_os", []) or [],
                                    "block_vpn": bool(_link.get("block_vpn", False)),
                                }]
                            }
                            import json as _j2
                            _sync_raw = _j2.dumps(_sync_body).encode("utf-8")
                            _sync_payload = {
                                "method": "POST",
                                "path": "/api/sync/links",
                                "body": _sync_body,
                                "query": {},
                                "raw_body_b64": _b64.b64encode(_sync_raw).decode("ascii"),
                                "content_type": "application/json",
                                # No JWT — the desktop's /api/sync/links
                                # authenticates via X-Krexion-License,
                                # which sync_client always attaches.
                                "authorization": "",
                            }
                            logger.info(
                                f"[bridge] pre-sync link {_link.get('short_code')} "
                                f"(id={str(_link.get('id'))[:8]}) to desktop for user={_uid[:8]}"
                            )
                            try:
                                _presync_resp = await _enq(
                                    {"id": _uid, "email": local_status.get("email")},
                                    "sync/links",
                                    _sync_payload,
                                    wait_for_result=True,
                                    wait_timeout=15,
                                )
                                logger.info(
                                    f"[bridge] pre-sync link done status={(_presync_resp or {}).get('status')}"
                                )
                            except Exception as _ps_err:  # noqa: BLE001
                                # Pre-sync failures should NOT block
                                # the main job — desktop might already
                                # have the link from a prior push or
                                # the user could be running an older
                                # client that doesn't have /api/sync/
                                # links bound. Best-effort, log and
                                # carry on; main job will surface the
                                # 404 if the link genuinely isn't
                                # there.
                                logger.warning(f"[bridge] pre-sync link failed (continuing): {_ps_err}")
                    except Exception as _link_lookup_err:  # noqa: BLE001
                        logger.warning(f"[bridge] link lookup failed: {_link_lookup_err}")

                # v2.1.7 PRE-SYNC PROXYJET CREDENTIALS: when the
                # bridged heavy job toggles use_proxyjet_auto=true,
                # the desktop's RUT endpoint checks
                # db.proxyjet_credentials.find_one({user_id}) which
                # is empty on a fresh customer install — the
                # credentials live ONLY in the cloud DB after the
                # user saved them on krexion.com → Proxies. Mirror
                # them across via the existing
                # /api/proxyjet/credentials POST (JWT-authed; the
                # bridge replay mints a local JWT for the same
                # user).
                _use_pj_auto = str((body_json or {}).get("use_proxyjet_auto", "")).lower() in ("true", "1", "yes")
                if _use_pj_auto:
                    try:
                        from proxyjet_module import get_credentials as _pj_get  # type: ignore
                        _pj_creds = await _pj_get(db, _uid)
                        if _pj_creds and _pj_creds.get("username") and _pj_creds.get("password"):
                            _pj_body = {
                                "username": _pj_creds.get("username", ""),
                                "password": _pj_creds.get("password", ""),
                                "server": _pj_creds.get("server") or "proxy-jet.io",
                                "port": int(_pj_creds.get("port") or 1010),
                                "default_country": (_pj_creds.get("default_country") or "US"),
                                "default_state": _pj_creds.get("default_state") or "",
                                "gateway": _pj_creds.get("gateway") or "ca",
                                "product": _pj_creds.get("product") or "resi",
                            }
                            import json as _j3
                            _pj_raw = _j3.dumps(_pj_body).encode("utf-8")
                            _pj_sync_payload = {
                                "method": "POST",
                                "path": "/api/proxyjet/credentials",
                                "body": _pj_body,
                                "query": {},
                                "raw_body_b64": _b64.b64encode(_pj_raw).decode("ascii"),
                                "content_type": "application/json",
                                # Forward the cloud JWT — sync_client
                                # will replace it with a local-minted
                                # JWT for the same user before replay,
                                # so the local get_current_user
                                # dependency succeeds.
                                "authorization": auth_hdr,
                            }
                            logger.info(
                                f"[bridge] pre-sync ProxyJet creds for user={_uid[:8]} "
                                f"(username={_pj_creds.get('username','')[:8]}...)"
                            )
                            try:
                                _pj_presync_resp = await _enq(
                                    {"id": _uid, "email": local_status.get("email")},
                                    "proxyjet/credentials",
                                    _pj_sync_payload,
                                    wait_for_result=True,
                                    wait_timeout=15,
                                )
                                logger.info(
                                    f"[bridge] pre-sync ProxyJet creds done "
                                    f"status={(_pj_presync_resp or {}).get('status')}"
                                )
                            except Exception as _pjps_err:  # noqa: BLE001
                                logger.warning(f"[bridge] pre-sync ProxyJet creds failed (continuing): {_pjps_err}")
                    except Exception as _pj_lookup_err:  # noqa: BLE001
                        logger.warning(f"[bridge] ProxyJet creds lookup failed: {_pj_lookup_err}")

                bridge_resp = await _enq(
                    {"id": _uid, "email": local_status.get("email")},
                    feature,
                    payload,
                    wait_for_result=True,
                    wait_timeout=25,
                )
                # When the desktop completes synchronously, return its body.
                # When still pending, hand back the job_id so the frontend
                # can poll /api/bridge/jobs/{id} (existing flow).
                if bridge_resp:
                    _status = bridge_resp.get("status")
                    logger.info(
                        f"[bridge] auto-route {feature} job_id={bridge_resp.get('job_id','')[:8]} "
                        f"status={_status}"
                    )
                    if _status == "done":
                        result = bridge_resp.get("result") or {}
                        # v1.0.19: previously raised HTTPException(200,
                        # detail=...) which made FastAPI wrap the body
                        # as {"detail": <body>}. Frontend then saw
                        # data.total === undefined and surfaced
                        # "Job started: undefined visit(s) queued"
                        # (exactly the customer's RUT screenshot).
                        # Use _BridgeDone so the registered handler
                        # returns the local backend's body verbatim.
                        raise _BridgeDone(
                            status=int(result.get("status") or 200),
                            body=result.get("body") if result.get("body") is not None else {"ok": True, "via": "bridge"},
                        )
                    if _status == "failed":
                        raise HTTPException(
                            status_code=500,
                            detail={"error": "bridge_execution_failed", "reason": bridge_resp.get("error")},
                        )
                    # pending / timeout: hand back the job id for polling.
                    # Use _BridgeDone (not HTTPException) so the body is
                    # returned VERBATIM as top-level JSON, otherwise
                    # FastAPI wraps it under {"detail": ...} and the
                    # frontend can't read top-level `job_id`.
                    raise _BridgeDone(
                        status=202,
                        body={
                            "queued": True,
                            "via": "bridge",
                            "job_id": bridge_resp.get("job_id"),
                            "message": "Job routed to your PC - polling for completion",
                        },
                    )
        except HTTPException:
            raise
        except _BridgeDone:
            # MUST propagate — handler converts to plain JSONResponse.
            raise
        except Exception as _bridge_err:  # noqa: BLE001
            logger.warning(f"[require_local_mode] bridge route failed for user {_uid}: {_bridge_err}")

    raise HTTPException(
        status_code=503,
        detail={
            "code": "local_pc_offline",  # kept for frontend interceptor compat
            "error": "local_pc_required",
            "message": CLOUD_HEAVY_BLOCKED_MSG,
            "download_url": "https://krexion.com/download",
            "local_status": local_status,
            "actionable_hint": actionable_hint,
        },
    )



