# v2.1.2: public status page endpoint - no auth required so it can be
# used as a customer-facing trust signal and for global launch.
@app.get("/api/public/status")
async def public_status():
    from datetime import datetime, timedelta, timezone
    now = datetime.now(timezone.utc)
    # API ok if we got this far
    api_ok = True
    # Mongo ok if we can ping
    mongo_ok = False
    try:
        await db.command("ping")
        mongo_ok = True
    except Exception:  # noqa: BLE001
        mongo_ok = False
    # Online PCs - heartbeats in last 90 s
    online_pcs = 0
    try:
        cutoff = now - timedelta(seconds=90)
        online_pcs = await db.sync_heartbeats.count_documents({
            "last_seen": {"$gte": cutoff}
        })
    except Exception:  # noqa: BLE001
        pass
    # Active users 24h - users who logged in in last day
    active_users_24h = 0
    try:
        cutoff_24h = (now - timedelta(hours=24)).isoformat()
        active_users_24h = await db.users.count_documents({
            "last_login_at": {"$gte": cutoff_24h}
        })
    except Exception:  # noqa: BLE001
        pass
    # Bridge job buckets - last 24h
    bridge_jobs_24h = {"pending": 0, "running": 0, "done": 0, "failed": 0}
    try:
        cutoff_24h_iso = (now - timedelta(hours=24)).isoformat()
        for st in bridge_jobs_24h.keys():
            bridge_jobs_24h[st] = await db.bridge_jobs.count_documents({
                "status": st,
                "created_at": {"$gte": cutoff_24h_iso},
            })
    except Exception:  # noqa: BLE001
        pass
    # Version
    version_str = "unknown"
    try:
        from pathlib import Path as _P
        for p in (_P(__file__).parent / "VERSION", _P("/app/backend/VERSION")):
            if p.exists():
                version_str = p.read_text(encoding="utf-8").strip()
                break
    except Exception:  # noqa: BLE001
        pass
    return {
        "api_ok": api_ok,
        "mongo_ok": mongo_ok,
        "online_pcs": online_pcs,
        "active_users_24h": active_users_24h,
        "bridge_jobs_24h": bridge_jobs_24h,
        "bridge_workers": online_pcs,
        "version": version_str,
        "now": now.isoformat(),
    }


# v2.1.5: TEMPORARY debug log endpoint. Frontend axios interceptor
# mirrors every request/response here so admin can inspect remotely.
# Stored in `debug_events` collection with 24h TTL. NO auth strictly
# required (interceptor sends Authorization opportunistically) — we
# accept the call regardless so failed-auth events also get captured.
@app.post("/api/debug/log")
async def debug_log(request: Request):
    try:
        body = await request.json()
    except Exception:
        body = {}
    if not isinstance(body, dict):
        body = {"raw": str(body)[:1000]}
    # Try to resolve the user from the auth header (best-effort, no raise)
    user_email = None
    try:
        auth = request.headers.get("Authorization") or ""
        if auth.startswith("Bearer "):
            tok = auth.split(" ", 1)[1]
            from jose import jwt as _jwt
            payload = _jwt.decode(tok, SECRET_KEY, algorithms=[ALGORITHM])
            user_email = payload.get("sub")
    except Exception:  # noqa: BLE001
        pass
    from datetime import datetime as _dt, timezone as _tz
    doc = {
        "ts": _dt.now(_tz.utc),
        "user_email": user_email,
        "client_ip": getattr(request.client, "host", None),
        "method": str(body.get("method", ""))[:10],
        "url": str(body.get("url", ""))[:500],
        "status": int(body.get("status") or 0),
        "duration_ms": int(body.get("duration_ms") or 0),
        "error": str(body.get("error") or "")[:500],
        "request_body": body.get("request_body"),
        "response_body": body.get("response_body"),
    }
    try:
        await db.debug_events.insert_one(doc)
        # Best-effort TTL index — ignore failures if already exists.
        try:
            await db.debug_events.create_index("ts", expireAfterSeconds=86400)
        except Exception:  # noqa: BLE001
            pass
    except Exception as _e:  # noqa: BLE001
        logger.warning(f"[debug_log] insert failed: {_e}")
    return {"ok": True}


@app.get("/api/debug/events")
async def debug_events_list(request: Request, limit: int = 100):
    """Admin-only readout of the last N debug events for the current
    user. Use this to inspect what a remote customer is seeing."""
    user = await get_current_user(request)
    cursor = db.debug_events.find(
        {"user_email": user.get("email")},
        {"_id": 0},
    ).sort("ts", -1).limit(min(limit, 500))
    items = []
    async for d in cursor:
        # Stringify the timestamp for JSON serialisation
        if hasattr(d.get("ts"), "isoformat"):
            d["ts"] = d["ts"].isoformat()
        items.append(d)
    return {"items": items}



# Debug endpoint to search for a specific IP in ALL databases
@app.get("/debug-search-ip/{ip}")
@app.get("/api/debug-search-ip/{ip}")
async def debug_search_ip(ip: str):
    """Search for an IP in ALL databases - for debugging duplicate issues"""
    results = {
        "searched_ip": ip,
        "found_in": [],
        "total_found": 0
    }
    
    ip_conditions = [
        {"ip_address": ip},
        {"ipv4": ip},
        {"ipv4": ip},
        {"detected_ip": ip},
        {"all_ips": ip},
        {"proxy_ips": ip}
    ]
    duplicate_query = {"$or": ip_conditions}
    
    # Check main database
    try:
        count = await db.clicks.count_documents(duplicate_query)
        if count > 0:
            results["found_in"].append({"database": "main_db", "count": count})
            results["total_found"] += count
    except Exception as e:
        results["found_in"].append({"database": "main_db", "error": str(e)})
    
    # Check ALL user databases
    try:
        all_db_names = await client.list_database_names()
        user_databases = [name for name in all_db_names if name.startswith("krexion_user_")]
        
        for db_name in user_databases:
            try:
                user_db_instance = client[db_name]
                count = await user_db_instance.clicks.count_documents(duplicate_query)
                if count > 0:
                    results["found_in"].append({"database": db_name, "count": count})
                    results["total_found"] += count
            except:
                continue
    except Exception as e:
        results["error"] = str(e)
    
    return results

