def verify_password(plain_password, hashed_password):
    return pwd_context.verify(plain_password, hashed_password)

def get_password_hash(password):
    return pwd_context.hash(password)

def create_access_token(data: dict):
    to_encode = data.copy()
    expire = datetime.now(timezone.utc) + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode.update({"exp": expire})
    encoded_jwt = jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)
    return encoded_jwt

async def get_current_user(request: Request):
    # v2.1.0: bridge-mode bypass. Sync_client replays cloud heavy
    # jobs by POSTing to its OWN local backend with X-Krexion-Bridge-Job
    # header. The forwarded Authorization JWT was signed with the
    # CLOUD's SECRET_KEY which differs from the local SECRET_KEY, so
    # naive JWT verification 401's even though the request is
    # legitimate (it physically came from the local sync_client
    # process). We trust the header when:
    #   1) KREXION_MODE != cloud   (only the local install honours it)
    #   2) Request source is loopback (127.0.0.1 / ::1)
    #   3) X-Krexion-License header is present and validates
    # In that case we resolve the user from the license_key and return
    # immediately (skips JWT verification entirely).
    if (
        not IS_CLOUD
        and request.headers.get("X-Krexion-Bridge-Job") == "1"
    ):
        client_host = (getattr(request.client, "host", "") or "").lower()
        if client_host in {"127.0.0.1", "localhost", "::1"}:
            br_lic = request.headers.get("X-Krexion-License", "").strip()
            if br_lic:
                lic_doc = await db.licenses.find_one(
                    {"license_key": br_lic}, {"_id": 0}
                )
                if lic_doc:
                    # Find user by license user_id OR email
                    uid = lic_doc.get("user_id")
                    lic_email = lic_doc.get("email")
                    user = None
                    if uid:
                        user = await db.users.find_one({"id": uid}, {"_id": 0})
                    if not user and lic_email:
                        user = await db.users.find_one({"email": lic_email}, {"_id": 0})
                    if not user and lic_email:
                        # Auto-create local user mirror for first-ever
                        # bridge call before the heartbeat mirror runs.
                        import uuid as _uuid
                        new_uid = uid or _uuid.uuid4().hex
                        new_user = {
                            "id": new_uid,
                            "email": lic_email,
                            "name": lic_email.split("@")[0],
                            "is_admin": False,
                            "status": "active",
                            "created_at": datetime.utcnow().isoformat(),
                            "bridge_synced": True,
                        }
                        await db.users.insert_one(new_user)
                        user = new_user
                    if user:
                        logger.info(
                            f"[bridge] get_current_user via license_key for {user.get('email')}"
                        )
                        return user

    auth_header = request.headers.get("Authorization")
    if not auth_header or not auth_header.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    token = auth_header.split(" ")[1]
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        email: str = payload.get("sub")
        is_sub_user: bool = payload.get("is_sub_user", False)
        parent_user_id: str = payload.get("parent_user_id")
        if email is None:
            raise HTTPException(status_code=401, detail="Invalid token")
    except JWTError:
        # ─── v2.1.15: Cloud-Auth Bridge fallback ────────────────────
        # The JWT couldn't be verified with the LOCAL SECRET_KEY. On a
        # desktop install this is the COMMON case: the token was
        # issued by krexion.com (different secret) when the user
        # logged in via the cloud-proxy. Verify it against the cloud
        # `/api/auth/me` endpoint — `verify_cloud_token` is imported
        # from cloud_proxy_module at startup; it has a built-in
        # 5-minute cache so we don't hammer the cloud.
        if not IS_CLOUD and verify_cloud_token is not None:
            try:
                cloud_user = await verify_cloud_token(auth_header)
            except Exception:  # noqa: BLE001
                cloud_user = None
            if cloud_user:
                # Mirror the cloud user into local Mongo so other
                # local endpoints (clicks, RUT, conversions) that
                # join on user_id keep working without a network
                # round-trip on every request.
                local_user = await db.users.find_one(
                    {"id": cloud_user.get("id")}, {"_id": 0}
                )
                if not local_user and cloud_user.get("email"):
                    # Also try by email — older mirrors used different ids
                    local_user = await db.users.find_one(
                        {"email": cloud_user.get("email")}, {"_id": 0}
                    )
                if not local_user:
                    # First time we see this cloud user on this PC —
                    # insert a thin mirror. The cloud is the source of
                    # truth; we never write back to it from here.
                    local_user = {
                        "id": cloud_user.get("id"),
                        "email": cloud_user.get("email"),
                        "name": cloud_user.get("name") or (cloud_user.get("email") or "").split("@")[0],
                        "is_admin": bool(cloud_user.get("is_admin")),
                        "status": cloud_user.get("status") or "active",
                        "created_at": cloud_user.get("created_at") or datetime.utcnow().isoformat(),
                        "cloud_synced": True,
                    }
                    try:
                        await db.users.insert_one(local_user)
                    except Exception:  # noqa: BLE001
                        # Race / duplicate — try fetching once more
                        local_user = await db.users.find_one(
                            {"id": cloud_user.get("id")}, {"_id": 0}
                        ) or cloud_user
                return local_user
        raise HTTPException(status_code=401, detail="Invalid token")
    
    if is_sub_user:
        # Handle sub-user authentication
        sub_user = await db.sub_users.find_one({"email": email}, {"_id": 0})
        if sub_user is None:
            raise HTTPException(status_code=401, detail="Sub-user not found")
        
        # Get parent user for features
        parent_user = await db.users.find_one({"id": parent_user_id}, {"_id": 0})
        if not parent_user or parent_user.get("status") != "active":
            raise HTTPException(status_code=403, detail="Parent account is not active")
        
        # Return sub-user with mapped features
        return {
            "id": parent_user_id,  # Use parent's ID for database access
            "sub_user_id": sub_user["id"],
            "email": sub_user["email"],
            "name": sub_user["name"],
            "is_sub_user": True,
            "parent_user_id": parent_user_id,
            "status": parent_user.get("status", "active"),
            "permissions": sub_user.get("permissions", {}),
            "features": _build_sub_user_features(
                sub_user.get("permissions", {}),
                parent_user.get("features", {}),
            ),
        }
    
    # Handle main user authentication
    user = await db.users.find_one({"email": email}, {"_id": 0})
    if user is None:
        raise HTTPException(status_code=401, detail="User not found")
    return user

def generate_short_code():
    return str(uuid.uuid4())[:8]

def validate_short_code(short_code: str) -> bool:
    """Validate custom short code format"""
    import re
    if len(short_code) < 3 or len(short_code) > 50:
        return False
    pattern = re.compile(r'^[a-zA-Z0-9-_]+$')
    return bool(pattern.match(short_code))

def normalize_country(country: str) -> str:
    """Normalize country names and codes"""
    country_map = {
        "USA": "United States",
        "US": "United States",
        "UK": "United Kingdom",
        "UAE": "United Arab Emirates",
        "CA": "Canada",
        "AU": "Australia",
        "NZ": "New Zealand",
        "IN": "India",
        "PK": "Pakistan",
        "BD": "Bangladesh",
        "BR": "Brazil",
        "MX": "Mexico",
        "AR": "Argentina",
        "DE": "Germany",
        "FR": "France",
        "IT": "Italy",
        "ES": "Spain",
        "NL": "Netherlands",
        "BE": "Belgium",
        "CH": "Switzerland",
        "AT": "Austria",
        "SE": "Sweden",
        "NO": "Norway",
        "DK": "Denmark",
        "FI": "Finland",
        "PL": "Poland",
        "RO": "Romania",
        "GR": "Greece",
        "PT": "Portugal",
        "CZ": "Czech Republic",
        "HU": "Hungary",
        "JP": "Japan",
        "CN": "China",
        "KR": "South Korea",
        "TH": "Thailand",
        "VN": "Vietnam",
        "PH": "Philippines",
        "ID": "Indonesia",
        "MY": "Malaysia",
        "SG": "Singapore",
        "ZA": "South Africa",
        "NG": "Nigeria",
        "EG": "Egypt",
        "KE": "Kenya",
        "IL": "Israel",
        "SA": "Saudi Arabia",
        "TR": "Turkey",
        "RU": "Russia"
    }
    
    country = country.strip()
    if country.upper() in country_map:
        return country_map[country.upper()]
    return country

def get_client_ip(request: Request) -> str:
    """Get the real client IP from request headers"""
    forwarded = request.headers.get("X-Forwarded-For")
    if forwarded:
        ip = forwarded.split(",")[0].strip()
        if not ip.startswith("10.") and not ip.startswith("172.") and not ip.startswith("192.168."):
            return ip
    
    real_ip = request.headers.get("X-Real-IP")
    if real_ip:
        return real_ip.strip()
    
    cf_connecting_ip = request.headers.get("CF-Connecting-IP")
    if cf_connecting_ip:
        return cf_connecting_ip.strip()
    
    true_client_ip = request.headers.get("True-Client-IP")
    if true_client_ip:
        return true_client_ip.strip()
    
    return request.client.host

def is_ipv6(ip: str) -> bool:
    """Check if IP address is IPv6"""
    return ":" in ip

def is_ipv4(ip: str) -> bool:
    """Check if IP address is IPv4"""
    parts = ip.split(".")
    return len(parts) == 4 and all(p.isdigit() and 0 <= int(p) <= 255 for p in parts)

def normalize_ipv6(ip: str) -> str:
    """Normalize IPv6 address to full format for consistent comparison"""
    if not is_ipv6(ip):
        return ip
    try:
        import ipaddress
        return str(ipaddress.ip_address(ip))
    except:
        return ip

def get_all_client_ips(request: Request) -> dict:
    """Get all possible client IPs (IPv4 ONLY) from request headers.
    
    IMPORTANT: Only returns the REAL client IP, ignores infrastructure/proxy IPs
    to prevent false duplicate detection.
    """
    ips = {"primary": None, "ipv4": None, "all": [], "proxy_ips": []}
    
    # Known infrastructure IP prefixes to IGNORE
    # These are ONLY load balancers/CDN proxies - NOT private network IPs
    # Private IPs (10.x, 172.x, 192.168.x) are ALLOWED for local testing
    INFRA_IP_PREFIXES = (
        "172.69.", "172.70.", "172.71.",  # Cloudflare proxies ONLY
        "34.160.",  # Google Cloud internal load balancers
        "35.191.", "35.186.",  # Google Cloud health checks
        "130.211.",  # Google Cloud
    )
    
    def is_infra_ip(ip: str) -> bool:
        """Check if IP is an infrastructure/proxy IP that should be ignored"""
        if not ip:
            return True
        return ip.startswith(INFRA_IP_PREFIXES)
    
    def is_private_ip(ip: str) -> bool:
        """We ALLOW private IPs for local/Docker testing"""
        # Return False to allow ALL IPs including 172.25.160.1
        return False
    
    # Get all IPs from X-Forwarded-For
    forwarded = request.headers.get("X-Forwarded-For")
    if forwarded:
        all_forwarded_ips = [ip.strip() for ip in forwarded.split(",")]
        
        # First IP is the original client - ONLY IPv4, skip private IPs
        if all_forwarded_ips:
            first_ip = all_forwarded_ips[0]
            if first_ip and is_ipv4(first_ip) and not is_private_ip(first_ip):
                ips["all"].append(first_ip)
                ips["ipv4"] = first_ip
        
        # We NO LONGER store proxy/intermediate IPs as they cause false duplicates
    
    # Check CF-Connecting-IP (Cloudflare real IP) - this is more reliable
    cf_ip = request.headers.get("CF-Connecting-IP")
    if cf_ip:
        ip = cf_ip.strip()
        if ip and is_ipv4(ip) and not is_private_ip(ip):
            if not ips["ipv4"]:
                ips["all"].append(ip)
                ips["ipv4"] = ip
            elif ip not in ips["all"]:
                # CF IP might be different, use it as primary if we don't have one
                pass
    
    # Fallback if no client IP found - ONLY IPv4
    if not ips["all"]:
        real_ip = request.headers.get("X-Real-IP")
        if real_ip:
            ip = real_ip.strip()
            if ip and is_ipv4(ip) and not is_private_ip(ip):
                ips["all"].append(ip)
                ips["ipv4"] = ip
    
    if not ips["all"] and request.client and request.client.host:
        ip = request.client.host
        if is_ipv4(ip) and not is_private_ip(ip):
            ips["all"].append(ip)
            ips["ipv4"] = ip
    
    # Set primary IP - ONLY IPv4
    ips["primary"] = ips["ipv4"] or (ips["all"][0] if ips["all"] else "unknown")
    
    # proxy_ips is now empty - we don't track infrastructure IPs anymore
    ips["proxy_ips"] = []
    
    return ips

# Referrer Source Categorization
REFERRER_PATTERNS = {
    "facebook": ["facebook.com", "fb.com", "fb.me", "m.facebook.com", "l.facebook.com", "lm.facebook.com"],
    "instagram": ["instagram.com", "l.instagram.com"],
    "twitter": ["twitter.com", "t.co", "x.com"],
    "pinterest": ["pinterest.com", "pin.it"],
    "linkedin": ["linkedin.com", "lnkd.in"],
    "youtube": ["youtube.com", "youtu.be"],
    "tiktok": ["tiktok.com", "vm.tiktok.com"],
    "snapchat": ["snapchat.com"],
    "reddit": ["reddit.com", "redd.it"],
    "whatsapp": ["whatsapp.com", "wa.me", "api.whatsapp.com"],
    "telegram": ["telegram.org", "t.me", "telegram.me"],
    "google": ["google.com", "google.co", "www.google"],
    "bing": ["bing.com"],
    "yahoo": ["yahoo.com", "search.yahoo"],
    "duckduckgo": ["duckduckgo.com"],
    "gmail": ["mail.google.com", "gmail.com"],
    "outlook": ["outlook.com", "outlook.live.com", "mail.live.com"],
    "discord": ["discord.com", "discord.gg", "discordapp.com"],
    "twitch": ["twitch.tv"],
    "spotify": ["spotify.com"],
}

def categorize_referrer(referrer: str, url_params: dict = None) -> dict:
    """Categorize referrer URL into source type. Also checks URL parameters for click IDs."""
    
    # Source names mapping
    source_names = {
        "facebook": "Facebook",
        "instagram": "Instagram", 
        "twitter": "Twitter/X",
        "pinterest": "Pinterest",
        "linkedin": "LinkedIn",
        "youtube": "YouTube",
        "tiktok": "TikTok",
        "snapchat": "Snapchat",
        "reddit": "Reddit",
        "whatsapp": "WhatsApp",
        "telegram": "Telegram",
        "google": "Google Search",
        "bing": "Bing Search",
        "yahoo": "Yahoo Search",
        "duckduckgo": "DuckDuckGo",
        "gmail": "Gmail",
        "outlook": "Outlook/Hotmail",
        "discord": "Discord",
        "twitch": "Twitch",
        "spotify": "Spotify"
    }
    
    # First check URL parameters for platform-specific click IDs
    # This is more reliable than referrer header (which apps often strip)
    if url_params:
        # Instagram - igshid parameter
        if url_params.get("igshid") or url_params.get("utm_source", "").lower() == "instagram":
            return {"source": "instagram", "source_name": "Instagram", "domain": "instagram.com", "detected_from": "url_params"}
        
        # Facebook - fbclid parameter
        if url_params.get("fbclid") or url_params.get("utm_source", "").lower() == "facebook":
            return {"source": "facebook", "source_name": "Facebook", "domain": "facebook.com", "detected_from": "url_params"}
        
        # TikTok - ttclid parameter
        if url_params.get("ttclid") or url_params.get("utm_source", "").lower() == "tiktok":
            return {"source": "tiktok", "source_name": "TikTok", "domain": "tiktok.com", "detected_from": "url_params"}
        
        # Twitter/X - twclid parameter
        if url_params.get("twclid") or url_params.get("utm_source", "").lower() in ["twitter", "x"]:
            return {"source": "twitter", "source_name": "Twitter/X", "domain": "twitter.com", "detected_from": "url_params"}
        
        # Google - gclid parameter  
        if url_params.get("gclid") or url_params.get("utm_source", "").lower() == "google":
            return {"source": "google", "source_name": "Google", "domain": "google.com", "detected_from": "url_params"}
        
        # Pinterest - epik parameter
        if url_params.get("epik") or url_params.get("utm_source", "").lower() == "pinterest":
            return {"source": "pinterest", "source_name": "Pinterest", "domain": "pinterest.com", "detected_from": "url_params"}
        
        # LinkedIn - li_fat_id parameter
        if url_params.get("li_fat_id") or url_params.get("utm_source", "").lower() == "linkedin":
            return {"source": "linkedin", "source_name": "LinkedIn", "domain": "linkedin.com", "detected_from": "url_params"}
        
        # Snapchat - sccid parameter
        if url_params.get("sccid") or url_params.get("utm_source", "").lower() == "snapchat":
            return {"source": "snapchat", "source_name": "Snapchat", "domain": "snapchat.com", "detected_from": "url_params"}
        
        # YouTube
        if url_params.get("utm_source", "").lower() == "youtube":
            return {"source": "youtube", "source_name": "YouTube", "domain": "youtube.com", "detected_from": "url_params"}
        
        # WhatsApp
        if url_params.get("utm_source", "").lower() == "whatsapp":
            return {"source": "whatsapp", "source_name": "WhatsApp", "domain": "whatsapp.com", "detected_from": "url_params"}
        
        # Telegram
        if url_params.get("utm_source", "").lower() == "telegram":
            return {"source": "telegram", "source_name": "Telegram", "domain": "telegram.org", "detected_from": "url_params"}
        
        # Generic utm_source fallback
        utm_source = url_params.get("utm_source", "").lower()
        if utm_source and utm_source in source_names:
            return {"source": utm_source, "source_name": source_names[utm_source], "domain": f"{utm_source}.com", "detected_from": "url_params"}
    
    # If no URL params match, check referrer header
    if not referrer or referrer.strip() == "":
        return {"source": "direct", "source_name": "Direct", "domain": None, "detected_from": "none"}
    
    referrer = referrer.lower().strip()
    
    # Extract domain from referrer
    try:
        from urllib.parse import urlparse
        parsed = urlparse(referrer)
        domain = parsed.netloc or parsed.path.split('/')[0]
        domain = domain.replace("www.", "")
    except:
        domain = referrer
    
    # Check against known patterns
    for source, patterns in REFERRER_PATTERNS.items():
        for pattern in patterns:
            if pattern in referrer or pattern in domain:
                return {
                    "source": source,
                    "source_name": source_names.get(source, source.title()),
                    "domain": domain,
                    "detected_from": "referrer"
                }
    
    # If no match, categorize as "other" with the domain
    return {"source": "other", "source_name": "Other", "domain": domain, "detected_from": "referrer"}

def generate_platform_params(platform: str, custom_params: dict = None, brand: str = "") -> dict:
    """Generate platform-specific URL parameters to simulate traffic source.

    2026-06 — ID FORMATS modernised to match what the real platforms
    actually emit in 2025–2026. Earlier versions used short "IwAR + 30
    alphanumeric" style fbclids (2018-2021 era) that anti-fraud trackers
    (Voluum / RedTrack / Binom / AppsFlyer) flag as outdated. The new
    formats below match what `fetch('https://www.facebook.com/...')` /
    `https://ads.google.com/...` actually drop in 2026 traffic.

    Per-visit randomness is preserved — every call yields a fresh ID,
    so 1000 clicks on the same link yield 1000 distinct fbclids/gclids.

    2026-06-14 — utm_campaign now PER-VISIT DYNAMIC. Earlier code emitted
    a literal "fb_ads" / "tiktok_ads" string on every click, which is the
    single biggest cohort tell on the affiliate-side dashboard. The new
    pool produces unique realistic campaign names like
    "irestore_lookalike_m35_64_video_a" or "tt_irestore_interest_carousel_v2".
    """
    import random
    import string
    import time as _t

    def random_id(length=20):
        return ''.join(random.choices(string.ascii_letters + string.digits, k=length))

    def random_numeric(length=15):
        return ''.join(random.choices(string.digits, k=length))

    # Base64-urlsafe alphabet — what real fbclid/gclid/ttclid use.
    _B64URL = string.ascii_letters + string.digits + "-_"
    def b64url_id(length: int) -> str:
        return ''.join(random.choices(_B64URL, k=length))

    # 2026-06-14 — pull dynamic utm_campaign + realistic timestamp helpers
    # from the referrer_pro module. Safe fallback if the import fails (we
    # never want this generator to raise).
    def _dyn_campaign(plat: str) -> str:
        try:
            from referrer_pro import pick_utm_campaign as _puc
            v = _puc(plat, brand)
            return v or ""
        except Exception:
            return ""

    def _realistic_past_ms() -> int:
        """Return a millisecond timestamp from the last 1-7 days, heavily
        weighted toward the last 24h (real ad clicks are mostly recent).
        70% within 24h, 20% within 1-3 days, 10% within 3-7 days.
        """
        now_ms = int(_t.time() * 1000)
        roll = random.random()
        if roll < 0.70:
            offset = random.randint(0, 24 * 3600 * 1000)
        elif roll < 0.90:
            offset = random.randint(24 * 3600 * 1000, 3 * 24 * 3600 * 1000)
        else:
            offset = random.randint(3 * 24 * 3600 * 1000, 7 * 24 * 3600 * 1000)
        return now_ms - offset

    params = {}

    if platform == "facebook":
        # Modern fbclid (2022+): "IwY2xjawF" prefix + ~80 chars base64url.
        # Reference samples seen in real FB ad traffic:
        #   IwY2xjawFkcGVsZWQ2NTdjOWE0...   (~95 total chars)
        # We randomise the length within the observed range so a bulk run
        # doesn't produce 100 fbclids of identical length (which itself
        # is a fingerprint). Also rotate prefix across known families.
        fbclid_prefix = random.choice(["IwY2xjawF", "IwY2xjawE", "IwY2xjawG", "IwY2xjawH"])
        fbclid_len = random.randint(78, 96)
        params["fbclid"] = f"{fbclid_prefix}{b64url_id(fbclid_len)}"
        # fbc = the cookie format Facebook drops when a user clicks an ad.
        # Format: fb.1.<timestamp_ms>.<fbclid>
        # 2026-06-14 fix: timestamp was current-now-ms which means EVERY
        # bot click has fbc.creation_time == click_time. Real users have
        # fbc dating back from when they FIRST saw the ad (hours/days
        # before click). Anti-fraud ML clusters "fbc==click_time" as bot
        # signature. Now we pick a realistic past timestamp.
        params["fbc"] = f"fb.1.{_realistic_past_ms()}.{params['fbclid']}"
        params["utm_source"] = "facebook"
        params["utm_medium"] = "paid_social"
        params["utm_campaign"] = _dyn_campaign("facebook") or f"fb_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "instagram":
        # Real igshid format: ~22 chars base64url, sometimes starts with
        # "MzRl" or "Mz" prefix.
        params["igshid"] = f"Mz{b64url_id(20)}"
        params["utm_source"] = "instagram"
        params["utm_medium"] = "social"
        params["utm_campaign"] = _dyn_campaign("instagram") or f"ig_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "tiktok":
        # Real ttclid format: ~64-char base64url string (longer than the
        # old 32-char random impl). TikTok also drops `_t` micro-stamp
        # and `_r=1` referral-bit on outbound clicks from the in-app
        # browser — adding those for max realism.
        params["ttclid"] = b64url_id(random.randint(60, 80))
        params["ttp"] = b64url_id(28)   # TikTok Pixel cookie
        params["_t"] = str(random.randint(8, 9)) + str(random.randint(10**11, 10**12 - 1))
        params["_r"] = "1"
        params["utm_source"] = "tiktok"
        params["utm_medium"] = "paid_social"
        params["utm_campaign"] = _dyn_campaign("tiktok") or f"tt_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "twitter":
        # twclid = 22-26 chars base64url.
        params["twclid"] = b64url_id(random.randint(22, 28))
        params["utm_source"] = "twitter"
        params["utm_medium"] = "social"
        params["utm_campaign"] = _dyn_campaign("twitter") or f"x_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "google":
        # Real gclid format (2026): mostly 3 observed prefixes —
        #   Cj0KCQ...   (most common — full search ad click)
        #   EAIaIQobChMI...   (display network)
        #   Cj4KCQ...   (legacy search shortened)
        # The body is base64url with mixed case + digits + - _
        prefix = random.choice(["Cj0KCQ", "EAIaIQ", "Cj4KCQ", "Cj0KEQ"])
        params["gclid"] = f"{prefix}{b64url_id(random.randint(58, 70))}"
        # Google Ads 2024+ also drops gad_source and (Enhanced
        # Conversions for Web) gbraid / wbraid on iOS/cross-app traffic.
        params["gad_source"] = str(random.randint(1, 5))
        if random.random() < 0.30:
            # 30% of Google ad clicks carry gbraid (iOS/cross-app).
            params["gbraid"] = f"0AAAAA{b64url_id(20)}"
        params["utm_source"] = "google"
        params["utm_medium"] = "cpc"
        params["utm_campaign"] = _dyn_campaign("google") or f"g_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "youtube":
        # YouTube redirector → ad clicks. Carries `feature` + sometimes
        # a video id (`v=`) in the referrer chain. Modern YT ads also
        # use gclid (since YouTube ads run via Google Ads).
        prefix = random.choice(["Cj0KCQ", "EAIaIQ"])
        params["gclid"] = f"{prefix}{b64url_id(random.randint(58, 70))}"
        params["utm_source"] = "youtube"
        params["utm_medium"] = "video"
        params["utm_campaign"] = _dyn_campaign("youtube") or f"yt_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "pinterest":
        # Real Pinterest epik format: "dj0y" prefix + base64url ~60 chars.
        params["epik"] = f"dj0y{b64url_id(random.randint(54, 70))}"
        params["utm_source"] = "pinterest"
        params["utm_medium"] = "social"
        params["utm_campaign"] = _dyn_campaign("pinterest") or f"pin_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "linkedin":
        # li_fat_id is a 36-char UUID-style identifier.
        import uuid as _u
        params["li_fat_id"] = str(_u.uuid4())
        params["utm_source"] = "linkedin"
        params["utm_medium"] = "social"
        params["utm_campaign"] = _dyn_campaign("linkedin") or f"li_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "whatsapp":
        params["utm_source"] = "whatsapp"
        params["utm_medium"] = "social"
        params["utm_campaign"] = f"{brand.lower() or 'campaign'}_wa_{random.choice(['share','direct','status','broadcast'])}_{random.randint(100,999)}"

    elif platform == "telegram":
        params["utm_source"] = "telegram"
        params["utm_medium"] = "social"
        params["utm_campaign"] = f"{brand.lower() or 'campaign'}_tg_{random.choice(['channel','group','direct'])}_{random.randint(100,999)}"

    elif platform == "snapchat":
        # Snap Click ID — base64url ~52 chars.
        params["sccid"] = b64url_id(random.randint(48, 60))
        params["ScCid"] = params["sccid"]   # Snap sometimes uppercases
        params["utm_source"] = "snapchat"
        params["utm_medium"] = "paid_social"
        params["utm_campaign"] = _dyn_campaign("snapchat") or f"snap_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "reddit":
        params["utm_source"] = "reddit"
        params["utm_medium"] = "social"
        params["utm_campaign"] = _dyn_campaign("reddit") or f"reddit_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "bing":
        # Bing Ads (Microsoft Ads) — msclkid base64url ~32 chars.
        params["msclkid"] = b64url_id(random.randint(28, 36)).lower()
        params["utm_source"] = "bing"
        params["utm_medium"] = "cpc"
        params["utm_campaign"] = _dyn_campaign("bing") or f"bing_{brand.lower() or 'campaign'}_{random.randint(100,9999)}"

    elif platform == "duckduckgo":
        params["utm_source"] = "duckduckgo"
        params["utm_medium"] = "organic"

    elif platform == "yahoo":
        params["utm_source"] = "yahoo"
        params["utm_medium"] = "organic"

    elif platform == "yandex":
        # Yandex Direct: yclid is numeric, 16-20 digits.
        params["yclid"] = random_numeric(random.randint(16, 20))
        params["utm_source"] = "yandex"
        params["utm_medium"] = "cpc"

    elif platform == "email":
        # ────────────────────────────────────────────────────────────
        # 2026-06 — Realistic email-marketing traffic.
        # Real emails ALMOST NEVER carry a Referer header (mail clients
        # strip it for privacy) OR they carry the ESP click-tracking
        # host as Referer (Mailchimp → us21.list-manage.com, etc.).
        # The engine handles the Referer side; here we focus on the
        # URL params that the tracker actually inspects to classify
        # "this click came from an email campaign".
        #
        # Trackers identify email by:
        #   • utm_medium=email          (the primary signal)
        #   • ESP-specific click/subscriber IDs (mc_cid / _kx / _hsenc …)
        #   • utm_source matching a campaign/list name (brand-tagged
        #     when the operator set a brand identifier)
        #
        # When the RUT engine pre-picked an ESP for this visit, it
        # passes that via `__force_esp` (HMAC-verified earlier in the
        # tracker). This guarantees the URL params (mc_cid vs _kx vs
        # _hsenc) line up with the Referer host the engine chose for
        # the same visit — eliminating the ESP↔Referer leak.
        # ────────────────────────────────────────────────────────────
        force_esp = (custom_params or {}).pop("__force_esp", None) if isinstance(custom_params, dict) else None
        brand     = (custom_params or {}).pop("__brand",     None) if isinstance(custom_params, dict) else None
        if force_esp and isinstance(force_esp, str):
            esp = force_esp.strip().lower()
        else:
            esp = random.choice([
                # Weighted by 2025-2026 market share (Litmus + EmailToolTester
                # reports). Mailchimp ~28% retail, Klaviyo ~16% ecom-heavy,
                # SendGrid ~12% transactional, HubSpot ~8% B2B, others tail.
                "mailchimp", "mailchimp", "mailchimp",
                "klaviyo",   "klaviyo",
                "sendgrid",  "sendgrid",
                "hubspot",
                "activecampaign",
                "convertkit",
                "constantcontact",
                "generic",
            ])
        if esp == "mailchimp":
            # Real Mailchimp click URLs: ?mc_cid=abc123 + &mc_eid=xyz456
            params["mc_cid"] = b64url_id(10).lower()
            params["mc_eid"] = b64url_id(10).lower()
        elif esp == "sendgrid":
            params["utm_id"] = f"sg_{b64url_id(22)}"
        elif esp == "klaviyo":
            # Klaviyo `_kx` is base64url 40-60 chars (encrypted subscriber id)
            params["_kx"] = b64url_id(random.randint(40, 60))
        elif esp == "hubspot":
            params["_hsenc"] = b64url_id(random.randint(40, 60))
            params["_hsmi"]  = str(random.randint(10**7, 10**9))
        elif esp == "activecampaign":
            params["vgo_ee"] = b64url_id(random.randint(24, 40))
        elif esp == "convertkit":
            params["ck_subscriber_id"] = str(random.randint(10**6, 10**8))
        elif esp == "constantcontact":
            params["ssp"] = b64url_id(random.randint(28, 40))
        # else "generic" → UTMs only (still classifies as email)

        # Brand-aware UTMs. When the operator entered a brand identifier
        # (e.g. "acme"), we use it as utm_source and prefix utm_campaign
        # so destination trackers see consistent brand-tagged labels
        # matching what an advertiser would expect from "Brand X's email
        # marketing".
        brand_safe = ""
        if brand:
            brand_safe = "".join(
                c if (c.isalnum() or c in "_-") else "_"
                for c in str(brand).lower().strip()
            )[:32]

        # Standard UTMs every email link carries
        if brand_safe:
            params["utm_source"] = f"{brand_safe}_newsletter"
        else:
            params["utm_source"] = random.choice([
                "newsletter", "email", "mailing_list", "weekly_digest",
                "subscribers", esp,
            ])
        params["utm_medium"] = "email"
        _campaign_base = random.choice([
            "jan_2026_promo", "weekly_digest", "exclusive_offer",
            "welcome_series", "abandoned_cart", "winback_q1",
            "new_product_launch", "vip_only", "limited_time",
            "flash_sale", "subscriber_perks", "monthly_recap",
        ])
        params["utm_campaign"] = (
            f"{brand_safe}_{_campaign_base}" if brand_safe else _campaign_base
        )
        params["utm_content"] = random.choice([
            "cta_top", "cta_bottom", "header_link",
            "footer_link", "main_image", "secondary_button",
            "text_link_1", "hero_button", "product_card_3",
        ])
        if random.random() < 0.40:
            # 40% of marketers also set utm_term (audience segment)
            params["utm_term"] = random.choice([
                "subscribers_a", "vip_segment", "us_users",
                "high_engagement", "new_signups", "win_back",
                "premium_tier", "active_30d",
            ])

    elif platform == "sms":
        params["utm_source"] = "sms"
        params["utm_medium"] = "sms"

    elif platform == "direct":
        # No params for direct traffic
        pass

    else:
        # Custom platform
        params["utm_source"] = platform
        params["utm_medium"] = "referral"

    # Add custom params if provided
    if custom_params:
        params.update(custom_params)

    return params


# ──────────────────────────────────────────────────────────────────────
# 2026-06: Per-visit platform override (RUT engine → tracker handshake)
# ──────────────────────────────────────────────────────────────────────
# When the RUT engine uses its referrer-override feature (especially
# `referer_mode=platform_pool`), each visit's Referer header is set to a
# different platform. To avoid the Referrer ↔ URL-params MISMATCH leak
# (e.g. visit comes "from tiktok.com" but offer URL gets fbclid because
# the link's static simulate_platform=facebook), the engine appends a
# tiny HMAC-signed pair of query params to the tracker URL:
#
#     ?_kx_src=<platform>&_kx_sig=<HMAC-SHA256(platform)[..12]>
#
# The tracker reads + verifies + strips them before redirecting. The
# verified platform overrides the link's static simulate_platform for
# THIS visit only. Pure signal-side fix — no link config changes needed.
#
# Security: the secret is `SECRET_KEY` (same as JWT). Since both signer
# and verifier are the SAME backend process, this is trivially safe
# against external forgery — an attacker can't sign a token, so an
# external visitor adding `?_kx_src=facebook` to a tracker URL has the
# token silently ignored (we never apply the override unless `_kx_sig`
# verifies).
# ──────────────────────────────────────────────────────────────────────
def _kx_src_sign(platform: str) -> str:
    """Return the short HMAC tag for a platform short-name. Trimmed to
    12 hex chars — that's 48 bits of entropy, way more than enough to
    block forgery (attackers would need 2^47 guesses on average) while
    keeping the tracker URL short."""
    import hmac as _hmac
    import hashlib as _hashlib
    msg = (platform or "").strip().lower().encode("utf-8")
    key = SECRET_KEY.encode("utf-8") if isinstance(SECRET_KEY, str) else bytes(SECRET_KEY)
    return _hmac.new(key, msg, _hashlib.sha256).hexdigest()[:12]


def _kx_src_verify(platform: str, sig: str) -> bool:
    """Constant-time HMAC verification. Returns False on any mismatch
    (bad sig, empty sig, mismatched platform). Never raises."""
    import hmac as _hmac
    try:
        if not platform or not sig:
            return False
        expected = _kx_src_sign(platform)
        return _hmac.compare_digest(expected, str(sig)[:12])
    except Exception:
        return False


def _kx_esp_sign(platform: str, esp: str) -> str:
    """HMAC tag for the (platform, esp) pair — used so the RUT engine
    can tell the tracker WHICH ESP to use for THIS visit's URL params
    when the platform is "email". Same secret + same 12-hex trim as
    _kx_src_sign."""
    import hmac as _hmac
    import hashlib as _hashlib
    msg = f"{(platform or '').strip().lower()}:{(esp or '').strip().lower()}".encode("utf-8")
    key = SECRET_KEY.encode("utf-8") if isinstance(SECRET_KEY, str) else bytes(SECRET_KEY)
    return _hmac.new(key, msg, _hashlib.sha256).hexdigest()[:12]


def _kx_esp_verify(platform: str, esp: str, sig: str) -> bool:
    """Constant-time HMAC verification of the (platform, esp) pair."""
    import hmac as _hmac
    try:
        if not platform or not esp or not sig:
            return False
        expected = _kx_esp_sign(platform, esp)
        return _hmac.compare_digest(expected, str(sig)[:12])
    except Exception:
        return False


def build_kx_src_qs(platform: str) -> str:
    """Build the `&_kx_src=...&_kx_sig=...` query-string fragment that
    the RUT engine appends to the tracker URL. Returns "" for unknown
    or empty platforms."""
    p = (platform or "").strip().lower()
    if not p:
        return ""
    return f"_kx_src={p}&_kx_sig={_kx_src_sign(p)}"

def build_redirect_url(base_url: str, params: dict) -> str:
    """Build redirect URL with added parameters"""
    from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
    
    if not params:
        return base_url
    
    parsed = urlparse(base_url)
    existing_params = parse_qs(parsed.query)
    
    # Flatten existing params (parse_qs returns lists)
    flat_params = {k: v[0] if isinstance(v, list) and len(v) == 1 else v for k, v in existing_params.items()}
    
    # Add new params (don't overwrite existing)
    for key, value in params.items():
        if key not in flat_params:
            flat_params[key] = value
    
    # Rebuild URL
    new_query = urlencode(flat_params, doseq=True)
    new_url = urlunparse((
        parsed.scheme,
        parsed.netloc,
        parsed.path,
        parsed.params,
        new_query,
        parsed.fragment
    ))
    
    return new_url

async def check_vpn_scamalytics(ip: str) -> dict:
    """Check IP against multiple services for VPN/proxy detection - with caching"""
    if not ip or ip in ["127.0.0.1", "localhost", "unknown", "Unknown", ""] or ip.startswith("10.") or ip.startswith("172.") or ip.startswith("192.168."):
        return {"is_vpn": False, "vpn_score": 0, "risk": "low", "source": "local"}
    
    # Fresh VPN check every time - no cache
    try:
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"http://ip-api.com/json/{ip}?fields=proxy,hosting,status",
                timeout=2  # 2 second timeout for speed
            )
            if response.status_code == 200:
                data = response.json()
                if data.get("status") == "success":
                    is_vpn = data.get("proxy", False) or data.get("hosting", False)
                    return {
                        "is_vpn": is_vpn, 
                        "vpn_score": 100 if is_vpn else 0, 
                        "risk": "high" if is_vpn else "low", 
                        "source": "ip-api"
                    }
    except:
        pass
    
    return {"is_vpn": False, "vpn_score": 0, "risk": "unknown", "source": "none"}


# API Usage Tracker - tracks daily usage for each API
_api_usage = {}
_api_usage_date = None

# API Daily Limits (free tier)
API_DAILY_LIMITS = {
    "proxycheck": 1000,      # 1000/day free
    "ipapi": 45 * 60 * 24,   # 45/minute = ~64,800/day but we'll set 10000 as practical limit
    "scamalytics": 5000,     # Varies by plan
    "ipqualityscore": 5000,  # 5000/month free, ~166/day
    "iphub": 1000,           # 1000/day free
}

# Override practical limits
API_DAILY_LIMITS["ipapi"] = 10000  # Practical daily limit for ip-api

def get_today_date():
    """Get today's date string for tracking"""
    return datetime.now(timezone.utc).strftime("%Y-%m-%d")

async def get_api_usage():
    """Get API usage from database"""
    global _api_usage, _api_usage_date
    today = get_today_date()
    
    # Check if we need to load from database or reset for new day
    if _api_usage_date != today:
        # Load from database or reset
        usage_doc = await main_db.settings.find_one({"key": "api_usage"})
        if usage_doc and usage_doc.get("date") == today:
            _api_usage = usage_doc.get("usage", {})
        else:
            _api_usage = {}
            # Save reset to database
            await main_db.settings.update_one(
                {"key": "api_usage"},
                {"$set": {"key": "api_usage", "date": today, "usage": {}}},
                upsert=True
            )
        _api_usage_date = today
    
    return _api_usage

async def increment_api_usage(api_key: str):
    """Increment usage count for an API"""
    global _api_usage
    await get_api_usage()  # Ensure loaded
    
    if api_key not in _api_usage:
        _api_usage[api_key] = 0
    _api_usage[api_key] += 1
    
    # Save to database every 10 requests to reduce writes
    if _api_usage[api_key] % 10 == 0:
        await main_db.settings.update_one(
            {"key": "api_usage"},
            {"$set": {f"usage.{api_key}": _api_usage[api_key]}},
            upsert=True
        )

async def save_api_usage():
    """Force save API usage to database"""
    global _api_usage, _api_usage_date
    if _api_usage:
        await main_db.settings.update_one(
            {"key": "api_usage"},
            {"$set": {"key": "api_usage", "date": _api_usage_date or get_today_date(), "usage": _api_usage}},
            upsert=True
        )

def is_api_limit_reached(api_key: str) -> bool:
    """Check if API has reached its daily limit"""
    limit = API_DAILY_LIMITS.get(api_key, 10000)
    used = _api_usage.get(api_key, 0)
    return used >= limit

def get_api_remaining(api_key: str) -> int:
    """Get remaining requests for an API"""
    limit = API_DAILY_LIMITS.get(api_key, 10000)
    used = _api_usage.get(api_key, 0)
    return max(0, limit - used)

# API Rate Limit Tracker - tracks which APIs have hit their limits (for errors)
_api_rate_limits = {}
_api_rate_limit_reset = 3600  # Reset rate limit flags after 1 hour

async def get_enabled_api_settings():
    """Get API settings from database, sorted by priority"""
    try:
        settings = await main_db.settings.find_one({"key": "api_settings"})
        if settings and "value" in settings:
            api_settings = settings["value"]
        else:
            api_settings = DEFAULT_API_SETTINGS
        
        # Filter enabled APIs and sort by priority
        enabled_apis = [
            (key, config) for key, config in api_settings.items() 
            if config.get("enabled", False)
        ]
        enabled_apis.sort(key=lambda x: x[1].get("priority", 99))
        return enabled_apis
    except Exception as e:
        logger.error(f"Error getting API settings: {e}")
        return []

def is_api_rate_limited(api_key: str) -> bool:
    """Check if an API is currently rate limited"""
    global _api_rate_limits
    if api_key not in _api_rate_limits:
        return False
    
    limit_time = _api_rate_limits[api_key]
    if time.time() - limit_time > _api_rate_limit_reset:
        del _api_rate_limits[api_key]
        return False
    return True

def mark_api_rate_limited(api_key: str):
    """Mark an API as rate limited"""
    global _api_rate_limits
    _api_rate_limits[api_key] = time.time()
    logger.warning(f"API {api_key} marked as rate limited")

async def check_vpn_with_api(ip: str, api_key: str, config: dict) -> dict:
    """Check VPN using a specific API configuration"""
    try:
        async with httpx.AsyncClient() as client:
            if api_key == "ipapi":
                url = f"{config['endpoint']}{ip}?fields=proxy,hosting,status"
                response = await client.get(url, timeout=3)
                if response.status_code == 200:
                    data = response.json()
                    if data.get("status") == "fail" and "rate limit" in str(data.get("message", "")).lower():
                        mark_api_rate_limited(api_key)
                        return None
                    if data.get("status") == "success":
                        await increment_api_usage(api_key)  # Track usage
                        is_vpn = data.get("proxy", False) or data.get("hosting", False)
                        return {"is_vpn": is_vpn, "vpn_score": 100 if is_vpn else 0, "risk": "high" if is_vpn else "low", "source": api_key}
            
            elif api_key == "proxycheck":
                url = f"{config['endpoint']}{ip}?vpn=1"
                if config.get("api_key"):
                    url += f"&key={config['api_key']}"
                response = await client.get(url, timeout=3)
                if response.status_code == 200:
                    data = response.json()
                    if data.get("status") == "denied" or data.get("status") == "error":
                        if "limit" in str(data.get("message", "")).lower():
                            mark_api_rate_limited(api_key)
                        return None
                    await increment_api_usage(api_key)  # Track usage
                    ip_data = data.get(ip, {})
                    is_vpn = ip_data.get("proxy") == "yes" or ip_data.get("type") in ["VPN", "Proxy", "Hosting"]
                    return {"is_vpn": is_vpn, "vpn_score": 100 if is_vpn else 0, "risk": "high" if is_vpn else "low", "source": api_key}
            
            elif api_key == "ipqualityscore":
                if not config.get("api_key"):
                    return None
                url = f"{config['endpoint']}{config['api_key']}/{ip}"
                response = await client.get(url, timeout=3)
                if response.status_code == 200:
                    data = response.json()
                    if not data.get("success", True):
                        if "limit" in str(data.get("message", "")).lower():
                            mark_api_rate_limited(api_key)
                        return None
                    await increment_api_usage(api_key)  # Track usage
                    is_vpn = data.get("vpn", False) or data.get("proxy", False) or data.get("tor", False)
                    vpn_score = data.get("fraud_score", 0)
                    return {"is_vpn": is_vpn, "vpn_score": vpn_score, "risk": "high" if vpn_score > 75 else "medium" if vpn_score > 50 else "low", "source": api_key}
            
            elif api_key == "iphub":
                if not config.get("api_key"):
                    return None
                headers = {"X-Key": config["api_key"]}
                url = f"{config['endpoint']}{ip}"
                response = await client.get(url, headers=headers, timeout=3)
                if response.status_code == 429:  # Too many requests
                    mark_api_rate_limited(api_key)
                    return None
                if response.status_code == 200:
                    await increment_api_usage(api_key)  # Track usage
                    data = response.json()
                    block_score = data.get("block", 0)
                    is_vpn = block_score >= 1
                    return {"is_vpn": is_vpn, "vpn_score": block_score * 50, "risk": "high" if block_score >= 2 else "medium" if block_score == 1 else "low", "source": api_key}
            
            elif api_key == "scamalytics":
                # Scamalytics requires special handling
                if not config.get("api_key"):
                    return None
                url = f"{config['endpoint']}{config['api_key']}/{ip}"
                response = await client.get(url, timeout=3)
                if response.status_code == 200:
                    await increment_api_usage(api_key)  # Track usage
                    data = response.json()
                    score = data.get("score", 0)
                    is_vpn = score > 50 or data.get("proxy", "no") == "yes"
                    return {"is_vpn": is_vpn, "vpn_score": score, "risk": "high" if score > 75 else "medium" if score > 50 else "low", "source": api_key}
            
            else:
                # Custom API - generic handling
                url = config['endpoint']
                if "{ip}" in url:
                    url = url.replace("{ip}", ip)
                else:
                    url = f"{url}{ip}"
                
                headers = {}
                if config.get("api_key"):
                    headers["Authorization"] = f"Bearer {config['api_key']}"
                
                response = await client.get(url, headers=headers, timeout=3)
                if response.status_code == 429:
                    mark_api_rate_limited(api_key)
                    return None
                if response.status_code == 200:
                    data = response.json()
                    # Try to find common VPN indicators in response
                    is_vpn = (
                        data.get("vpn", False) or 
                        data.get("proxy", False) or 
                        data.get("is_vpn", False) or 
                        data.get("is_proxy", False) or
                        str(data.get("type", "")).lower() in ["vpn", "proxy", "hosting", "datacenter"]
                    )
                    return {"is_vpn": is_vpn, "vpn_score": 100 if is_vpn else 0, "risk": "high" if is_vpn else "low", "source": api_key}
    
    except httpx.TimeoutException:
        logger.debug(f"API {api_key} timed out for IP {ip}")
        return None
    except Exception as e:
        logger.debug(f"API {api_key} error for IP {ip}: {e}")
        return None
    
    return None

async def check_vpn_detailed(ip: str) -> dict:
    """Detailed VPN check using multiple services with automatic fallback"""
    if not ip or ip in ["127.0.0.1", "localhost", "unknown", "Unknown", ""] or ip.startswith("10.") or ip.startswith("172.") or ip.startswith("192.168."):
        return {"is_vpn": False, "vpn_score": 0, "risk": "low", "source": "local"}
    
    # Get enabled APIs sorted by priority
    enabled_apis = await get_enabled_api_settings()
    
    # Load current usage
    await get_api_usage()
    
    if not enabled_apis:
        # Fallback to hardcoded behavior if no APIs configured
        logger.warning("No APIs enabled, using default ip-api")
        try:
            async with httpx.AsyncClient() as client:
                response = await client.get(f"http://ip-api.com/json/{ip}?fields=proxy,hosting,status", timeout=2)
                if response.status_code == 200:
                    data = response.json()
                    if data.get("status") == "success":
                        await increment_api_usage("ipapi")
                        is_vpn = data.get("proxy", False) or data.get("hosting", False)
                        return {"is_vpn": is_vpn, "vpn_score": 100 if is_vpn else 0, "risk": "high" if is_vpn else "low", "source": "ip-api-fallback"}
        except:
            pass
        return {"is_vpn": False, "vpn_score": 0, "risk": "unknown", "source": "none"}
    
    # Try each API in priority order
    apis_tried = []
    apis_skipped_limit = []
    for api_key, config in enabled_apis:
        # Skip if daily limit reached
        if is_api_limit_reached(api_key):
            apis_skipped_limit.append(api_key)
            logger.debug(f"Skipping {api_key} - daily limit reached ({_api_usage.get(api_key, 0)}/{API_DAILY_LIMITS.get(api_key, 10000)})")
            continue
        
        # Skip if rate limited (error-based)
        if is_api_rate_limited(api_key):
            logger.debug(f"Skipping {api_key} - rate limited by API response")
            continue
        
        apis_tried.append(api_key)
        result = await check_vpn_with_api(ip, api_key, config)
        
        if result is not None:
            logger.debug(f"VPN check for {ip}: {result['source']} returned is_vpn={result['is_vpn']}")
            return result
    
    # All APIs failed or rate limited
    if apis_skipped_limit:
        logger.warning(f"All VPN APIs at limit for IP {ip}. Skipped: {apis_skipped_limit}, Tried: {apis_tried}")
    else:
        logger.warning(f"All VPN APIs failed for IP {ip}. Tried: {apis_tried}")
    return {"is_vpn": False, "vpn_score": 0, "risk": "unknown", "source": "all_failed", "apis_tried": apis_tried, "apis_at_limit": apis_skipped_limit}

# Geolocation cache - reduces API calls significantly
_geo_cache = {}
_geo_cache_ttl = 3600  # 1 hour cache for geolocation

async def get_country_from_ip(ip: str) -> dict:
    global _geo_cache
    
    if ip in ["127.0.0.1", "localhost"]:
        return {"country": "Local", "city": "", "region": "", "lat": 0, "lon": 0, "isp": "", "is_vpn": False, "is_proxy": False, "vpn_score": 0}
    
    if ip.startswith("10.") or ip.startswith("172.") or ip.startswith("192.168."):
        return {"country": "Local", "city": "", "region": "", "lat": 0, "lon": 0, "isp": "", "is_vpn": False, "is_proxy": False, "vpn_score": 0}
    
    # Check cache first
    current_time = time.time()
    if ip in _geo_cache:
        cached = _geo_cache[ip]
        if current_time - cached["time"] < _geo_cache_ttl:
            return cached["data"]
    
    country = "Unknown"
    city = ""
    region = ""
    lat = 0
    lon = 0
    isp = ""
    is_vpn = False
    is_proxy = False
    vpn_score = 0
    
    # Get full geolocation from ip-api (free, no key needed) - reduced timeout for speed
    try:
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"http://ip-api.com/json/{ip}?fields=status,country,countryCode,region,regionName,city,lat,lon,isp,proxy,hosting",
                timeout=2  # Reduced from 5 to 2 seconds
            )
            if response.status_code == 200:
                data = response.json()
                if data.get("status") == "success":
                    country = data.get("country", "Unknown")
                    city = data.get("city", "")
                    region = data.get("regionName", "")
                    lat = data.get("lat", 0)
                    lon = data.get("lon", 0)
                    isp = data.get("isp", "")
                    is_proxy = data.get("proxy", False) or data.get("hosting", False)
    except Exception as e:
        pass  # Silently fail - don't block redirect
    
    # Only check VPN if needed (proxy already detected) - skip expensive call if we have answer
    if not is_proxy:
        try:
            vpn_info = await check_vpn_scamalytics(ip)
            is_vpn = vpn_info.get("is_vpn", False)
            vpn_score = vpn_info.get("vpn_score", 0)
        except:
            pass
    else:
        is_vpn = True
        vpn_score = 100
    
    result = {
        "country": country, 
        "city": city, 
        "region": region, 
        "lat": lat, 
        "lon": lon, 
        "isp": isp,
        "is_vpn": is_vpn, 
        "is_proxy": is_vpn, 
        "vpn_score": vpn_score
    }
    
    # Cache the result
    _geo_cache[ip] = {"data": result, "time": current_time}
    
    # Clean old cache entries (keep max 50000)
    if len(_geo_cache) > 50000:
        sorted_keys = sorted(_geo_cache.keys(), key=lambda k: _geo_cache[k]["time"])
        for k in sorted_keys[:25000]:
            del _geo_cache[k]
    
    return result

def detect_device(user_agent_string: str) -> dict:
    """Detect device type, OS, browser, and device brand/model"""
    ua = parse(user_agent_string)
    
    device_type = "desktop"
    if ua.is_mobile:
        device_type = "mobile"
    elif ua.is_tablet:
        device_type = "tablet"
    
    os_name = "Unknown"
    os_version = ""
    browser = ua.browser.family if ua.browser else "Unknown"
    browser_version = ua.browser.version_string if ua.browser and ua.browser.version_string else ""
    
    # Device brand and model
    device_brand = ua.device.brand if ua.device and ua.device.brand else "Unknown"
    device_model = ua.device.model if ua.device and ua.device.model else "Unknown"
    device_family = ua.device.family if ua.device and ua.device.family else "Unknown"
    
    if ua.os.family:
        os_family = ua.os.family.lower()
        
        if "ios" in os_family or "iphone" in os_family or "ipad" in os_family:
            os_name = "iOS"
            os_version = ua.os.version_string if ua.os.version_string else ""
            # For iOS, set brand to Apple if not detected
            if device_brand == "Unknown":
                device_brand = "Apple"
            if "ipad" in os_family.lower() or "ipad" in device_family.lower():
                device_model = device_model if device_model != "Unknown" else "iPad"
            elif "iphone" in os_family.lower() or "iphone" in device_family.lower():
                device_model = device_model if device_model != "Unknown" else "iPhone"
        elif "android" in os_family:
            os_name = "Android"
            os_version = ua.os.version_string if ua.os.version_string else ""
        elif "mac" in os_family or "os x" in os_family:
            os_name = "macOS"
            os_version = ua.os.version_string if ua.os.version_string else ""
            if device_brand == "Unknown":
                device_brand = "Apple"
                device_model = "Mac"
        elif "windows" in os_family:
            os_name = "Windows"
            os_version = ua.os.version_string if ua.os.version_string else ""
            if device_brand == "Unknown":
                device_brand = "PC"
                device_model = "Windows PC"
        elif "linux" in os_family:
            os_name = "Linux"
            os_version = ua.os.version_string if ua.os.version_string else ""
        elif "chrome os" in os_family:
            os_name = "ChromeOS"
        else:
            os_name = ua.os.family
            os_version = ua.os.version_string if ua.os.version_string else ""
    
    # Build device display string
    device_display = ""
    if device_brand != "Unknown" and device_model != "Unknown":
        device_display = f"{device_brand} {device_model}"
    elif device_brand != "Unknown":
        device_display = device_brand
    elif device_model != "Unknown":
        device_display = device_model
    else:
        device_display = device_type.title()
    
    # Build browser display string with version
    browser_display = browser
    if browser_version:
        browser_display = f"{browser} {browser_version}"

    # 2026-06 BUG-B FIX — merge with `_detect_inapp` so in-app UAs that
    # the `user_agents` library mis-identifies (TikTok musical_ly,
    # YouTube com.google.ios.youtube, WhatsApp CFNetwork, KakaoTalk,
    # Line, WeChat MicroMessenger, coerced TwitterIOS/Android etc.) are
    # surfaced with their REAL app name + version instead of generic
    # "Mobile Safari UI/WKWebView". Also covers the Facebook iOS case
    # where the lib detects family="Facebook" but leaves version="" —
    # we backfill from _detect_inapp's FBAV match.
    is_inapp = False
    inapp_app = None
    inapp_app_name = None
    inapp_app_version = None
    try:
        inapp = _detect_inapp(user_agent_string)
        if inapp.get("is_inapp"):
            is_inapp = True
            inapp_app = inapp.get("app")
            inapp_app_name = inapp.get("app_name")
            inapp_app_version = inapp.get("app_version")
            # Generic engine names the library returns for in-app
            # webviews — when seen alongside is_inapp=True, prefer the
            # REAL app name + version we resolved (otherwise advertiser
            # dashboards see "Chrome 128" for a click that actually came
            # from a TikTok in-app webview).
            generic_libs = {
                "Mobile Safari", "Mobile Safari UI/WKWebView", "Safari",
                "Chrome Mobile", "Chrome Mobile WebView", "Chrome",
                "WebKit", "Chromium", "Other", "Unknown", "",
            }
            lib_browser_was_generic = (
                (not browser) or browser in generic_libs
            )
            if lib_browser_was_generic or inapp_app_name == browser:
                # Override name when the library returned a generic
                # engine string OR already happened to match (idempotent).
                browser = inapp_app_name or browser
                # When the name was generic, the library's version is
                # the engine version (e.g. Chrome's 128.0.0) — NOT the
                # app version the operator wants to see. Prefer the
                # real app version we extracted.
                if lib_browser_was_generic and inapp_app_version:
                    browser_version = inapp_app_version
                elif not browser_version and inapp_app_version:
                    browser_version = inapp_app_version
            else:
                # Library detected a non-generic name (e.g. "Facebook"
                # via its FBAV rule, or "Instagram"). Trust the name but
                # backfill the version when the lib couldn't extract it
                # (Facebook iOS case — name = "Facebook", version = "").
                if not browser_version and inapp_app_version:
                    browser_version = inapp_app_version
            # Recompose display string with the resolved name+version.
            browser_display = f"{browser} {browser_version}".strip()
    except Exception:
        # `_detect_inapp` must never break click logging.
        pass

    return {
        "device_type": device_type,
        "device_brand": device_brand,
        "device_model": device_model,
        "device_display": device_display,
        "os_name": os_name,
        "os_version": os_version,
        "browser": browser,
        "browser_version": browser_version,
        "browser_display": browser_display,
        "full_string": f"{os_name} {os_version}".strip() if os_version else os_name,
        # 2026-06 BUG-C FIX — surface in-app fields so click_doc can
        # persist them. Frontends/exports can render an "in-app" badge
        # and group analytics by app_name.
        "is_inapp": is_inapp,
        "inapp_app": inapp_app,
        "inapp_app_name": inapp_app_name,
        "inapp_app_version": inapp_app_version,
    }

def check_user_feature(user: dict, feature: str):
    """Check if user has access to a specific feature. Raises HTTPException if not."""
    status = user.get("status", "pending")
    
    if status == "blocked":
        raise HTTPException(status_code=403, detail="Your account has been blocked. Contact admin for support.")
    
    if status != "active":
        raise HTTPException(status_code=403, detail=f"Your account is pending activation. Contact admin at {ADMIN_CONTACT_EMAIL} for access.")
    
    features = user.get("features", {})
    # v2.2.0 admin-controlled gating:
    #   • If the feature is EXPLICITLY set to False in the user document
    #     → DENY. The admin has intentionally disabled this feature for
    #     this customer; we must respect that choice.
    #   • If the feature key is ABSENT from the user's features dict
    #     AND DEFAULT_FEATURES has it as True → auto-grant (this is the
    #     pre-existing migration path for legacy users created before
    #     a new feature was added, and is the only safe auto-grant case).
    #   • Otherwise → deny.
    if feature in features and features[feature] is False:
        raise HTTPException(
            status_code=403,
            detail=f"Feature '{feature}' is not enabled for your account. Contact admin for access.",
        )
    if feature not in features:
        default_val = DEFAULT_FEATURES.get(feature)
        if default_val is True:
            # Auto-grant in-memory so this request succeeds.
            features[feature] = True
            user["features"] = features
            # Best-effort async persist (don't block).
            try:
                asyncio.create_task(
                    main_db.users.update_one(
                        {"id": user.get("id")},
                        {"$set": {f"features.{feature}": True}},
                    )
                )
            except Exception:  # noqa: BLE001
                pass
            return True
    # Backward compat: new granular features (email_checker, separate_data, import_traffic,
    # real_traffic, ua_generator) fall back to the legacy "import_data" flag when not set
    # explicitly. That way users created before these features existed keep access.
    LEGACY_IMPORT_GROUP = {"email_checker", "phone_checker", "separate_data", "import_traffic", "real_traffic", "ua_generator"}
    if feature not in features and feature in LEGACY_IMPORT_GROUP:
        if features.get("import_data", False):
            return True
    if not features.get(feature, False):
        raise HTTPException(status_code=403, detail=f"Feature '{feature}' is not enabled for your account. Contact admin for access.")
    
    return True

async def get_current_user_with_fresh_data(request: Request) -> dict:
    """Get current user with fresh data from database (for feature checks)"""
    # v2.1.0: bridge-mode bypass mirror — same logic as get_current_user.
    # Heavy job endpoints use get_current_user_with_fresh_data so this
    # MUST also accept the X-Krexion-Bridge-Job + X-Krexion-License
    # combo from loopback (sync_client).
    if (
        not IS_CLOUD
        and request.headers.get("X-Krexion-Bridge-Job") == "1"
    ):
        client_host = (getattr(request.client, "host", "") or "").lower()
        if client_host in {"127.0.0.1", "localhost", "::1"}:
            br_lic = request.headers.get("X-Krexion-License", "").strip()
            if br_lic:
                lic_doc = await main_db.licenses.find_one(
                    {"license_key": br_lic}, {"_id": 0}
                )
                if lic_doc:
                    uid = lic_doc.get("user_id")
                    lic_email = lic_doc.get("email")
                    user = None
                    if uid:
                        user = await main_db.users.find_one({"id": uid}, {"_id": 0, "password_hash": 0})
                    if not user and lic_email:
                        user = await main_db.users.find_one({"email": lic_email}, {"_id": 0, "password_hash": 0})
                    if not user and lic_email:
                        import uuid as _uuid
                        new_uid = uid or _uuid.uuid4().hex
                        new_user = {
                            "id": new_uid,
                            "email": lic_email,
                            "name": lic_email.split("@")[0],
                            "is_admin": False,
                            "status": "active",
                            "features": {f: True for f in (
                                "real_user_traffic", "form_filler",
                                "visual_recorder", "proxies", "links",
                                "clicks", "import_traffic",
                                "email_checker", "phone_checker", "separate_data",
                                "ua_generator", "ua_checker",
                                "real_traffic", "import_data",
                                "adspower", "uploaded_things",
                                "profile_builder", "traffic_sources",
                            )},
                            "created_at": datetime.utcnow().isoformat(),
                            "bridge_synced": True,
                        }
                        await main_db.users.insert_one(new_user)
                        user = new_user
                    if user:
                        # Grant ALL heavy-job feature flags by default
                        # for bridge-resolved users (they paid for the
                        # license; cloud already authorised the call).
                        # v2.1.2: ALSO force-set status='active'. The
                        # local user record may have been auto-created
                        # by the heartbeat-mirror without a status
                        # field, which check_user_feature reads as
                        # 'pending' -> 403 'Account pending activation'.
                        # The license itself is the source of truth
                        # here — if the license is valid and matches,
                        # the user IS active on the cloud side. Mirror.
                        user["status"] = "active"
                        user.setdefault("features", {})
                        for feat in ("real_user_traffic", "form_filler",
                                     "visual_recorder", "proxies", "links",
                                     "clicks", "import_traffic",
                                     "email_checker", "phone_checker", "separate_data",
                                     "ua_generator", "ua_checker",
                                     "real_traffic", "import_data",
                                     "adspower", "uploaded_things",
                                     "profile_builder", "traffic_sources"):
                            user["features"].setdefault(feat, True)
                        # Persist the active flag so subsequent NON-bridge
                        # calls (e.g. user opens krexion-local in a
                        # browser) also see them as active.
                        try:
                            await main_db.users.update_one(
                                {"id": user["id"]},
                                {"$set": {"status": "active",
                                          "features": user["features"]}},
                            )
                        except Exception:  # noqa: BLE001
                            pass
                        return user

    auth_header = request.headers.get("Authorization")
    if not auth_header or not auth_header.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    token = auth_header.split(" ")[1]
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        email = payload.get("sub")
        is_sub_user = payload.get("is_sub_user", False)
        parent_user_id = payload.get("parent_user_id")
        if not email:
            raise HTTPException(status_code=401, detail="Invalid token")
    except JWTError:
        # ─── v2.1.16: Cloud-Auth Bridge fallback ────────────────────
        # The JWT couldn't be verified with the LOCAL SECRET_KEY. On a
        # desktop install this is the COMMON case (the token was
        # issued by krexion.com via the cloud-proxy). Verify it
        # against the cloud `/api/auth/me` endpoint and use the same
        # local-mirror pattern as `get_current_user`. `verify_cloud_token`
        # is imported at startup and has a 5-min cache so we don't
        # hammer the cloud on every heavy-job request.
        if not IS_CLOUD and verify_cloud_token is not None:
            try:
                cloud_user = await verify_cloud_token(auth_header)
            except Exception:  # noqa: BLE001
                cloud_user = None
            if cloud_user:
                local_user = await main_db.users.find_one(
                    {"id": cloud_user.get("id")},
                    {"_id": 0, "password_hash": 0},
                )
                if not local_user and cloud_user.get("email"):
                    local_user = await main_db.users.find_one(
                        {"email": cloud_user.get("email")},
                        {"_id": 0, "password_hash": 0},
                    )
                if not local_user:
                    # First time seeing this cloud user — mirror into
                    # local Mongo with all heavy-job feature flags
                    # ON. The cloud is the source of truth.
                    local_user = {
                        "id": cloud_user.get("id"),
                        "email": cloud_user.get("email"),
                        "name": cloud_user.get("name") or (cloud_user.get("email") or "").split("@")[0],
                        "is_admin": bool(cloud_user.get("is_admin")),
                        "status": "active",  # cloud already authorised
                        "features": cloud_user.get("features") or {f: True for f in (
                            "real_user_traffic", "form_filler",
                            "visual_recorder", "proxies", "links",
                            "clicks", "import_traffic",
                            "email_checker", "phone_checker", "separate_data",
                            "ua_generator", "ua_checker",
                            "real_traffic", "import_data",
                            "adspower", "uploaded_things",
                            "profile_builder", "traffic_sources",
                            "cpi", "settings",
                        )},
                        "subscription_type": cloud_user.get("subscription_type"),
                        "subscription_expires": cloud_user.get("subscription_expires"),
                        "max_sub_users": cloud_user.get("max_sub_users"),
                        "max_links": cloud_user.get("max_links"),
                        "max_clicks": cloud_user.get("max_clicks"),
                        "created_at": cloud_user.get("created_at") or datetime.utcnow().isoformat(),
                        "cloud_synced": True,
                    }
                    try:
                        await main_db.users.insert_one(local_user.copy())
                    except Exception:  # noqa: BLE001
                        # Race — fetch fresh
                        local_user = await main_db.users.find_one(
                            {"id": cloud_user.get("id")},
                            {"_id": 0, "password_hash": 0},
                        ) or local_user
                else:
                    # Existing mirror — refresh feature flags + status
                    # from cloud so a recent admin-side change shows
                    # up immediately (we already paid the cloud call).
                    updates = {}
                    if cloud_user.get("status"):
                        updates["status"] = cloud_user["status"]
                    if cloud_user.get("features"):
                        updates["features"] = cloud_user["features"]
                    if cloud_user.get("subscription_expires"):
                        updates["subscription_expires"] = cloud_user["subscription_expires"]
                    if updates:
                        try:
                            await main_db.users.update_one(
                                {"id": local_user["id"]},
                                {"$set": updates},
                            )
                            local_user.update(updates)
                        except Exception:  # noqa: BLE001
                            pass
                return local_user
        raise HTTPException(status_code=401, detail="Invalid token")

    # If sub-user, get parent user data
    if is_sub_user and parent_user_id:
        sub_user = await main_db.sub_users.find_one({"email": email}, {"_id": 0, "password_hash": 0})
        if not sub_user:
            raise HTTPException(status_code=401, detail="Sub-user not found")
        if not sub_user.get("is_active", True):
            raise HTTPException(status_code=403, detail="Sub-user account is deactivated")
        
        parent_user = await main_db.users.find_one({"id": parent_user_id}, {"_id": 0, "password_hash": 0})
        if not parent_user:
            raise HTTPException(status_code=401, detail="Parent user not found")
        if parent_user.get("status") == "blocked":
            raise HTTPException(status_code=403, detail="Parent account has been blocked")
        if parent_user.get("status") != "active":
            raise HTTPException(status_code=403, detail="Parent account is not active")
        
        # Return parent user with sub-user info and mapped features
        parent_user["is_sub_user"] = True
        parent_user["sub_user_id"] = sub_user["id"]
        parent_user["sub_user_email"] = sub_user["email"]
        parent_user["sub_user_permissions"] = sub_user.get("permissions", {})
        
        # Map sub-user permissions to features (cap by parent's owned features)
        parent_user["features"] = _build_sub_user_features(
            sub_user.get("permissions", {}),
            parent_user.get("features", {}),
        )
        return parent_user
    
    user = await main_db.users.find_one({"email": email}, {"_id": 0, "password_hash": 0})
    if not user:
        raise HTTPException(status_code=401, detail="User not found")
    
    # Check if blocked
    if user.get("status") == "blocked":
        raise HTTPException(status_code=403, detail="Your account has been blocked. Contact admin for support.")
    
    user["is_sub_user"] = False
    return user

def check_sub_user_permission(user: dict, permission: str):
    """Check if sub-user has specific permission"""
    if user.get("is_sub_user"):
        permissions = user.get("sub_user_permissions", {})
        if not permissions.get(permission, False):
            raise HTTPException(status_code=403, detail=f"You don't have permission to {permission}")
    return True

async def setup_user_database(user_id: str):
    """Create indexes for user-specific database"""
    user_db = get_user_db(user_id)
    try:
        await user_db.clicks.create_index([("link_id", 1), ("created_at", -1)])
        await user_db.clicks.create_index([("created_at", -1)])
        await user_db.clicks.create_index([("ip_address", 1)])
        await user_db.clicks.create_index([("ipv4", 1)])  # Fast IPv4 lookup
        await user_db.clicks.create_index([("ipv6", 1)])  # Fast IPv6 lookup
        await user_db.clicks.create_index([("detected_ip", 1)])  # Fast detected IP lookup
        await user_db.links.create_index([("short_code", 1)], unique=True)
        await user_db.proxies.create_index([("status", 1)])
        await user_db.proxies.create_index([("proxy_ip", 1)])
    except Exception as e:
        print(f"Error setting up user database: {e}")

@api_router.post("/auth/register", response_model=Token)
async def register(user: UserCreate):
    existing = await main_db.users.find_one({"email": user.email})
    if existing:
        raise HTTPException(status_code=400, detail="Email already registered")
    
    user_id = str(uuid.uuid4())
    user_doc = {
        "id": user_id,
        "email": user.email,
        "name": user.name,
        "password_hash": get_password_hash(user.password),
        "status": "pending",  # pending, active, blocked
        "features": DEFAULT_FEATURES.copy(),
        "subscription_note": "",
        "created_at": datetime.now(timezone.utc).isoformat()
    }
    
    await main_db.users.insert_one(user_doc)
    
    # Setup user-specific database
    await setup_user_database(user_id)
    
    access_token = create_access_token(data={"sub": user.email})
    
    user_response = {
        "id": user_doc["id"], 
        "email": user_doc["email"], 
        "name": user_doc["name"],
        "status": user_doc["status"],
        "features": user_doc["features"]
    }
    return {"access_token": access_token, "token_type": "bearer", "user": user_response}

@api_router.post("/auth/login", response_model=Token)
async def login(user: UserLogin):
    # Check main users first
    db_user = await main_db.users.find_one({"email": user.email}, {"_id": 0})
    
    if db_user:
        if not verify_password(user.password, db_user["password_hash"]):
            raise HTTPException(status_code=401, detail="Invalid credentials")
        
        if db_user.get("status") == "blocked":
            raise HTTPException(status_code=403, detail="Your account has been blocked. Contact admin for support.")
        
        access_token = create_access_token(data={"sub": user.email, "is_sub_user": False})
        user_response = {
            "id": db_user["id"], 
            "email": db_user["email"], 
            "name": db_user["name"],
            "status": db_user.get("status", "pending"),
            "features": db_user.get("features", DEFAULT_FEATURES),
            "is_sub_user": False
        }
        return {"access_token": access_token, "token_type": "bearer", "user": user_response}
    
    # Check sub-users
    sub_user = await main_db.sub_users.find_one({"email": user.email}, {"_id": 0})
    if sub_user:
        if not verify_password(user.password, sub_user["password_hash"]):
            raise HTTPException(status_code=401, detail="Invalid credentials")
        
        if not sub_user.get("is_active", True):
            raise HTTPException(status_code=403, detail="Sub-user account is deactivated")
        
        # Get parent user
        parent_user = await main_db.users.find_one({"id": sub_user["parent_user_id"]}, {"_id": 0})
        if not parent_user or parent_user.get("status") != "active":
            raise HTTPException(status_code=403, detail="Parent account is not active")
        
        # Update last active
        await main_db.sub_users.update_one(
            {"id": sub_user["id"]},
            {"$set": {"last_active": datetime.now(timezone.utc).isoformat()}}
        )
        
        access_token = create_access_token(data={
            "sub": user.email, 
            "is_sub_user": True,
            "parent_user_id": sub_user["parent_user_id"]
        })
        
        user_response = {
            "id": sub_user["id"],
            "email": sub_user["email"],
            "name": sub_user["name"],
            "permissions": sub_user.get("permissions", {}),
            "is_sub_user": True,
            "parent_user_id": sub_user["parent_user_id"],
            "parent_name": parent_user["name"],
            "status": parent_user.get("status", "active"),
            # Map sub-user permissions to features for frontend compatibility
            "features": _build_sub_user_features(
                sub_user.get("permissions", {}),
                parent_user.get("features", {}),
            ),
            "subscription_type": parent_user.get("subscription_type", "free")
        }
        return {"access_token": access_token, "token_type": "bearer", "user": user_response}
    
    raise HTTPException(status_code=401, detail="Invalid credentials")

# ==================== FORGOT PASSWORD ====================
class ForgotPasswordRequest(BaseModel):
    email: str

class ResetPasswordRequest(BaseModel):
    token: str
    new_password: str

@api_router.post("/auth/forgot-password")
async def forgot_password(request: ForgotPasswordRequest):
    """Generate password reset token and send email for all user types"""
    user = None
    user_type = "user"
    user_name = "User"
    
    # Check if it's an admin
    if request.email == ADMIN_EMAIL:
        user = {"id": "admin", "email": ADMIN_EMAIL, "name": "Admin"}
        user_type = "admin"
        user_name = "Admin"
    
    # Check main users
    if not user:
        user = await main_db.users.find_one({"email": request.email})
        if user:
            user_type = "main user"
            user_name = user.get("name", "User")
    
    # Check sub-users
    if not user:
        sub_user = await main_db.sub_users.find_one({"email": request.email})
        if sub_user:
            user = sub_user
            user_type = "sub-user"
            user_name = sub_user.get("name", "User")
    
    if not user:
        # Don't reveal if email exists - still return success message
        return {"message": "If email exists, reset instructions will be sent", "email_sent": False}
    
    # Generate reset token (valid for 1 hour)
    reset_token = str(uuid.uuid4())
    expires = datetime.now(timezone.utc) + timedelta(hours=1)
    
    await main_db.password_resets.insert_one({
        "token": reset_token,
        "user_id": user["id"],
        "user_type": user_type,
        "email": request.email,
        "expires": expires.isoformat(),
        "used": False,
        "created_at": datetime.now(timezone.utc).isoformat()
    })
    
    # Send password reset email
    email_result = await send_password_reset_email(
        to_email=request.email,
        user_name=user_name,
        reset_token=reset_token,
        user_type=user_type
    )
    
    response = {
        "message": "Password reset instructions sent to your email",
        "email_sent": email_result.get("status") == "sent",
        "expires_in": "1 hour"
    }
    
    # Log demo mode info but don't expose reset URL to frontend
    if email_result.get("status") == "demo":
        logger.info(f"[DEMO MODE] Reset URL for {request.email}: {email_result.get('reset_url')}")
    
    return response

@api_router.post("/auth/reset-password")
async def reset_password(request: ResetPasswordRequest):
    """Reset password using token - works for all user types"""
    reset_doc = await main_db.password_resets.find_one({
        "token": request.token,
        "used": False
    })
    
    if not reset_doc:
        raise HTTPException(status_code=400, detail="Invalid or expired reset token")
    
    # Check expiration
    expires = datetime.fromisoformat(reset_doc["expires"])
    if datetime.now(timezone.utc) > expires:
        raise HTTPException(status_code=400, detail="Reset token has expired")
    
    # Update password based on user type
    new_hash = get_password_hash(request.new_password)
    user_type = reset_doc.get("user_type", "main user")
    user_id = reset_doc["user_id"]
    
    if user_type == "admin":
        # Admin password is in env, but we can update it in a config collection
        await main_db.admin_config.update_one(
            {"key": "admin_password"},
            {"$set": {"value": new_hash, "updated_at": datetime.now(timezone.utc).isoformat()}},
            upsert=True
        )
        logger.info(f"Admin password updated via reset token")
    elif user_type == "sub-user":
        # Update sub-user password
        await main_db.sub_users.update_one(
            {"id": user_id},
            {"$set": {"password_hash": new_hash}}
        )
        logger.info(f"Sub-user password reset for user_id: {user_id}")
    else:
        # Update main user password
        await main_db.users.update_one(
            {"id": user_id},
            {"$set": {"password_hash": new_hash}}
        )
        logger.info(f"Main user password reset for user_id: {user_id}")
    
    # Mark token as used
    await main_db.password_resets.update_one(
        {"token": request.token},
        {"$set": {"used": True, "used_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    return {"message": "Password reset successfully"}

@api_router.get("/auth/verify-reset-token/{token}")
async def verify_reset_token(token: str):
    """Verify if reset token is valid"""
    reset_doc = await main_db.password_resets.find_one({
        "token": token,
        "used": False
    })
    
    if not reset_doc:
        raise HTTPException(status_code=400, detail="Invalid token")
    
    expires = datetime.fromisoformat(reset_doc["expires"])
    if datetime.now(timezone.utc) > expires:
        raise HTTPException(status_code=400, detail="Token expired")
    
    return {"valid": True, "email": reset_doc["email"]}

@api_router.get("/auth/me")
async def get_me(user: dict = Depends(get_current_user)):
    # Handle sub-user
    if user.get("is_sub_user"):
        return {
            "id": user.get("sub_user_id"),
            "email": user["email"],
            "name": user["name"],
            "status": user.get("status", "active"),
            "features": user.get("features", {}),
            "is_sub_user": True,
            "parent_user_id": user.get("parent_user_id"),
            "permissions": user.get("permissions", {}),
            "admin_contact": ADMIN_CONTACT_EMAIL
        }
    
    # Handle main user
    sub_user_count = await db.sub_users.count_documents({"parent_user_id": user["id"]})
    features = user.get("features", DEFAULT_FEATURES)
    max_sub_users = features.get("max_sub_users", 0)
    return {
        "id": user["id"], 
        "email": user["email"], 
        "name": user["name"],
        "status": user.get("status", "pending"),
        "features": features,
        "subscription_type": user.get("subscription_type", "free"),
        "subscription_expires": user.get("subscription_expires"),
        "sub_user_count": sub_user_count,
        "max_sub_users": max_sub_users,
        "is_sub_user": False,
        "admin_contact": ADMIN_CONTACT_EMAIL
    }

@api_router.put("/auth/profile")
async def update_profile(update: UserProfileUpdate, user: dict = Depends(get_current_user_with_fresh_data)):
    """Update user's own profile (name, password)"""
    update_data = {}
    
    if update.name:
        update_data["name"] = update.name
    
    if update.new_password:
        if not update.current_password:
            raise HTTPException(status_code=400, detail="Current password required to change password")
        
        # Verify current password
        db_user = await db.users.find_one({"id": user["id"]})
        if not verify_password(update.current_password, db_user["password_hash"]):
            raise HTTPException(status_code=400, detail="Current password is incorrect")
        
        update_data["password_hash"] = get_password_hash(update.new_password)
    
    if update_data:
        await db.users.update_one({"id": user["id"]}, {"$set": update_data})
    
    updated_user = await db.users.find_one({"id": user["id"]}, {"_id": 0, "password_hash": 0})
    return {"message": "Profile updated successfully", "user": updated_user}


