# ==================== FORM FILLER / SURVEY BOT ====================

from form_filler import (
    load_rows_from_excel,
    load_rows_from_google_sheet,
    run_form_filler_job,
    create_job_record,
    cleanup_old_job,
    RESULTS_ROOT as _FF_RESULTS_ROOT,
    JOBS as _FF_JOBS,
)


@api_router.post("/form-filler/jobs")
async def form_filler_create_job(
    background: BackgroundTasks,
    target_link_id: Optional[str] = Form(None),
    target_url: Optional[str] = Form(None),
    data_source: str = Form("excel"),              # "excel" or "gsheet"
    gsheet_url: Optional[str] = Form(None),
    count: int = Form(10),
    duration_minutes: float = Form(5.0),
    skip_captcha: bool = Form(True),
    use_user_agents: bool = Form(True),
    use_proxies: bool = Form(False),
    file: Optional[UploadFile] = File(None),
    # ── 2026-02 v2.1.31 — Anti-Detect Wiring (Phase 1) ──────────────
    pacing_per_hour: int = Form(0),
    identity_label: str = Form(""),
    tls_prewarm: bool = Form(False),
    # 2026-02 Step 5 — Phase 3+4 parity with RUT (Big-1)
    proxy_chain_enabled: bool = Form(False),
    proxy_chain_use_tor: bool = Form(True),
    browser_variant: str = Form("auto"),
    behavioral_bio_enabled: bool = Form(False),
    ip_warmup_enabled: bool = Form(False),
    user: dict = Depends(get_current_user),
    _cloud_gate: bool = Depends(require_local_mode),
):
    """
    Create a Form Filler job. The request is multipart/form-data.
    EITHER `target_link_id` (to reuse a link from the user's Links panel)
    OR `target_url` must be provided.
    `data_source` = "excel" requires `file`; `data_source` = "gsheet" requires `gsheet_url`.
    """
    check_user_feature(user, "form_filler")
    # Resolve target URL
    final_url = (target_url or "").strip()
    if target_link_id and not final_url:
        link = await db.links.find_one({"id": target_link_id, "user_id": user["id"]}, {"_id": 0})
        if not link:
            raise HTTPException(status_code=404, detail="Link not found in your panel")
        final_url = link.get("destination_url") or link.get("target_url") or link.get("url", "")
    if not final_url or not final_url.startswith(("http://", "https://")):
        raise HTTPException(status_code=400, detail="Provide a valid target URL or pick a link from your panel")

    # Load rows
    if data_source == "gsheet":
        if not gsheet_url:
            raise HTTPException(status_code=400, detail="gsheet_url is required when data_source='gsheet'")
        try:
            rows = await load_rows_from_google_sheet(gsheet_url)
        except Exception as e:
            raise HTTPException(status_code=400, detail=f"Could not load Google Sheet: {e}")
    else:
        if not file:
            raise HTTPException(status_code=400, detail="Excel/CSV file is required when data_source='excel'")
        content = await file.read()
        try:
            rows = load_rows_from_excel(content, file.filename or "data.xlsx")
        except Exception as e:
            raise HTTPException(status_code=400, detail=f"Could not parse file: {e}")

    if not rows:
        raise HTTPException(status_code=400, detail="Uploaded data has no rows")
    if count < 1 or count > 5000:
        raise HTTPException(status_code=400, detail="Count must be between 1 and 5000")
    if duration_minutes < 0 or duration_minutes > 1440:
        raise HTTPException(status_code=400, detail="Duration must be between 0 and 1440 minutes")

    # Optional: gather user's stored UAs + proxies
    ua_list = None
    if use_user_agents:
        # Use the master pool from the UA generator as a simple source
        try:
            from server import _IOS_DEVICES, _ANDROID_DEVICES, _ua_chrome_android, _ua_safari_ios, _CHROME_VERSIONS  # self-import, safe
        except Exception:
            pass
        # Generate 10 realistic UAs ad-hoc
        uas = []
        for _ in range(min(count, 20)):
            d = random.choice(_ANDROID_DEVICES + _IOS_DEVICES)
            if "and_ver" in d:
                uas.append(_ua_chrome_android(d, random.choice(_CHROME_VERSIONS)))
            else:
                uas.append(_ua_safari_ios(d))
        ua_list = uas

    proxy_list = None
    if use_proxies:
        proxies = await db.proxies.find(
            {"user_id": user["id"], "status": {"$in": ["active", "online", None]}},
            {"_id": 0, "proxy_ip": 1, "proxy_port": 1, "username": 1, "password": 1},
        ).to_list(500)
        proxy_list = []
        for p in proxies:
            ip = p.get("proxy_ip")
            port = p.get("proxy_port")
            if not ip or not port:
                continue
            if p.get("username") and p.get("password"):
                proxy_list.append(f"{ip}:{port}:{p['username']}:{p['password']}")
            else:
                proxy_list.append(f"{ip}:{port}")
        if not proxy_list:
            proxy_list = None  # fall through to no-proxy mode

    # Create job record & kick off background task
    job_id = str(uuid.uuid4())
    create_job_record(
        job_id=job_id,
        user_id=user["id"],
        target_url=final_url,
        total_rows=len(rows),
        count=count,
        duration_minutes=duration_minutes,
        data_source=data_source,
    )
    # Fetch user's saved AI key + provider for AI Vision fallback.
    # If neither key is set, AI fallback is silently disabled.
    db_user = await db.users.find_one(
        {"id": user["id"]},
        {"_id": 0, "gemini_api_key": 1, "openai_api_key": 1, "ai_provider": 1},
    ) or {}
    ai_provider = (db_user.get("ai_provider") or "gemini").strip().lower()
    if ai_provider == "openai":
        ai_api_key = (db_user.get("openai_api_key") or "").strip() or None
    else:
        ai_api_key = (db_user.get("gemini_api_key") or "").strip() or None
    if not ai_api_key:
        # auto-fallback to the other provider if its key exists
        if ai_provider == "gemini" and (db_user.get("openai_api_key") or "").strip():
            ai_provider = "openai"
            ai_api_key = db_user["openai_api_key"].strip()
        elif ai_provider == "openai" and (db_user.get("gemini_api_key") or "").strip():
            ai_provider = "gemini"
            ai_api_key = db_user["gemini_api_key"].strip()

    background.add_task(
        run_form_filler_job,
        job_id=job_id,
        target_url=final_url,
        rows=rows,
        count=count,
        duration_minutes=duration_minutes,
        user_agents=ua_list,
        proxies=proxy_list,
        skip_captcha=skip_captcha,
        db=db,
        gemini_api_key=ai_api_key,
        ai_provider=ai_provider,
        # 2026-02 v2.1.31 — Anti-Detect Phase 1 wiring
        pacing_per_hour=max(0, int(pacing_per_hour or 0)),
        identity_label=(identity_label or "").strip()[:120],
        tls_prewarm=bool(tls_prewarm),
        # 2026-02 Step 5 — Phase 3+4 parity
        proxy_chain_enabled=bool(proxy_chain_enabled),
        proxy_chain_use_tor=bool(proxy_chain_use_tor),
        browser_variant=(browser_variant or "auto").strip().lower()[:32],
        behavioral_bio_enabled=bool(behavioral_bio_enabled),
        ip_warmup_enabled=bool(ip_warmup_enabled),
    )
    return {
        "job_id": job_id,
        "status": "queued",
        "total": min(count, len(rows)),
        "target_url": final_url,
        "rows_loaded": len(rows),
    }


@api_router.get("/form-filler/jobs")
async def form_filler_list_jobs(user: dict = Depends(get_current_user)):
    """List this user's form-filler jobs (hot cache + persisted)."""
    check_user_feature(user, "form_filler")
    # Merge in-memory + persisted
    persisted = await db.form_filler_jobs.find(
        {"user_id": user["id"]}, {"_id": 0, "report": 0}
    ).sort("created_at", -1).to_list(200)
    hot = [j for j in _FF_JOBS.values() if j.get("user_id") == user["id"]]
    seen, out = set(), []
    for j in sorted(hot + persisted, key=lambda x: x.get("created_at", ""), reverse=True):
        jid = j.get("job_id")
        if jid in seen:
            continue
        seen.add(jid)
        out.append(j)
    return {"jobs": out}


@api_router.get("/form-filler/jobs/{job_id}")
async def form_filler_get_job(job_id: str, user: dict = Depends(get_current_user)):
    """Progress + report for one job."""
    check_user_feature(user, "form_filler")
    j = _FF_JOBS.get(job_id)
    if not j:
        j = await db.form_filler_jobs.find_one({"job_id": job_id, "user_id": user["id"]}, {"_id": 0})
    if not j:
        raise HTTPException(status_code=404, detail="Job not found")
    if j.get("user_id") != user["id"]:
        raise HTTPException(status_code=403, detail="Forbidden")
    return j


@api_router.get("/form-filler/jobs/{job_id}/download")
async def form_filler_download(job_id: str, user: dict = Depends(get_current_user)):
    """Download the ZIP (screenshots + report.csv)."""
    check_user_feature(user, "form_filler")
    j = _FF_JOBS.get(job_id) or await db.form_filler_jobs.find_one({"job_id": job_id, "user_id": user["id"]}, {"_id": 0})
    if not j or j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    if j.get("status") != "completed":
        raise HTTPException(status_code=400, detail=f"Job is {j.get('status')} — not ready yet")
    zip_path = Path(_FF_RESULTS_ROOT) / job_id / "results.zip"
    if not zip_path.exists():
        raise HTTPException(status_code=404, detail="Results archive not found on disk")
    return FileResponse(
        str(zip_path),
        media_type="application/zip",
        filename=f"form-filler-{job_id[:8]}.zip",
    )


@api_router.delete("/form-filler/jobs/{job_id}")
async def form_filler_delete(job_id: str, user: dict = Depends(get_current_user)):
    check_user_feature(user, "form_filler")
    j = _FF_JOBS.get(job_id) or await db.form_filler_jobs.find_one({"job_id": job_id, "user_id": user["id"]}, {"_id": 0})
    if not j or j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    cleanup_old_job(job_id)
    await db.form_filler_jobs.delete_one({"job_id": job_id, "user_id": user["id"]})
    return {"message": "Deleted"}


# ==================== REAL USER TRAFFIC (anti-detect) ====================

from real_user_traffic import (
    run_real_user_traffic_job,
    create_rut_job,
    cleanup_rut_job,
    request_job_cancel,
    get_live_steps as _rut_get_live_steps,
    RUT_JOBS as _RUT_JOBS,
    get_engine_status as _rut_get_engine_status,
)
import proxyjet_module as _pj


def _is_local_or_private_host(url: str) -> bool:
    """True if url's host is not reachable through a public proxy —
    localhost / 127.x / 0.0.0.0 / 10.x / 172.16-31.x / 192.168.x /
    Docker service names ('backend', 'frontend', 'mongo', etc.).
    Used to detect when the user pasted a local-only tracker URL that
    can't be opened through a real-user-traffic proxy."""
    try:
        from urllib.parse import urlparse
        import ipaddress
        host = (urlparse(url).hostname or "").lower()
        if not host:
            return False
        # Common local / Docker service names
        if host in ("localhost", "backend", "frontend", "mongo", "host.docker.internal"):
            return True
        if host.endswith(".local") or host.endswith(".internal"):
            return True
        try:
            ip = ipaddress.ip_address(host)
            return ip.is_loopback or ip.is_private or ip.is_link_local or ip.is_unspecified
        except ValueError:
            return False
    except Exception:
        return False


def _is_emergent_preview_host(url: str) -> bool:
    """Detect Emergent preview-pod hosts. These are behind a Cloudflare /
    Kubernetes-ingress bot-protection layer that returns HTTP 403 + captcha
    for requests coming from commercial residential-proxy egress IPs. So if
    the RUT engine is asked to hit the tracker URL on THIS preview pod
    through a residential proxy, EVERY visit will land on a captcha page and
    the form will never be reached. When we detect this case we auto-swap
    the browser destination to the link's `offer_url` (direct advertiser
    URL) so the form-fill + conversion flow actually works in the preview."""
    try:
        from urllib.parse import urlparse
        h = (urlparse(url or "").hostname or "").lower()
        if not h:
            return False
        return (
            h.endswith(".preview.emergentagent.com")
            or h.endswith(".preview.emergent.host")
            or h.endswith(".preview.emergent.sh")
        )
    except Exception:
        return False


def _rut_build_target_url(request: Request, link: dict, explicit_target: Optional[str], force_tracker: bool = False) -> str:
    sc = link["short_code"]
    offer = (link.get("offer_url") or link.get("destination_url") or "").strip()
    offer_is_public = bool(
        offer
        and offer.lower().startswith(("http://", "https://"))
        and not _is_local_or_private_host(offer)
        and not _is_emergent_preview_host(offer)
    )
    # v2.1.19 — Tracker URL MUST be the cloud (krexion.com), never the
    # customer's local 127.0.0.1. Reasons:
    #   1. Links live cloud-side now (v2.1.15 architecture). The cloud's
    #      /api/t/{code} handler records the click + redirects to the
    #      offer. Local /api/t/ would record into local Mongo and the
    #      cloud admin dashboard wouldn't see the visit.
    #   2. Residential proxies CAN'T reach 127.0.0.1 anyway — they hand
    #      back ERR_TUNNEL_CONNECTION_FAILED, which is why the old RUT
    #      target was being auto-swapped to the offer_url, bypassing the
    #      tracker entirely and losing click attribution.
    cloud_tracker_base = (
        os.environ.get("KREXION_CLOUD_URL")
        or "https://krexion.com"
    ).rstrip("/")
    if explicit_target and explicit_target.strip():
        tu = explicit_target.strip().rstrip("/")
        if tu.lower().startswith(("http://", "https://")):
            # If the caller passed a local/preview tracker URL, REWRITE it
            # to the cloud tracker (unless force_tracker explicitly wants
            # the literal URL for offer-URL bypass testing).
            if _is_local_or_private_host(tu) or _is_emergent_preview_host(tu):
                if not force_tracker and offer_is_public:
                    return offer
                # Force-tracker case: use the cloud /api/t/{sc} so the
                # click is at least recorded on cloud.
                return f"{cloud_tracker_base}/api/t/{sc}"
            return tu
        # Bare host like "yourdomain.com" → append tracker path
        return f"{tu}/api/t/{sc}"
    # No explicit_target → always prefer cloud tracker (professional URL
    # + ensures click attribution on the cloud Mongo).
    return f"{cloud_tracker_base}/api/t/{sc}"
    # ── Legacy code path kept for reference only (unreachable) ───────
    public_base = os.environ.get("PUBLIC_BASE_URL") or os.environ.get("REACT_APP_BACKEND_URL") or ""
    if public_base and public_base.startswith("http"):
        candidate = f"{public_base.rstrip('/')}/api/t/{sc}"
        if not force_tracker and (_is_local_or_private_host(candidate) or _is_emergent_preview_host(candidate)):
            if offer_is_public:
                return offer
        return candidate
    try:
        fwd_proto = request.headers.get("x-forwarded-proto") or request.url.scheme or "https"
        fwd_host = request.headers.get("x-forwarded-host") or request.headers.get("host")
        if fwd_host:
            scheme = fwd_proto.split(",")[0].strip()
            host = fwd_host.split(",")[0].strip()
            candidate = f"{scheme}://{host}/api/t/{sc}"
            if not force_tracker and (_is_local_or_private_host(candidate) or _is_emergent_preview_host(candidate)):
                if offer_is_public:
                    return offer
            return candidate
    except Exception:
        pass
    raise HTTPException(
        status_code=400,
        detail=("Could not determine a PUBLIC short-link URL. Paste it in the "
                "'Target URL' field or set PUBLIC_BASE_URL in backend .env."),
    )


# ─── Concurrent-safe lock for the global click-IP cache rebuild ────────
# Without this, N concurrent RUT jobs whose cache TTL expired at the same
# moment would all fan out to scan every database's `clicks` collection
# in parallel — pushing Mongo into a thundering-herd. The lock ensures
# only ONE rebuild runs at a time; the others reuse the freshly-warmed
# cache.
_DUP_IP_CACHE_LOCK = asyncio.Lock()


async def _get_dup_ip_set_safe(
    force_refresh: bool = False,
    user_id: Optional[str] = None,
) -> set:
    """Concurrent-safe wrapper around get_all_click_ips_from_entire_database().
    Returns an empty set on any failure so the BG task never crashes here.

    2026-05: When `force_refresh=True` the cache is bypassed and a fresh
    scan of all `clicks` collections + the persistent `rut_burnt_ips`
    block-list is performed.

    2026-01: `user_id` parameter — scopes the scan to that user's
    per-tenant DB only (sub-users share parent's DB, see
    get_db_for_user). Eliminates cross-tenant false-positive
    duplicates.
    """
    try:
        async with _DUP_IP_CACHE_LOCK:
            return await get_all_click_ips_from_entire_database(
                force_refresh=force_refresh, user_id=user_id,
            )
    except Exception as e:  # noqa: BLE001
        logger.warning(f"Could not load duplicate IP set: {e}")
        return set()


# ──────────────────────────────────────────────────────────────────────
# Memory-pressure throttle — ZERO-OOM safety net
# ──────────────────────────────────────────────────────────────────────
# When backend RSS approaches the container `mem_limit` (default 6 GB on
# the production stack), pause spawning new visits / new BG prep tasks.
# In-flight visits keep running normally — they finish, RSS drops, and
# the throttle releases automatically.
#
# This prevents the cgroup OOM-killer from terminating the backend
# process during peak Playwright contexts, which would orphan the job
# record (the auto-resume reaper picks it up but a momentary throttle
# is way better than a full restart cycle).
#
# Tunables (env-overridable so the user can match their own mem_limit):
#   RUT_MEM_LIMIT_MB        — total container cap (default 6144 = 6 GB)
#   RUT_MEM_THROTTLE_PCT    — pause-spawn threshold (default 80 = 80%)
#   RUT_MEM_RESUME_PCT      — resume-spawn threshold (default 65 = 65%)
# Both percentages are computed against `mem_limit`, NOT against
# host RAM, so the math stays correct on small-memory test pods.
import psutil as _psutil


def _detect_container_mem_limit_mb(default_mb: int = 6144) -> int:
    """Auto-detect this container's memory hard-limit in MB.

    Reads (in priority order):
      1. cgroup v2:  /sys/fs/cgroup/memory.max
      2. cgroup v1:  /sys/fs/cgroup/memory/memory.limit_in_bytes
      3. psutil:     actual system RAM (Windows / macOS / native installs)
      4. fallback:   `default_mb`

    Both cgroup files return huge sentinel values when no limit is set
    (cgroup v2 = the literal string "max"; cgroup v1 = INT64_MAX-ish ≈
    9.2 EB). We treat anything > 1 TB as "unbounded" and fall back to
    the default. This matches Docker's own behaviour for unlimited
    containers and avoids the throttle never firing on dev machines
    where Docker has no mem_limit set.

    2026-06-28 (native-app fix): step 3 added so customer Windows/macOS
    installs (KREXION_MODE=native, NSSM service or Electron-spawned
    backend) get a cap that reflects their ACTUAL machine RAM instead
    of the safe-but-tiny 6 GB default. Previously a 32 GB customer
    machine throttled the very first RUT job because backend RSS
    (Playwright + Chromium) easily crossed 80% of the fake 6 GB cap
    within the first minute. Now the same 32 GB machine gets a ~24 GB
    cap → throttle never falsely fires while real OOM protection on
    low-RAM machines (8 GB and below) is PRESERVED.
    """
    # cgroup v2 (Docker 20.10+ on cgroup-v2 hosts — most modern setups)
    try:
        v2_path = "/sys/fs/cgroup/memory.max"
        if os.path.exists(v2_path):
            with open(v2_path) as f:
                raw = f.read().strip()
            if raw and raw != "max":
                limit_bytes = int(raw)
                if 0 < limit_bytes < 1024**4:  # < 1 TB ⇒ a real cap
                    return max(256, limit_bytes // (1024 * 1024))
    except Exception:
        pass

    # cgroup v1 (older Docker setups — still common on Windows WSL2)
    try:
        v1_path = "/sys/fs/cgroup/memory/memory.limit_in_bytes"
        if os.path.exists(v1_path):
            with open(v1_path) as f:
                limit_bytes = int(f.read().strip())
            if 0 < limit_bytes < 1024**4:  # < 1 TB ⇒ a real cap
                return max(256, limit_bytes // (1024 * 1024))
    except Exception:
        pass

    # 3. Native install (no container limits) — derive from actual
    #    physical RAM so the throttle math is meaningful.
    #
    #    Formula: (total_ram_mb - 4096) * 0.85
    #      Reserve 4 GB for OS, Mongo, Chrome, AV, etc.
    #      Use 85% of the remaining headroom for the backend cap.
    #      Clamp to [1024, 32768] so 4 GB toy machines still get a
    #      sane minimum and 256 GB workstations don't overcommit.
    #
    #    Examples (matches what each tier "feels" like in practice):
    #       8 GB machine ->  3481 MB cap  (throttles correctly under load)
    #      16 GB machine -> 10444 MB cap  (single concurrent RUT job fine)
    #      32 GB machine -> 24371 MB cap  (47 concurrent visits OK — was the
    #                                     primary customer complaint that
    #                                     prompted this fix)
    #      64 GB machine -> 32768 MB cap  (clamped — Krexion never needs more)
    try:
        import psutil as _ps_mem  # local import; psutil is a hard runtime dep
        total_bytes = _ps_mem.virtual_memory().total
        if total_bytes and total_bytes > 0:
            total_mb = total_bytes // (1024 * 1024)
            # Only apply this branch when we actually have meaningful RAM
            # info (psutil sometimes returns 0 on locked-down kiosk OSes).
            if total_mb >= 2048:
                cap_mb = int((total_mb - 4096) * 0.85)
                cap_mb = max(1024, min(cap_mb, 32768))
                return cap_mb
    except Exception:
        pass

    return default_mb


# Resolve in this priority: explicit env override > cgroup auto-detect > default 6144
_default_cap_mb = _detect_container_mem_limit_mb(default_mb=6144)
_RUT_MEM_LIMIT_MB = int(os.environ.get("RUT_MEM_LIMIT_MB", str(_default_cap_mb)))
_RUT_MEM_THROTTLE_PCT = float(os.environ.get("RUT_MEM_THROTTLE_PCT", "80"))
_RUT_MEM_RESUME_PCT = float(os.environ.get("RUT_MEM_RESUME_PCT", "65"))
_MEM_THROTTLED_AT: Optional[float] = None  # epoch seconds; None = not throttled

logger.info(
    f"RUT memory throttle configured: cap={_RUT_MEM_LIMIT_MB} MB "
    f"(auto-detected={_default_cap_mb} MB, env-override={'yes' if 'RUT_MEM_LIMIT_MB' in os.environ else 'no'}), "
    f"throttle@{_RUT_MEM_THROTTLE_PCT}%, resume@{_RUT_MEM_RESUME_PCT}%"
)

# 2026-05: Surface the strict-proxy setting on startup so the admin can
# see at a glance whether direct-bypass leak protection is active.
_RUT_STRICT_PROXY = (
    os.environ.get("RUT_STRICT_PROXY_ONLY", "false").strip().lower()
    in ("1", "true", "yes", "on")
)
logger.info(
    f"RUT proxy mode: {'STRICT (no tracker-bypass — proxy-only enforced for EVERY hit)' if _RUT_STRICT_PROXY else 'NORMAL (tracker-bypass enabled for your own tracker domains only — external offers always use proxy)'}"
)


def _backend_rss_pct() -> float:
    """Return current process RSS as a percentage of the container
    memory limit. Used by the throttle loop and surfaced in
    /api/diagnostics/health."""
    try:
        rss_mb = _psutil.Process().memory_info().rss / (1024 * 1024)
        return (rss_mb / _RUT_MEM_LIMIT_MB) * 100 if _RUT_MEM_LIMIT_MB > 0 else 0.0
    except Exception:
        return 0.0


async def _wait_for_memory_headroom(
    job_id: Optional[str] = None,
    max_wait_seconds: float = 120.0,
) -> bool:
    """Block here until backend RSS drops below RESUME_PCT of mem_limit.

    Called BEFORE spawning a new RUT prep task / a new visit. Returns
    True if memory was OK (or recovered within max_wait); False if the
    timeout elapsed (extremely rare — would mean a true memory leak).

    While throttling, pushes a single live-log entry per job so the
    user sees WHY the job is paused rather than thinking it hung.
    """
    global _MEM_THROTTLED_AT
    pct = _backend_rss_pct()
    if pct < _RUT_MEM_THROTTLE_PCT:
        # Fast path — way under threshold, no waiting.
        if _MEM_THROTTLED_AT is not None and pct < _RUT_MEM_RESUME_PCT:
            _MEM_THROTTLED_AT = None
        return True

    # We're at or above the throttle threshold. Push a live-log marker
    # ONCE so the user sees "Memory pressure — pausing new visits…"
    # instead of silent inactivity.
    try:
        if job_id:
            from real_user_traffic import push_live_step as _push
            _push(
                job_id, 0, "throttle", "info",
                f"⏸ Memory pressure ({pct:.0f}% of {_RUT_MEM_LIMIT_MB} MB) — "
                f"pausing new visits until headroom recovers"
            )
    except Exception:
        pass

    if _MEM_THROTTLED_AT is None:
        _MEM_THROTTLED_AT = asyncio.get_event_loop().time()
        logger.warning(
            f"RUT memory throttle ENGAGED: RSS={pct:.1f}% of {_RUT_MEM_LIMIT_MB}MB cap. "
            f"Pausing new visit dispatch until recovery."
        )

    deadline = asyncio.get_event_loop().time() + max_wait_seconds
    while asyncio.get_event_loop().time() < deadline:
        await asyncio.sleep(2.0)
        pct = _backend_rss_pct()
        if pct < _RUT_MEM_RESUME_PCT:
            _MEM_THROTTLED_AT = None
            logger.info(
                f"RUT memory throttle RELEASED: RSS dropped to {pct:.1f}%. "
                f"Resuming visit dispatch."
            )
            try:
                if job_id:
                    from real_user_traffic import push_live_step as _push
                    _push(
                        job_id, 0, "throttle", "ok",
                        f"▶ Memory recovered ({pct:.0f}%) — resuming visits"
                    )
            except Exception:
                pass
            return True
    logger.error(
        f"RUT memory throttle TIMEOUT after {max_wait_seconds}s "
        f"(RSS still {pct:.1f}%). Continuing anyway — risk of OOM."
    )
    return False


async def _rut_prepare_and_run(
    job_id: str,
    user: dict,
    link: dict,
    target: str,
    params: Dict[str, Any],
) -> None:
    """Background task: do all the heavy preparation (gsheet fetches,
    Excel parsing, dup-IP scan, target-screenshot pHash), then dispatch
    the actual run_real_user_traffic_job runner.

    The job DB record was already inserted in the foreground endpoint
    with status="queued" — this function progressively updates it and,
    on any prep failure, marks status="failed" with `error_message` so
    the UI's existing job-poll surfaces the error to the user instantly.
    """
    consume_upload_ids: List[str] = []
    # Track prep-step counter so live-log idx stays unique even when no
    # visits have started yet (Live Activity dialog uses idx as cursor).
    _prep_step_counter = {"n": 0}

    async def _set_step(step_label: str) -> None:
        """Update the job's `prep_step` field so the UI can show what
        prep phase is currently running. Also ensures status is flipped
        from `queued` → `preparing` on the FIRST step so the user sees
        movement instantly instead of staring at `queued` for 10-30s
        while gsheets are fetched.

        ALSO pushes the step into the in-memory live-steps buffer so
        the "Live Activity" dialog shows prep progress immediately —
        without this push, prep steps were invisible (only visit-level
        steps were ever pushed) and the dialog showed
        "Waiting for the next backend step…" until visit #1 began.

        IMPORTANT — RESUME-AWARE:
        After an auto-resume, the reaper has already set status to
        `running` and the engine had previously been making real
        progress. Flipping the status BACK to `preparing` here would
        make the user (correctly) feel that the job has restarted from
        scratch. We use a conditional Mongo update that ONLY transitions
        `queued` → `preparing` and never downgrades a job that is
        already `running` / `completed` / `failed` / `stopped`.
        """
        # Conditional status flip — only affects fresh / queued jobs.
        try:
            await db.real_user_traffic_jobs.update_one(
                {"job_id": job_id, "status": {"$in": ["queued", "preparing"]}},
                {"$set": {"status": "preparing"}},
            )
        except Exception:
            pass
        # prep_step + prep_step_at always update — gives the UI a soft
        # indicator of current prep phase even on a job that's still
        # showing as `running` (after resume).
        try:
            await db.real_user_traffic_jobs.update_one(
                {"job_id": job_id},
                {"$set": {
                    "prep_step": step_label,
                    "prep_step_at": datetime.now(timezone.utc).isoformat(),
                }},
            )
        except Exception:
            pass
        try:
            from real_user_traffic import RUT_JOBS as _RJ, push_live_step as _push
            if job_id in _RJ:
                # Only push status to "preparing" in-memory if it's not
                # already a forward-state. Same logic as DB above.
                cur_status = _RJ[job_id].get("status")
                if cur_status in (None, "queued", "preparing"):
                    _RJ[job_id]["status"] = "preparing"
                _RJ[job_id]["prep_step"] = step_label
            _prep_step_counter["n"] += 1
            # visit=0 marks this as a job-level (prep) event; the dialog
            # already renders these without thumbnails.
            _push(job_id, 0, "prep", "info", step_label)
        except Exception:
            pass

    async def _mark_failed(reason: str) -> None:
        try:
            await db.real_user_traffic_jobs.update_one(
                {"job_id": job_id},
                {"$set": {
                    "status": "failed",
                    "error_message": reason[:500],
                    "preparing": False,
                    "finished_at": datetime.now(timezone.utc).isoformat(),
                }},
            )
        except Exception:
            pass
        # Also flip in-memory status so live-log endpoint reflects reality
        try:
            from real_user_traffic import RUT_JOBS as _RJ
            if job_id in _RJ:
                _RJ[job_id]["status"] = "failed"
                _RJ[job_id]["error_message"] = reason[:500]
        except Exception:
            pass

    try:
        # ZERO-OOM safety net — wait for memory headroom BEFORE we start
        # loading proxies / UAs / Excel rows. Avoids piling on more RSS
        # when the container is already near its cap.
        await _wait_for_memory_headroom(job_id=job_id, max_wait_seconds=180)
        await _set_step("Loading proxies…")
        # ── 0. Kick off dup-IP cache fetch in PARALLEL with proxy/UA load.
        # This used to block sequentially before step 4. On a cold
        # process / big DB it takes 200-2000 ms; running it concurrently
        # with the gsheet fetches below means we usually have the result
        # ready by the time we actually need it (zero added latency).
        # Result is awaited at step 4.
        dup_ip_task: Optional[asyncio.Task] = None
        if params.get("skip_duplicate_ip"):
            # 2026-05: force_refresh=True so each RUT job loads the
            # absolute latest burnt-IP block-list (clicks DB + the
            # persistent rut_burnt_ips collection). Without this, two
            # jobs started within the 60s cache window would share the
            # same stale set and re-use dirty IPs the FIRST job just
            # burned.
            # 2026-01 — scope to the MAIN user's tenant DB (sub-users
            # automatically inherit via get_db_for_user). Eliminates
            # the false-positive "duplicate IP" rejections that were
            # bleeding from other tenants' click history into this
            # job's exclusion set.
            _dup_user_id = user.get("parent_user_id") or user["id"]
            dup_ip_task = asyncio.create_task(
                _get_dup_ip_set_safe(force_refresh=True, user_id=_dup_user_id)
            )

        # ── 1. Proxies ────────────────────────────────────────────────
        upload_proxy_id = params.get("upload_proxy_id")
        upload_proxy_ids_raw = params.get("upload_proxy_ids")
        use_stored_proxies = params.get("use_stored_proxies")
        paste_proxy_lines = params.get("paste_proxy_lines") or []
        use_proxyjet_auto = bool(params.get("use_proxyjet_auto"))
        # 2026-01 — ProxyJet now defaults to ROW-FIRST on-demand mode.
        # The legacy pre-generation flow is preserved below and can be
        # re-activated by passing `proxyjet_legacy_pregen=true` in the
        # submit params. Both paths produce a valid `proxy_lines` list.
        proxyjet_legacy_pregen = bool(params.get("proxyjet_legacy_pregen"))
        if use_proxyjet_auto and not proxyjet_legacy_pregen:
            # ── 2026-01 ROW-FIRST ON-DEMAND MODE ─────────────────────
            # The engine now fetches a fresh state-matched ProxyJet IP
            # for EACH visit (after picking the row), retrying until
            # the exit-IP is unique vs. the user's prior clicks. We
            # therefore skip the upfront pre-generation that the legacy
            # path used — it wasted ProxyJet sessions when a state had
            # no leads / when the IP turned out to be a duplicate.
            #
            # We still validate credentials here so the user gets an
            # immediate error instead of failing 50 attempts in.
            try:
                _creds_check = await _pj.get_credentials(db, user["id"])
            except Exception as _e:
                return await _mark_failed(f"ProxyJet credentials check failed: {_e}")
            if not _creds_check:
                return await _mark_failed(
                    "ProxyJet credentials not configured. Add them in "
                    "Proxies → Auto Mode (one-time setup)."
                )
            proxy_lines = []
            await _set_step(
                "✓ ProxyJet ROW-FIRST mode active — IPs will be fetched on-demand "
                f"per visit (country: {params.get('proxyjet_country','US')}, "
                f"state from each data row)."
            )
        elif use_proxyjet_auto and proxyjet_legacy_pregen:
            # ── LEGACY ProxyJet pre-generation (fallback) ────────────
            # Kept for backward-compatibility & easy rollback. The
            # engine consumes these proxies the same way as a manual
            # upload list.
            total_clicks_val = int(params.get("total_clicks") or 10)
            target_mode_val = (params.get("target_mode") or "clicks").lower()
            if target_mode_val == "conversions":
                base_need = max(int(params.get("max_attempts") or 0),
                                int(params.get("target_conversions") or 0) * 5)
            else:
                base_need = total_clicks_val
            gen_count = max(base_need * 3, 50)
            gen_count = min(gen_count, 100000)

            # ── State-aware generation ───────────────────────────────
            # When the user has form-fill ON, state-match ON, and didn't
            # pin a specific ProxyJet state ("Any"), generate proxies in
            # the same state distribution as the lead file. This makes
            # every proxy have a matching-state lead → ZERO state-mismatch
            # skips, which is exactly what the user complained about.
            state_distribution: Optional[Dict[str, int]] = None
            needs_state_aware = (
                bool(params.get("form_fill_enabled"))
                and bool(params.get("state_match_enabled"))
                and not (params.get("proxyjet_state") or "").strip()
            )
            if needs_state_aware:
                try:
                    from real_user_traffic import (
                        _find_state_column as _fsc,
                        _normalize_state as _nst,
                    )
                    # Re-parse the data file inline (cheap — same file as
                    # step 3 will load again, parsing twice is negligible
                    # for 200-row Excel files).
                    _early_rows: List[Dict[str, Any]] = []
                    _ds = params.get("data_source") or "excel"
                    if _ds == "pending_from_job":
                        _src_job = await db.real_user_traffic_jobs.find_one(
                            {"job_id": params.get("import_pending_from_job_id"), "user_id": user["id"]},
                            {"_id": 0}
                        )
                        if _src_job:
                            from real_user_traffic import RESULTS_ROOT as _RR
                            _pp = Path(_src_job.get("pending_leads_path") or (_RR / params["import_pending_from_job_id"] / "pending_leads.xlsx"))
                            if _pp.exists():
                                _early_rows = load_rows_from_excel(_pp.read_bytes(), _pp.name)
                    elif _ds == "gsheet" and params.get("gsheet_url"):
                        _early_rows = await load_rows_from_google_sheet(params["gsheet_url"])
                    elif params.get("upload_data_file_id"):
                        _pair = await _load_upload_data_file(user["id"], params["upload_data_file_id"])
                        if _pair:
                            _fp, _on = _pair
                            _early_rows = load_rows_from_excel(Path(_fp).read_bytes(), _on)
                    elif params.get("file_bytes"):
                        _early_rows = load_rows_from_excel(
                            params["file_bytes"],
                            params.get("file_name") or "data.xlsx",
                        )
                    elif params.get("file_path"):
                        _fp2 = Path(params["file_path"])
                        if _fp2.exists():
                            _early_rows = load_rows_from_excel(_fp2.read_bytes(), _fp2.name)

                    if _early_rows:
                        _sel_raw = (params.get("selected_states") or "").strip()
                        _sel_codes = (
                            {s.strip().upper() for s in _sel_raw.split(",") if s.strip()}
                            if _sel_raw else None
                        )
                        _scol = _fsc(_early_rows)
                        if _scol:
                            _counts: Dict[str, int] = {}
                            for _r in _early_rows:
                                _code = _nst(_r.get(_scol))
                                if not _code:
                                    continue
                                if _sel_codes and _code not in _sel_codes:
                                    continue
                                _counts[_code] = _counts.get(_code, 0) + 1
                            if _counts:
                                state_distribution = _counts
                except Exception as _e:
                    logger.warning(f"State-aware proxy pre-pass failed: {_e}")

            try:
                if state_distribution:
                    # Generate per-state proxies in the same proportion as
                    # leads. Each state pool is over-sampled 3× for retries.
                    proxy_lines = []
                    _per_state_summary = []
                    for _st, _lc in sorted(
                        state_distribution.items(), key=lambda x: -x[1]
                    ):
                        _per = min(max(int(_lc) * 3, 5), 10000)
                        try:
                            _sp = await _pj.generate_unique_proxies(
                                db, user["id"],
                                count=_per,
                                country=params.get("proxyjet_country", "US"),
                                state=_st,
                                job_id=job_id,
                            )
                            proxy_lines.extend(_sp)
                            _per_state_summary.append(f"{_st}={len(_sp)}")
                        except Exception as _e:
                            logger.warning(f"ProxyJet gen failed for state {_st}: {_e}")
                    if not proxy_lines:
                        return await _mark_failed(
                            "ProxyJet returned zero proxies for any of your lead-states. "
                            "Check credentials or selected-state list."
                        )
                    _summ_short = ", ".join(_per_state_summary[:6])
                    if len(_per_state_summary) > 6:
                        _summ_short += f", +{len(_per_state_summary) - 6} more"
                    await _set_step(
                        f"✓ Generated {len(proxy_lines)} state-matched ProxyJet proxies "
                        f"({len(state_distribution)} states: {_summ_short})"
                    )
                else:
                    proxy_lines = await _pj.generate_unique_proxies(
                        db,
                        user["id"],
                        count=gen_count,
                        country=params.get("proxyjet_country", "US"),
                        state=params.get("proxyjet_state") or None,
                        countries_pool=params.get("proxyjet_countries") or None,
                        states_pool=params.get("proxyjet_states") or None,
                        job_id=job_id,
                    )
                    if not proxy_lines:
                        return await _mark_failed("ProxyJet returned zero proxies — check credentials.")
                    # ── 2026-06-11: Shuffle when MIX mode is on ────
                    _mix_on = (
                        len(params.get("proxyjet_countries") or []) >= 2
                        or len(params.get("proxyjet_states") or []) >= 2
                    )
                    if _mix_on:
                        import random as _r
                        _r.shuffle(proxy_lines)
                    _pj_st = params.get("proxyjet_state")
                    _pj_cs = params.get("proxyjet_countries") or []
                    _pj_ss = params.get("proxyjet_states") or []
                    _label = (
                        f"mix[{','.join(_pj_cs)}]"
                        if len(_pj_cs) >= 2
                        else params.get('proxyjet_country', 'US')
                    )
                    _state_label = (
                        f"-mix[{','.join(_pj_ss)}]"
                        if len(_pj_ss) >= 2
                        else (('-' + _pj_st) if _pj_st else '')
                    )
                    await _set_step(
                        f"✓ Generated {len(proxy_lines)} unique ProxyJet proxies "
                        f"(auto-mode · {_label}{_state_label})"
                    )
            except RuntimeError as e:
                return await _mark_failed(str(e))
        elif upload_proxy_id or upload_proxy_ids_raw:
            # ── 2026-06-11: Multi-batch uploaded proxies ────────────
            # Mirror the UA multi-batch flow: gather + dedupe + shuffle.
            proxy_batch_ids: List[str] = []
            if upload_proxy_ids_raw:
                proxy_batch_ids = [b.strip() for b in upload_proxy_ids_raw.split(",") if b.strip()]
            elif upload_proxy_id:
                proxy_batch_ids = [upload_proxy_id]
            if len(proxy_batch_ids) == 1:
                # Legacy single-batch path (preserves all live-remove +
                # gsheet-write semantics that depend on a single
                # `upload_proxy_id` reference in the engine).
                uploaded_proxy_lines = await _load_upload_items(user["id"], proxy_batch_ids[0], "proxies")
                if not uploaded_proxy_lines:
                    return await _mark_failed("Selected proxy upload is empty or not found")
                proxy_lines = uploaded_proxy_lines
                consume_upload_ids.append(proxy_batch_ids[0])
                upload_proxy_id = proxy_batch_ids[0]   # back-fill for downstream
            else:
                # 2+ batches → merge + dedupe + shuffle
                batch_results = await asyncio.gather(
                    *[_load_upload_items(user["id"], bid, "proxies") for bid in proxy_batch_ids],
                    return_exceptions=True,
                )
                merged_proxy_lines: List[str] = []
                seen_px: set = set()
                for bid, batch_items in zip(proxy_batch_ids, batch_results):
                    if isinstance(batch_items, Exception) or not batch_items:
                        continue
                    for px_line in batch_items:
                        if px_line and px_line not in seen_px:
                            seen_px.add(px_line)
                            merged_proxy_lines.append(px_line)
                    consume_upload_ids.append(bid)
                if not merged_proxy_lines:
                    return await _mark_failed("Selected proxy upload(s) are empty or not found")
                # Random shuffle so the round-robin pick interleaves
                # across batches (no batch-1-first / batch-2-second
                # grouping in the run order — same fix we applied to
                # multi-batch UAs).
                import random as _r
                _r.shuffle(merged_proxy_lines)
                proxy_lines = merged_proxy_lines
                # NOTE: For multi-batch, live-remove + gsheet-row-delete
                # cannot target one specific batch deterministically
                # (since a duplicate proxy line could exist in multiple
                # batches). We pass `upload_proxy_id=None` to the
                # engine so the live-remove hook is a no-op for these
                # jobs — the user's batches remain intact after the
                # run. They can manually clean up via "Uploaded Things".
                upload_proxy_id = None
        elif use_stored_proxies:
            stored = await db.proxies.find(
                {"user_id": user["id"], "status": {"$in": ["working", "active", None]}},
                {"_id": 0, "proxy_string": 1},
            ).to_list(length=5000)
            proxy_lines = [p["proxy_string"] for p in stored if p.get("proxy_string")]
            if not proxy_lines:
                return await _mark_failed("No stored proxies found. Add some in the Proxies page or paste manually.")
        else:
            proxy_lines = paste_proxy_lines
            if not proxy_lines:
                return await _mark_failed("At least one proxy required")
        if use_proxyjet_auto and not proxyjet_legacy_pregen:
            # On-demand mode: proxies fetched per-visit; nothing to log here.
            pass
        else:
            await _set_step(f"✓ Loaded {len(proxy_lines)} proxies")

        # ── 2. User agents (multi-batch) ─────────────────────────────
        await _set_step("Loading user-agents…")
        upload_ua_id = params.get("upload_ua_id")
        upload_ua_ids_raw = params.get("upload_ua_ids")
        paste_ua_lines = params.get("paste_ua_lines") or []
        ua_batch_ids: List[str] = []
        if upload_ua_ids_raw:
            ua_batch_ids = [b.strip() for b in upload_ua_ids_raw.split(",") if b.strip()]
        elif upload_ua_id:
            ua_batch_ids = [upload_ua_id]
        ua_to_batch_map: Dict[str, str] = {}
        if ua_batch_ids:
            batch_results = await asyncio.gather(
                *[_load_upload_items(user["id"], bid, "user_agents") for bid in ua_batch_ids],
                return_exceptions=True,
            )
            merged_ua_lines: List[str] = []
            for bid, batch_items in zip(ua_batch_ids, batch_results):
                if isinstance(batch_items, Exception) or not batch_items:
                    continue
                for ua_line in batch_items:
                    if ua_line not in ua_to_batch_map:
                        ua_to_batch_map[ua_line] = bid
                        merged_ua_lines.append(ua_line)
                consume_upload_ids.append(bid)
            if not merged_ua_lines:
                return await _mark_failed("Selected user-agent upload(s) are empty or not found")
            # ── 2026-06-11: Shuffle merged multi-batch UA list ───────
            # Without this, batches stay grouped in load-order (batch1
            # UAs first, batch2 UAs second, …). Because the runner's
            # `pick_next_ua` is sequential round-robin, the FIRST N
            # visits would all draw from batch1 (e.g. all Android),
            # then batch2 (all iOS) — defeating the user's intent of a
            # mixed device/platform pool. Shuffling once at load time
            # gives a true random interleave for the entire job while
            # keeping the deterministic round-robin pick (so we still
            # don't repeat a UA until the whole pool is exhausted).
            import random as _r
            _r.shuffle(merged_ua_lines)
            ua_lines = merged_ua_lines
        else:
            ua_lines = paste_ua_lines
            if not ua_lines:
                return await _mark_failed("At least one User Agent required")
        await _set_step(f"✓ Loaded {len(ua_lines)} user-agents")

        # ── 3. Form-fill data rows ────────────────────────────────────
        rows: Optional[List[Dict[str, Any]]] = None
        form_fill_enabled = bool(params.get("form_fill_enabled"))
        if form_fill_enabled:
            await _set_step("Loading form-fill rows…")
            data_source = params.get("data_source", "excel")
            import_pending_from_job_id = params.get("import_pending_from_job_id")
            file_bytes = params.get("file_bytes")
            file_name = params.get("file_name")
            upload_data_file_id = params.get("upload_data_file_id")
            gsheet_url = params.get("gsheet_url")

            if data_source == "pending_from_job" or (import_pending_from_job_id and not file_bytes and data_source != "gsheet"):
                if not import_pending_from_job_id:
                    return await _mark_failed("import_pending_from_job_id required for data_source=pending_from_job")
                src_job = await db.real_user_traffic_jobs.find_one(
                    {"job_id": import_pending_from_job_id, "user_id": user["id"]}, {"_id": 0}
                )
                if not src_job:
                    return await _mark_failed("Source job not found")
                from real_user_traffic import RESULTS_ROOT
                pending_path = Path(src_job.get("pending_leads_path") or (RESULTS_ROOT / import_pending_from_job_id / "pending_leads.xlsx"))
                if not pending_path.exists():
                    return await _mark_failed("Previous job's pending_leads.xlsx not found (it may have been deleted or that job had no leads)")
                try:
                    with open(pending_path, "rb") as fp:
                        content = fp.read()
                    rows = load_rows_from_excel(content, pending_path.name)
                except Exception as e:
                    return await _mark_failed(f"Pending leads file parse failed: {e}")
            elif data_source == "gsheet":
                if not gsheet_url:
                    return await _mark_failed("gsheet_url required when form fill is enabled")
                try:
                    rows = await load_rows_from_google_sheet(gsheet_url)
                except Exception as e:
                    return await _mark_failed(f"Google Sheet load failed: {e}")
            else:
                if upload_data_file_id:
                    pair = await _load_upload_data_file(user["id"], upload_data_file_id)
                    if not pair:
                        # ── 2026-06-25 — Verbose diagnostic for the
                        # "Selected data-file upload not found" report.
                        # Inspect the per-user DB directly so the user
                        # gets an actionable message (doc missing vs
                        # file vanished from disk vs depleted) instead
                        # of a one-line dead end.
                        _diag_detail = "unknown"
                        try:
                            _user_db = get_user_db(user["id"])
                            _doc_check = await _user_db["uploaded_resources"].find_one(
                                {"id": upload_data_file_id},
                                {"_id": 0, "items": 0},
                            )
                            if not _doc_check:
                                _diag_detail = "DB doc missing (re-upload required)"
                            else:
                                _dtype = _doc_check.get("type")
                                _file_path = _doc_check.get("file_path")
                                _remaining_fp = _doc_check.get("remaining_file_path")
                                _depleted = bool(_doc_check.get("depleted"))
                                _user_id_field = _doc_check.get("user_id", "?")
                                _exists_file = bool(_file_path) and Path(_file_path).exists() if _file_path else False
                                _exists_rem = bool(_remaining_fp) and Path(_remaining_fp).exists() if _remaining_fp else False
                                _diag_detail = (
                                    f"type='{_dtype}' depleted={_depleted} "
                                    f"file_path_exists={_exists_file} "
                                    f"remaining_exists={_exists_rem} "
                                    f"doc.user_id={_user_id_field}"
                                )
                                if _depleted:
                                    _diag_detail = (
                                        "Upload is marked DEPLETED — all rows already "
                                        "consumed by previous jobs. Re-upload to re-use."
                                    )
                                elif not _exists_file and not _exists_rem:
                                    _diag_detail = (
                                        "File missing on disk (deployment volume / "
                                        "file_path issue). Please re-upload the data file."
                                    )
                        except Exception as _ex:
                            _diag_detail = f"diag-error: {_ex}"
                        logger.warning(
                            f"data-file upload not loadable for job {job_id}: "
                            f"id={upload_data_file_id} user={user['id'][:8]} :: {_diag_detail}"
                        )
                        return await _mark_failed(
                            f"Selected data-file upload not found · {_diag_detail}"
                        )
                    fp, orig_name = pair
                    try:
                        with open(fp, "rb") as fh:
                            content = fh.read()
                        rows = load_rows_from_excel(content, orig_name)
                    except Exception as e:
                        return await _mark_failed(f"Saved data file parse failed: {e}")
                    consume_upload_ids.append(upload_data_file_id)
                else:
                    # On resume after backend restart, file_bytes is gone but
                    # we persist the original upload to disk in step 5a of the
                    # /jobs endpoint. Try loading from that path before giving up.
                    if not file_bytes:
                        _disk_path = params.get("file_path")
                        if _disk_path:
                            try:
                                with open(_disk_path, "rb") as _fh:
                                    file_bytes = _fh.read()
                            except Exception as _e:
                                logger.warning(f"Failed to reload persisted form-fill file from {_disk_path}: {_e}")
                    if not file_bytes:
                        return await _mark_failed("Excel/CSV file required when form fill is enabled")
                    try:
                        rows = load_rows_from_excel(file_bytes, file_name or "data.xlsx")
                    except Exception as e:
                        return await _mark_failed(f"File parse failed: {e}")
            if not rows:
                return await _mark_failed("No rows in uploaded file")
            await _set_step(f"✓ Loaded {len(rows)} form-fill rows")

            # ── State filter (user-selected subset) ────────────────────
            # When the user picks specific states on the RUT page, only
            # rows whose state column matches those codes are kept. Empty
            # → no filter (use all rows). Saves bandwidth + ensures only
            # matching-state leads flow through.
            sel_states_raw = (params.get("selected_states") or "").strip()
            if sel_states_raw:
                try:
                    from real_user_traffic import _find_state_column, _normalize_state
                    sel_codes = {
                        s.strip().upper() for s in sel_states_raw.split(",") if s.strip()
                    }
                    if sel_codes:
                        scol = _find_state_column(rows)
                        if scol:
                            before = len(rows)
                            rows = [
                                r for r in rows
                                if _normalize_state(r.get(scol)) in sel_codes
                            ]
                            await _set_step(
                                f"✓ State filter applied: kept {len(rows)} / {before} rows "
                                f"(states: {', '.join(sorted(sel_codes))})"
                            )
                            if not rows:
                                return await _mark_failed(
                                    "State filter removed all rows — no leads in selected states"
                                )
                        else:
                            await _set_step("⚠ State filter ignored: no state column in data file")
                except Exception as e:
                    logger.warning(f"State filter failed (continuing without): {e}")

            # ── 2026-06 — Email-domain subset filter ─────────────────
            # When set, keep only rows whose email is at one of the
            # selected domains (e.g. "gmail.com,yahoo.com"). Same
            # semantics as `selected_states`. Empty → no filter.
            sel_emails_raw = (params.get("selected_email_domains") or "").strip()
            if sel_emails_raw and rows:
                try:
                    from real_user_traffic import _find_email_column, _extract_email_domain
                    sel_domains = {
                        d.strip().lower() for d in sel_emails_raw.split(",") if d.strip()
                    }
                    if sel_domains:
                        ecol = _find_email_column(rows)
                        if ecol:
                            before = len(rows)
                            rows = [
                                r for r in rows
                                if _extract_email_domain(r.get(ecol)) in sel_domains
                            ]
                            await _set_step(
                                f"✓ Email-domain filter applied: kept {len(rows)} / {before} rows "
                                f"(domains: {', '.join(sorted(sel_domains))})"
                            )
                            if not rows:
                                return await _mark_failed(
                                    "Email-domain filter removed all rows — no leads at selected domains"
                                )
                        else:
                            await _set_step("⚠ Email-domain filter ignored: no email column in data file")
                except Exception as e:
                    logger.warning(f"Email-domain filter failed (continuing without): {e}")

        # ── 4. Duplicate-IP blocklist (await the parallel fetch from step 0) ─
        dup_ip_set = None
        if params.get("skip_duplicate_ip"):
            await _set_step("Loading duplicate-IP blocklist…")
            try:
                dup_ip_set = await dup_ip_task if dup_ip_task else await _get_dup_ip_set_safe(user_id=(user.get("parent_user_id") or user["id"]))
            except Exception as e:
                logger.warning(f"dup-IP fetch failed (continuing without): {e}")
                dup_ip_set = None
            await _set_step(f"✓ Loaded blocklist ({len(dup_ip_set or [])} IPs)")

        # ── 5. Filters ────────────────────────────────────────────────
        allowed_countries_lc = [c.strip().lower() for c in (params.get("allowed_countries") or "").split(",") if c.strip()]
        allowed_os_list = [o.strip().lower() for o in (params.get("allowed_os") or "").split(",") if o.strip()]

        # ── 6. Automation JSON ────────────────────────────────────────
        automation_steps = None
        automation_source_text = params.get("automation_json")
        upload_automation_json_id = params.get("upload_automation_json_id")
        if (not automation_source_text or not automation_source_text.strip()) and upload_automation_json_id:
            automation_source_text = await _load_upload_automation_json(user["id"], upload_automation_json_id)
            if not automation_source_text:
                return await _mark_failed("Selected automation-JSON template not found")
        if automation_source_text and automation_source_text.strip():
            try:
                import json as _json
                parsed = _json.loads(automation_source_text)
                if isinstance(parsed, list):
                    automation_steps = parsed
                elif isinstance(parsed, dict) and isinstance(parsed.get("steps"), list):
                    automation_steps = parsed["steps"]
                else:
                    return await _mark_failed('automation_json must be a list of steps or {"steps":[...]}')
                if not automation_steps:
                    return await _mark_failed("automation_json has no steps")
            except Exception as e:
                return await _mark_failed(f"Invalid automation_json: {e}")

        # ── 7. Target screenshot pHash ────────────────────────────────
        target_screenshot_phash: Optional[str] = None
        target_screenshot_path: Optional[str] = None
        target_screenshot_upload_id = params.get("target_screenshot_upload_id")
        target_screenshot_bytes = params.get("target_screenshot_bytes")
        target_screenshot_threshold = max(0, min(30, int(params.get("target_screenshot_threshold") or 12)))

        if target_screenshot_upload_id:
            pair = await _load_upload_target_screenshot(user["id"], target_screenshot_upload_id)
            if not pair:
                return await _mark_failed("Selected target-screenshot upload not found")
            src_path, target_screenshot_phash = pair
            try:
                from pathlib import Path as _P
                job_dir = _P("real_user_traffic_results") / "_pending"
                job_dir.mkdir(parents=True, exist_ok=True)
                target_screenshot_path = str(job_dir / f"target_{uuid.uuid4().hex}.png")
                import shutil as _sh
                _sh.copyfile(src_path, target_screenshot_path)
            except Exception as e:
                logger.warning(f"target_screenshot copy from upload failed: {e}")
                target_screenshot_phash = None
                target_screenshot_path = None
        elif target_screenshot_bytes and len(target_screenshot_bytes) >= 200:
            try:
                from screenshot_verifier import compute_phash
                target_screenshot_phash = compute_phash(target_screenshot_bytes)
                if target_screenshot_phash:
                    job_dir = Path("real_user_traffic_results") / "_pending"
                    job_dir.mkdir(parents=True, exist_ok=True)
                    target_screenshot_path = str(job_dir / f"target_{uuid.uuid4().hex}.png")
                    with open(target_screenshot_path, "wb") as f:
                        f.write(target_screenshot_bytes)
            except Exception as e:
                logger.warning(f"target_screenshot processing failed: {e}")
        else:
            # On resume after backend restart, target_screenshot_bytes is None
            # but the original upload was persisted in step 5a of the /jobs
            # endpoint. Reload it from disk so the conversion check still works.
            _ts_disk_path = params.get("target_screenshot_path")
            if _ts_disk_path and Path(_ts_disk_path).exists():
                try:
                    with open(_ts_disk_path, "rb") as _fh:
                        _ts_bytes = _fh.read()
                    from screenshot_verifier import compute_phash
                    target_screenshot_phash = compute_phash(_ts_bytes)
                    if target_screenshot_phash:
                        job_dir = Path("real_user_traffic_results") / "_pending"
                        job_dir.mkdir(parents=True, exist_ok=True)
                        target_screenshot_path = str(job_dir / f"target_{uuid.uuid4().hex}.png")
                        with open(target_screenshot_path, "wb") as f:
                            f.write(_ts_bytes)
                except Exception as e:
                    logger.warning(f"target_screenshot resume from {_ts_disk_path} failed: {e}")

        # Move target screenshot from _pending into per-job folder
        if target_screenshot_path:
            try:
                new_dir = Path("real_user_traffic_results") / job_id
                new_dir.mkdir(parents=True, exist_ok=True)
                new_path = new_dir / "target_screenshot.png"
                Path(target_screenshot_path).rename(new_path)
                target_screenshot_path = str(new_path)
            except Exception as e:
                logger.debug(f"target screenshot move failed: {e}")

        # ── 8. Update DB record with loaded params + mark running ────
        post_submit_wait = max(3, min(600, int(params.get("post_submit_wait") or 6)))
        await db.real_user_traffic_jobs.update_one(
            {"job_id": job_id},
            {"$set": {
                "consume_upload_ids": consume_upload_ids,
                "target_screenshot_phash": target_screenshot_phash or "",
                "target_screenshot_path": target_screenshot_path or "",
                "target_screenshot_threshold": target_screenshot_threshold,
                "proxies_count": len(proxy_lines),
                "user_agents_count": len(ua_lines),
                "rows_loaded": len(rows) if rows else 0,
                "custom_automation": bool(automation_steps),
                "preparing": False,
                "prep_finished_at": datetime.now(timezone.utc).isoformat(),
                # ── PREP-SUCCESS rc-RESET ─────────────────────────────
                # Whenever prep finishes cleanly we treat this run as
                # "healthy" and give it a fresh auto-resume budget. This
                # is the antidote to the user's 10-attempt-cap pain:
                # if a job dies AFTER making it past prep (ie during
                # actual visits), the *next* restart's reaper sees rc=0
                # and resumes again. Only true unrecoverable crash
                # loops — where prep itself blows up before ever
                # finishing — accumulate rc and eventually give up.
                "restart_count": 0,
            }},
        )

        # ── 9. Dispatch the actual runner ────────────────────────────
        await _set_step("Launching browser engine…")
        await run_real_user_traffic_job(
            job_id=job_id,
            target_url=target,
            proxies_raw=proxy_lines,
            user_agents=ua_lines,
            total_clicks=int(params.get("total_clicks") or 10),
            concurrency=int(params.get("concurrency") or 3),
            duration_minutes=float(params.get("duration_minutes") or 0),
            allowed_os=allowed_os_list,
            allowed_countries_lc=allowed_countries_lc,
            skip_duplicate_ip=bool(params.get("skip_duplicate_ip")),
            skip_vpn=bool(params.get("skip_vpn")),
            follow_redirect=bool(params.get("follow_redirect")),
            no_repeated_proxy=bool(params.get("no_repeated_proxy")),
            form_fill_enabled=form_fill_enabled,
            rows=rows,
            skip_captcha=bool(params.get("skip_captcha")),
            duplicate_ip_set=dup_ip_set,
            post_submit_wait=post_submit_wait,
            automation_steps=automation_steps,
            self_heal=bool(params.get("self_heal")),
            pure_json_mode=bool(params.get("pure_json_mode")),
            state_match_enabled=bool(params.get("state_match_enabled")),
            target_mode=params.get("target_mode") or "clicks",
            target_conversions=int(params.get("target_conversions") or 0),
            max_attempts=int(params.get("max_attempts") or 0),
            invalid_detection_enabled=bool(params.get("invalid_detection_enabled")),
            invalid_data_retry_limit=int(params.get("invalid_data_retry_limit") or 10),
            step_timeout_multiplier=float(params.get("step_timeout_multiplier") or 1.0),
            db=db,
            link_id=link.get("id") if link else None,
            link_owner_id=(link or {}).get("user_id") or user["id"],
            link_short_code=(link or {}).get("short_code"),
            engine_user_id=user["id"],
            upload_proxy_id=(upload_proxy_id or None),
            upload_ua_id=(ua_batch_ids[0] if len(ua_batch_ids) == 1 else None),
            upload_ua_ids=(ua_batch_ids if len(ua_batch_ids) > 1 else None),
            ua_to_batch_map=(ua_to_batch_map or None),
            upload_data_file_id=(params.get("upload_data_file_id") or None),
            target_screenshot_phash=target_screenshot_phash or "",
            target_screenshot_threshold=target_screenshot_threshold,
            # 2026-01 ROW-FIRST on-demand ProxyJet mode (skipped when the
            # caller explicitly requested the legacy pre-gen flow)
            proxyjet_on_demand=bool(use_proxyjet_auto and not proxyjet_legacy_pregen),
            proxyjet_country=params.get("proxyjet_country", "US"),
            proxyjet_default_state=(params.get("proxyjet_state") or None),
            # ── 2026-06-11: ProxyJet Multi-Geo MIX pools ────────────
            proxyjet_countries_pool=list(params.get("proxyjet_countries") or []),
            proxyjet_states_pool=list(params.get("proxyjet_states") or []),
            proxyjet_unique_retry_cap=int(params.get("proxyjet_unique_retry_cap") or 50),
            # 2026-01 — per-job watchdog inactivity threshold (seconds).
            # Default raised 60 → 240 (2026-05) → 600 (2026-06-27, user request).
            # UI exposes a number input so operators can tune per offer.
            stuck_watchdog_seconds=float(params.get("stuck_watchdog_seconds") or 600.0),
            # 2026-02 v2.1.31 — Anti-Detect wiring (Phase 1)
            pacing_per_hour=int(params.get("pacing_per_hour") or 0),
            identity_label=str(params.get("identity_label") or "").strip(),
            tls_prewarm=bool(params.get("tls_prewarm")),
            # 2026-02 v2.1.31 — Step 3 wiring
            proxy_chain_enabled=bool(params.get("proxy_chain_enabled")),
            proxy_chain_use_tor=bool(params.get("proxy_chain_use_tor", True)),
            proxy_chain_extra_hops=list(params.get("proxy_chain_extra_hops") or []),
            browser_variant=str(params.get("browser_variant") or "auto").strip().lower(),
            # 2026-02 v2.1.31 — Step 4 wiring
            behavioral_bio_enabled=bool(params.get("behavioral_bio_enabled")),
            ip_warmup_enabled=bool(params.get("ip_warmup_enabled")),
            # 2026-06 — Referrer override wiring
            referer_override_enabled=bool(params.get("referer_override_enabled")),
            referer_mode=str(params.get("referer_mode") or "auto"),
            referer_value=str(params.get("referer_value") or ""),
            referer_platform_pool=str(params.get("referer_platform_pool") or ""),
            referer_brand=str(params.get("referer_brand") or ""),
            # 2026-06-11 — Referrer Pro-Mode wiring (weighted pools,
            # geo search, social wrappers, in-app deep paths, etc.)
            referer_pro_mode=bool(params.get("referer_pro_mode")),
            referer_platform_weights=str(params.get("referer_platform_weights") or ""),
            referer_email_weights=str(params.get("referer_email_weights") or ""),
            referer_social_wrapper=bool(params.get("referer_social_wrapper", True)),
            referer_inapp_deep=bool(params.get("referer_inapp_deep", True)),
            referer_search_engine=str(params.get("referer_search_engine") or "google"),
            referer_search_keywords=str(params.get("referer_search_keywords") or ""),
            referer_strip_search_path=bool(params.get("referer_strip_search_path", True)),
            referer_network_click_chain=bool(params.get("referer_network_click_chain", False)),
            # 2026-01 — Pass-Referer-To-Offer (server-side tracker
            # resolve + direct offer navigation, see RUT engine
            # for behaviour). Default OFF preserves legacy path.
            referer_pass_to_offer=bool(params.get("referer_pass_to_offer", False)),
            # 2026-06-14 — UA ↔ Referer coercion (default True for new
            # jobs; legacy jobs that never set the key also get the
            # safer/realer default via `.get(..., True)`).
            referer_match_ua_to_platform=bool(params.get("referer_match_ua_to_platform", True)),
        )
    except Exception as e:  # noqa: BLE001
        logger.exception(f"_rut_prepare_and_run crashed for job {job_id}: {e}")
        await _mark_failed(f"Prep/run crashed: {e}")


# ── Data-file preview (auto-detect states, columns, quality) ─────────
# Used by Real User Traffic page: when user uploads a data file, the
# frontend calls this endpoint to get a per-state row count + column
# list so a "State filter" UI can be shown. The user picks which states
# to run on; the chosen list is then passed to job creation via the
# `selected_states` form field. Read-only — no DB write, no side effect.
@api_router.post("/real-user-traffic/preview-data-file")
async def rut_preview_data_file(
    file: Optional[UploadFile] = File(None),
    upload_data_file_id: Optional[str] = Form(None),
    gsheet_url: Optional[str] = Form(None),
    user: dict = Depends(get_current_user),
):
    from real_user_traffic import _find_state_column, _normalize_state, _find_email_column, _extract_email_domain
    rows: List[Dict[str, Any]] = []
    src = ""
    try:
        if upload_data_file_id:
            # 2026-02 — uploaded resources live in the PER-USER database
            # under `uploaded_resources` (NOT the global `db.uploads`).
            # Querying the wrong DB caused the user-reported error:
            #   "Could not analyze data file: Uploaded data file not found"
            # even though the batch was clearly visible in /uploaded-items.
            user_db_inst = get_db_for_user(user)
            doc = await user_db_inst["uploaded_resources"].find_one(
                {"id": upload_data_file_id, "type": "data_file"},
                {"_id": 0}
            )
            if not doc:
                raise HTTPException(status_code=404, detail="Uploaded data file not found")
            # 2026-06 — Prefer remaining_file_path (rows still unused);
            # fall back to file_path (original master). This way the
            # preview reflects what an actual job would consume.
            remaining_fp = (doc.get("remaining_file_path") or "").strip()
            file_path = (
                remaining_fp
                if (remaining_fp and Path(remaining_fp).exists())
                else doc.get("file_path")
            )
            if not file_path or not Path(file_path).exists():
                raise HTTPException(status_code=404, detail="Uploaded data file no longer on disk")
            content = Path(file_path).read_bytes()
            rows = load_rows_from_excel(content, doc.get("filename", "data.xlsx"))
            src = doc.get("filename") or "uploaded batch"
        elif gsheet_url:
            rows = await load_rows_from_google_sheet(gsheet_url)
            src = "google sheet"
        elif file:
            content = await file.read()
            rows = load_rows_from_excel(content, file.filename or "data.xlsx")
            src = file.filename or "uploaded file"
        else:
            raise HTTPException(status_code=400, detail="Provide a file, upload_data_file_id, or gsheet_url")
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Could not parse data file: {e}")

    if not rows:
        return {
            "source": src, "total_rows": 0, "columns": [],
            "state_column": None, "states": [], "quality": {},
        }

    # Detect columns (preserve original order)
    columns: List[str] = []
    for r in rows[:50]:
        for k in r.keys():
            if k not in columns:
                columns.append(k)

    # Detect state column + per-state row counts
    state_col = _find_state_column(rows)
    state_counts: Dict[str, int] = {}
    unknown_state_rows = 0
    if state_col:
        for r in rows:
            code = _normalize_state(r.get(state_col))
            if code:
                state_counts[code] = state_counts.get(code, 0) + 1
            else:
                unknown_state_rows += 1

    # ── 2026-06 — Per-email-domain row counts (mirrors state filter) ──
    # Lets the operator subset uploaded leads by gmail / yahoo / hotmail
    # etc. on the RUT page. Returned alongside `states` so the frontend
    # can render an identical pill picker.
    email_col = _find_email_column(rows)
    email_domain_counts: Dict[str, int] = {}
    unknown_email_rows = 0
    if email_col:
        for r in rows:
            dom = _extract_email_domain(r.get(email_col))
            if dom:
                email_domain_counts[dom] = email_domain_counts.get(dom, 0) + 1
            else:
                unknown_email_rows += 1

    # Quality stats — count empty values for common required fields
    def _empty_count(keys: List[str]) -> int:
        n = 0
        for r in rows:
            v = None
            for k in keys:
                if k in r and str(r[k]).strip():
                    v = r[k]
                    break
            if v is None or str(v).strip() == "":
                n += 1
        return n

    quality = {
        "empty_first_name": _empty_count(["first", "fname", "firstname", "first_name", "FirstName"]),
        "empty_last_name": _empty_count(["last", "lname", "lastname", "last_name", "LastName"]),
        "empty_email": _empty_count(["email", "Email", "e_mail", "e-mail"]),
        "empty_phone": _empty_count(["phone", "cellphone", "phone1", "mobile", "cell", "PhoneNumber"]),
        "empty_zip": _empty_count(["zip", "zipcode", "postal", "postal_code", "Zip"]),
        "empty_gender": _empty_count(["gender", "Gender", "sex"]),
        "empty_dob": _empty_count(["day", "Day", "DayOfBirth"]),
    }

    # Sort states by count desc
    states_sorted = [
        {"code": code, "count": cnt}
        for code, cnt in sorted(state_counts.items(), key=lambda x: -x[1])
    ]

    # Sort email domains by count desc (same shape as states)
    email_domains_sorted = [
        {"domain": dom, "count": cnt}
        for dom, cnt in sorted(email_domain_counts.items(), key=lambda x: -x[1])
    ]

    return {
        "source": src,
        "total_rows": len(rows),
        "columns": columns,
        "state_column": state_col,
        "states": states_sorted,
        "unknown_state_rows": unknown_state_rows,
        "email_column": email_col,
        "email_domains": email_domains_sorted,
        "unknown_email_rows": unknown_email_rows,
        "quality": quality,
    }


@api_router.post("/real-user-traffic/jobs")
async def rut_create_job(
    background: BackgroundTasks,
    request: Request,
    link_id: str = Form(...),
    target_url: Optional[str] = Form(None),
    # Traffic source
    proxies: str = Form(""),                          # newline-separated
    user_agents: str = Form(""),                     # newline-separated (optional if upload_ua_id provided)
    use_stored_proxies: bool = Form(False),
    # Run settings
    total_clicks: int = Form(10),
    concurrency: int = Form(3),
    duration_minutes: float = Form(0),
    # Target mode — "clicks" = run N visits; "conversions" = keep running
    # until X conversions OR max_attempts reached (whichever comes first)
    target_mode: str = Form("clicks"),
    target_conversions: int = Form(0),
    max_attempts: int = Form(0),
    # Filters
    allowed_countries: str = Form(""),                # comma-separated country NAMES
    allowed_os: str = Form(""),                       # comma-separated os keys (android,ios,windows,macos,linux)
    skip_duplicate_ip: bool = Form(True),
    skip_vpn: bool = Form(True),
    follow_redirect: bool = Form(False),
    no_repeated_proxy: bool = Form(False),
    # Form filler
    form_fill_enabled: bool = Form(False),
    data_source: str = Form("excel"),                 # "excel" | "gsheet" | "pending_from_job"
    gsheet_url: Optional[str] = Form(None),
    import_pending_from_job_id: Optional[str] = Form(None),
    state_match_enabled: bool = Form(False),
    selected_states: Optional[str] = Form(None),     # CSV of 2-letter state codes
                                                      # (e.g. "FL,CA,TX"). When set,
                                                      # only data rows whose state
                                                      # matches are used; others are
                                                      # filtered OUT before the job runs.
    # ── 2026-06 — Email-domain subset filter ───────────────────────────
    # CSV of lowercase email domains (e.g. "gmail.com,yahoo.com"). When
    # set, only rows whose email column belongs to one of those domains
    # are kept. Mirrors `selected_states` semantics.
    selected_email_domains: Optional[str] = Form(None),
    invalid_detection_enabled: bool = Form(False),    # OFF by default — landing
                                                      # pages with consent banners
                                                      # trigger false positives
    # 2026-06 — Max retries when invalid_detection_enabled flags a lead.
    # Used to be a hard-coded 3 inside the engine; now configurable so
    # operators with dirty data can ask the engine to absorb a longer
    # tail of bad rows without losing the visit/proxy/UA. 1..50 range.
    invalid_data_retry_limit: int = Form(10),
    # 2026-06 — Per-step timeout multiplier for slow offers / proxies.
    # Stretches every entry in `_STEP_TIMEOUT_CEILINGS_MS` so a slow
    # visit's current step finishes before the engine moves on.
    # 1.0 = no change (default). 0.5..5.0 (clamped server-side).
    step_timeout_multiplier: float = Form(1.0),
    # 2026-06-25 — Per-job stuck-watchdog inactivity threshold (seconds).
    # Default 600s (raised from 240s on 2026-06-25 per operator feedback —
    # survey-heavy deal flows routinely take 5-10 min legitimately and
    # the lower default was killing healthy long visits). Clamped 30..1800
    # server-side; users can still lower this from the UI for fast flows.
    stuck_watchdog_seconds: float = Form(600.0),
    skip_captcha: bool = Form(True),
    post_submit_wait: int = Form(6),                  # seconds 3..600
    automation_json: Optional[str] = Form(None),      # custom step-list JSON
    self_heal: bool = Form(True),                     # AI fallback for unexpected popups
    # ── 2026-05: Pure JSON Mode ──
    # When True, the runner strictly follows the recorded automation JSON
    # with NO AI involvement — self_heal is forced OFF and AI answer-
    # learning (Thompson sampling for survey picks) is bypassed. Default
    # OFF preserves current behaviour exactly.
    pure_json_mode: bool = Form(False),
    # Auto-resume opt-IN (default OFF per 2026-01 user feedback). When
    # False, a backend restart marks the job `failed` and the user
    # clicks "Retry" manually — predictable, no surprise resumes mid-run.
    # When True, the reaper re-spawns the prep + run with rc-counter
    # safety net (up to 100 attempts, exp backoff).
    auto_resume_enabled: bool = Form(True),
    file: Optional[UploadFile] = File(None),
    # 2026-06-25 — Bridge-replay base64 file payload. When the cloud
    # bridges a heavy job to a customer's desktop, the bridge replay
    # path is urlencoded (bytes-stripped multipart), so an
    # `upload_data_file_id` reference would 404 on the desktop's empty
    # local `uploaded_resources`. The cloud edge reads the cloud-side
    # file bytes and inlines them as base64 here. When set, this takes
    # precedence over `upload_data_file_id` (which is dropped by the
    # edge inline-pass) and is decoded back to `file_bytes` before the
    # BG task runs. Both fields are OPTIONAL and have no effect on
    # direct (non-bridged) job submissions.
    data_file_b64: Optional[str] = Form(None),
    data_file_b64_name: Optional[str] = Form(None),
    # Target Screenshot Verification — user-uploaded reference image of the
    # expected final/thank-you page. After every visit we screenshot the
    # final page and compare via perceptual hash. Distance ≤ threshold ⇒
    # verified TRUE conversion (not just heuristic host-change).
    target_screenshot: Optional[UploadFile] = File(None),
    target_screenshot_threshold: int = Form(12),  # 0..30 — Hamming distance
    # Pre-uploaded target screenshot — preferred path. Pass this instead
    # of the multipart `target_screenshot` file to keep the job-create
    # POST tiny (avoids Cloudflare tunnel 100s timeout + ingress limits
    # on large images).
    target_screenshot_upload_id: Optional[str] = Form(None),
    # Uploaded Things — optional batch IDs from the "Uploaded Things" page.
    # When provided, items are loaded from those saved batches AND the
    # batch is auto-deleted when the job finishes so it never repeats.
    upload_ua_id: Optional[str] = Form(None),
    upload_ua_ids: Optional[str] = Form(None),        # NEW: comma-separated list for multi-UA jobs
    upload_proxy_id: Optional[str] = Form(None),
    upload_data_file_id: Optional[str] = Form(None),
    # Automation-JSON template — picked from the reusable library; NOT
    # auto-deleted so the same template can be used across many campaigns.
    upload_automation_json_id: Optional[str] = Form(None),
    # Strict tracker-URL flow — when True, every visit MUST go through
    # `/api/t/<short_code>` on this preview pod (no auto-bypass to the
    # offer URL). Use when you want server-side click logging + duplicate
    # IP check to happen at the tracker endpoint itself.
    force_tracker_url: bool = Form(False),
    # ── ProxyJet Auto Mode (one-time creds → unique IP per visit) ──
    # When True, the BG task ignores `proxies`/`upload_proxy_id`/
    # `use_stored_proxies` and instead asks `proxyjet_module` for a
    # fresh batch of unique residential proxies. Session IDs are
    # persisted so the SAME exit-IP is never reused for this user.
    # When False (default), all legacy paths run identically.
    use_proxyjet_auto: bool = Form(False),
    proxyjet_country: str = Form("US"),
    proxyjet_state: str = Form(""),
    # ── 2026-06-11: ProxyJet Multi-Geo MIX mode ─────────────────────
    # CSV of country codes (e.g. "US,CA,GB") OR newline-separated. When
    # 2+ entries, the per-visit ProxyJet call picks a RANDOM country
    # per visit so the campaign's exit-IPs are spread across multiple
    # countries naturally. Same for `proxyjet_states` (US 2-letter
    # codes). When state_match_enabled is ON, per-row state still wins
    # (the data file dictates which state to target). Single-entry /
    # empty values silently fall back to scalar `proxyjet_country` /
    # `proxyjet_state` so legacy single-geo flows are unaffected.
    proxyjet_countries: str = Form(""),
    proxyjet_states: str = Form(""),
    # ── 2026-06-11: Multi-batch uploaded proxies ───────────────────
    # Comma-separated list of proxy batch IDs. When provided, the
    # engine merges all batches, dedupes lines, and SHUFFLES the
    # merged list so the round-robin pick produces a random
    # interleave of every batch (not batch1-first-then-batch2).
    # Mirrors the existing `upload_ua_ids` semantics.
    upload_proxy_ids: Optional[str] = Form(None),
    # ── 2026-05: Pre-flight Smoke Test ──────────────────────────────────
    # When True, the runner is forced to total_clicks=1, concurrency=1
    # and target_mode="clicks" so the user can validate their recording
    # + proxy chain on ONE visit BEFORE committing budget to a 1000-visit
    # full run. The job row carries `smoke_test: True` so the frontend
    # can render the result panel with "All steps OK → Start Full Job"
    # vs "Step #N failed → fix recording".
    smoke_test: bool = Form(False),
    # ── 2026-02 v2.1.31 — Anti-Detect Wiring (Phase 1) ──────────────
    # When > 0, the runner uses PacingEngine (log-normal jitter) for
    # visit spacing instead of the flat duration/total math. Defeats
    # cohort detection that flags evenly-spaced visit patterns.
    pacing_per_hour: int = Form(0),
    # When non-empty, the runner reuses cookies + fingerprint persisted
    # under this label across runs (returning-user pattern).
    identity_label: str = Form(""),
    # When True, every visit pre-fetches the target via curl_cffi (real
    # Chrome JA3) BEFORE Playwright's first navigation, then injects the
    # warmed cookies into the Playwright context. Bypass Cloudflare BM /
    # DataDome / Akamai BM on cold visits.
    tls_prewarm: bool = Form(False),
    # ── 2026-02 v2.1.31 — Step 3: Multi-Hop Proxy Chain ───────────────
    proxy_chain_enabled: bool = Form(False),
    proxy_chain_use_tor: bool = Form(True),
    # 2026-02 Step 5 (Big-14): newline-separated hop URIs inserted into
    # the chain BETWEEN Tor and the exit proxy. Optional.
    proxy_chain_extra_hops: str = Form(""),
    # ── 2026-02 v2.1.31 — Step 3: Browser Binary Rotation ─────────────
    # "auto" | "chromium" | "headless-shell" | "brave" | "rotate"
    browser_variant: str = Form("auto"),
    # ── 2026-02 v2.1.31 — Step 4: Phase-4 Anti-Detect ────────────────
    behavioral_bio_enabled: bool = Form(False),
    ip_warmup_enabled: bool = Form(False),
    # ── 2026-06: User-configurable Referrer Override ─────────────────
    # OFF by default → legacy UA-derived referer behaviour is preserved
    # exactly. When ON, the operator's chosen strategy (auto / custom /
    # random_list / google_search / platform_pool / direct) is applied
    # per visit. See `_resolve_visit_referer` in real_user_traffic.py.
    referer_override_enabled: bool = Form(False),
    referer_mode: str = Form("auto"),
    referer_value: str = Form(""),
    referer_platform_pool: str = Form(""),
    # Brand identifier (optional). When set + email is in the platform
    # pool, the tracker tags email visits with brand-aware UTMs
    # (utm_source=<brand>_newsletter, utm_campaign=<brand>_<base>) so a
    # customer claiming "I am Brand X's marketing" produces consistent
    # brand-labelled signals — without leaking any actual email address.
    referer_brand: str = Form(""),
    # ── 2026-06-11: Referrer Pro-Mode (weighted pools + realism layers)
    referer_pro_mode: bool = Form(False),
    referer_platform_weights: str = Form(""),     # JSON dict: {"facebook":40,"tiktok":30}
    referer_email_weights: str = Form(""),        # JSON dict: {"empty":35,"gmail":20,...}
    referer_social_wrapper: bool = Form(True),    # l.facebook.com / t.co / lnkd.in / …
    referer_inapp_deep: bool = Form(True),        # Mobile in-app deep paths
    referer_search_engine: str = Form("google"),  # google/bing/yahoo/duckduckgo/yandex/youtube
    referer_search_keywords: str = Form(""),      # Newline-separated keyword pool
    referer_strip_search_path: bool = Form(True), # Real Chrome Referrer-Policy
    referer_network_click_chain: bool = Form(False),  # One optional 302 hop
    # ── 2026-01 — Pass-Referer-To-Offer (direct offer navigation) ────
    # OFF (default) → legacy: bot navigates tracker → 302 → offer.
    #                  Offer sees Krexion origin per browser policy.
    # ON  → bot resolves tracker SERVER-SIDE (click is still recorded
    #       w/ proxy exit-IP via X-Forwarded-For), then Chromium
    #       navigates DIRECTLY to the resolved offer URL with the
    #       chosen Referer. Offer sees the EXACT chosen Referer
    #       (TikTok / custom URL / platform pool / etc.).
    referer_pass_to_offer: bool = Form(False),
    # ── 2026-06-14: UA ↔ Referer coercion (anti-fraud) ──────────────
    # Default True — when the chosen referer is an in-app platform
    # (FB/TikTok/IG/Snapchat/Messenger/LinkedIn/Twitter) and the rotating
    # UA is a mobile UA without the matching in-app markers, the engine
    # coerces the UA to carry realistic in-app webview tokens. Desktop
    # UAs are left untouched. Eliminates the "Referer=facebook.com +
    # UA=plain Chrome mobile" mismatch that fraud detectors flag.
    referer_match_ua_to_platform: bool = Form(True),
    user: dict = Depends(get_current_user_with_fresh_data),
    _cloud_gate: bool = Depends(require_local_mode),
):
    """Kick off a real-user-traffic run. Combines real-traffic + optional form-fill.

    FAST endpoint: only quick validation runs in the foreground (~1-2s).
    All heavy preparation (gsheet fetches, big Excel parsing, dup-IP cache
    rebuild, target-screenshot pHash) happens in a background task via
    `_rut_prepare_and_run`. The job DB record is inserted IMMEDIATELY
    with status="queued" + preparing=True so the frontend's recovery
    polling (and the Past-Jobs list) sees the job within ~2s, even when
    the user submitted a 6000-row gsheet over a slow Cloudflare tunnel.
    On any prep failure the BG task flips status="failed" with a
    user-readable error_message, surfaced via the existing job-status poll.
    """
    check_user_feature(user, "real_user_traffic")

    # 1. Link ownership + target URL (fast).
    #    v2.1.17: Cloud is the source of truth for links (per the
    #    v2.1.15 hybrid architecture — links live cloud-side so they
    #    keep redirecting even when the customer's PC is off). When
    #    the link isn't in local Mongo yet, fall back to cloud and
    #    mirror the result locally so future RUT visits avoid the
    #    round-trip.
    link = await db.links.find_one({"id": link_id, "user_id": user["id"]}, {"_id": 0})
    if not link and not IS_CLOUD:
        try:
            from cloud_proxy_module import fetch_link_from_cloud
            auth_header = request.headers.get("Authorization") or ""
            cloud_link = await fetch_link_from_cloud(link_id, auth_header)
            if cloud_link:
                cloud_link["user_id"] = user["id"]
                try:
                    await db.links.update_one(
                        {"id": link_id},
                        {"$set": cloud_link},
                        upsert=True,
                    )
                except Exception:  # noqa: BLE001
                    pass
                link = cloud_link
        except Exception as _e:  # noqa: BLE001
            logger.warning(f"[rut] cloud link fallback failed: {_e}")
    if not link:
        raise HTTPException(status_code=404, detail="Link not found")
    target = _rut_build_target_url(request, link, target_url, force_tracker=force_tracker_url)

    # 2. Numeric validations (fast)
    if total_clicks < 1 or total_clicks > 100000:
        raise HTTPException(status_code=400, detail="total_clicks must be 1..100000")
    if concurrency < 1 or concurrency > 50:
        raise HTTPException(status_code=400, detail="concurrency must be 1..50")
    if duration_minutes < 0 or duration_minutes > 1440:
        raise HTTPException(status_code=400, detail="duration_minutes must be 0..1440")

    target_mode = (target_mode or "clicks").strip().lower()
    if target_mode not in ("clicks", "conversions"):
        raise HTTPException(status_code=400, detail="target_mode must be 'clicks' or 'conversions'")

    # 2026-05 — Smoke-test override. Force everything to a single visit
    # so the user can validate their recording + proxy chain BEFORE
    # committing budget to a full run. We coerce here AFTER the validation
    # block so user-supplied limits (which may be enormous for the real
    # run) are accepted by validation but then narrowed to 1.
    if smoke_test:
        total_clicks = 1
        concurrency = 1
        duration_minutes = 0
        target_mode = "clicks"
        target_conversions = 0
        max_attempts = 0
    if target_mode == "conversions":
        if target_conversions < 1 or target_conversions > 10000:
            raise HTTPException(status_code=400, detail="target_conversions must be 1..10000 when target_mode='conversions'")
        if max_attempts < 0 or max_attempts > 100000:
            raise HTTPException(status_code=400, detail="max_attempts must be 0..100000")
        if max_attempts and max_attempts < target_conversions:
            raise HTTPException(status_code=400, detail="max_attempts must be >= target_conversions")

    # 3. Drain inline-uploaded files into bytes — body is already buffered
    # in memory so this is instant. We CANNOT use the UploadFile objects
    # after this endpoint returns (BackgroundTasks runs after response),
    # so the bytes get passed to the BG task explicitly.
    file_bytes: Optional[bytes] = None
    file_name: Optional[str] = None
    if file is not None:
        try:
            file_bytes = await file.read()
            file_name = file.filename or "data.xlsx"
        except Exception as e:
            raise HTTPException(status_code=400, detail=f"File read failed: {e}")
    # 2026-06-25 — Bridge-replay base64 decode. The cloud edge inlines
    # cloud-side data files into the bridge payload as base64 to bypass
    # the urlencoded body limitation (multipart files get stripped by
    # the bridge body-capture). When `data_file_b64` is present and no
    # direct file was multipart-attached, decode it back to bytes here
    # so the rest of the pipeline (persistence to disk + BG task
    # consumption) is identical to the direct-upload path.
    if file_bytes is None and (data_file_b64 or "").strip():
        try:
            import base64 as _b64_in
            file_bytes = _b64_in.b64decode(data_file_b64.strip())
            file_name = (data_file_b64_name or "data.xlsx").strip() or "data.xlsx"
            # Force data_source=excel since we now have inline bytes — the
            # edge bridge may also have stripped `upload_data_file_id`.
            if not data_source or data_source.strip().lower() == "excel":
                data_source = "excel"
        except Exception as e:  # noqa: BLE001
            raise HTTPException(
                status_code=400,
                detail=f"data_file_b64 decode failed: {e}",
            )
    target_screenshot_bytes: Optional[bytes] = None
    if target_screenshot is not None:
        try:
            target_screenshot_bytes = await target_screenshot.read()
        except Exception as e:
            logger.warning(f"target_screenshot read failed: {e}")

    # 4. Paste-mode parsing (instant; gsheet/upload-batch loads happen in BG)
    paste_proxy_lines = [ln for ln in (proxies or "").splitlines() if ln.strip()]
    paste_ua_lines = [ln for ln in (user_agents or "").splitlines() if ln.strip()]
    # 4b. Fast emptiness validation — when the user hasn't picked an
    # uploaded batch / stored-proxies / gsheet, paste fields are the only
    # source. Validate them upfront so the user sees an immediate 400
    # instead of a misleading "Job started" toast followed by a silent
    # failure in the BG task. Upload existence still runs in BG (one DB
    # query, fast, but not blocking the response).
    if not upload_proxy_id and not use_stored_proxies and not paste_proxy_lines and not use_proxyjet_auto:
        raise HTTPException(status_code=400, detail="At least one proxy required (paste, pick a saved batch, enable Use Stored Proxies, or turn on ProxyJet Auto Mode)")
    if use_proxyjet_auto:
        _pj_creds = await _pj.get_credentials(db, user["id"])
        if not _pj_creds:
            raise HTTPException(status_code=400, detail="ProxyJet Auto Mode is on but credentials are not configured. Save them in Proxies → ProxyJet Auto.")
        # Auto Mode mandates strongest anti-duplicate posture: each
        # generated proxy is used at most once and the engine's own
        # dup-IP filter remains on as a belt-and-suspenders guard.
        no_repeated_proxy = True
        skip_duplicate_ip = True
    if not upload_ua_id and not upload_ua_ids and not paste_ua_lines:
        raise HTTPException(status_code=400, detail="At least one User Agent required (paste or pick a saved batch)")
    if form_fill_enabled and data_source == "excel" and not file and not file_bytes and not upload_data_file_id and not import_pending_from_job_id:
        raise HTTPException(status_code=400, detail="Excel/CSV file required when form fill is enabled (upload a file, pick a saved data-file, or import from a previous job)")
    if form_fill_enabled and data_source == "gsheet" and not (gsheet_url or "").strip():
        raise HTTPException(status_code=400, detail="gsheet_url required when form fill is enabled with data_source='gsheet'")

    # 5. Create job_id + RUT_JOBS in-memory entry + DB record (status=queued)
    job_id = str(uuid.uuid4())
    create_rut_job(
        job_id=job_id,
        user_id=user["id"],
        target_url=target,
        total=total_clicks,
        form_fill_enabled=form_fill_enabled,
    )

    # 5a. Persist inline file uploads to disk so the job is resumable
    # across backend restarts. Without this, an inline-Excel + screenshot
    # job would mark `is_resumable=False` and the startup reaper would
    # mark it "stopped" with the scary "Job interrupted by repeated
    # backend restarts" diagnosis whenever the pod recycles.
    persisted_file_path: Optional[str] = None
    persisted_screenshot_path: Optional[str] = None
    try:
        from pathlib import Path as _P
        _job_dir = _P(__file__).parent / "real_user_traffic_results" / job_id / "uploads"
        _job_dir.mkdir(parents=True, exist_ok=True)
        if file_bytes:
            _ext = ".xlsx"
            if file_name and "." in file_name:
                _ext = "." + file_name.rsplit(".", 1)[-1].lower()
                if _ext not in (".xlsx", ".xls", ".csv"):
                    _ext = ".xlsx"
            persisted_file_path = str(_job_dir / f"data{_ext}")
            with open(persisted_file_path, "wb") as _fh:
                _fh.write(file_bytes)
        if target_screenshot_bytes:
            persisted_screenshot_path = str(_job_dir / "target.png")
            with open(persisted_screenshot_path, "wb") as _fh:
                _fh.write(target_screenshot_bytes)
    except Exception as e:
        logger.warning(f"Could not persist inline uploads for job {job_id}: {e}")

    # Build params dict + resumability flag BEFORE the DB upsert so we
    # can persist them into the job record for auto-resume on restart.
    params_dict = {
        "proxies": proxies,
        "user_agents": user_agents,
        "use_stored_proxies": use_stored_proxies,
        "upload_proxy_id": upload_proxy_id,
        "upload_ua_id": upload_ua_id,
        "upload_ua_ids": upload_ua_ids,
        "upload_data_file_id": upload_data_file_id,
        "upload_automation_json_id": upload_automation_json_id,
        "data_source": data_source,
        "gsheet_url": gsheet_url,
        "import_pending_from_job_id": import_pending_from_job_id,
        "form_fill_enabled": form_fill_enabled,
        "state_match_enabled": state_match_enabled,
        "selected_states": (selected_states or "").strip(),
        "selected_email_domains": (selected_email_domains or "").strip(),
        "automation_json": automation_json,
        "self_heal": self_heal,
        "pure_json_mode": bool(pure_json_mode),
        "auto_resume_enabled": bool(auto_resume_enabled),
        "skip_duplicate_ip": skip_duplicate_ip,
        "skip_vpn": skip_vpn,
        "follow_redirect": follow_redirect,
        "no_repeated_proxy": no_repeated_proxy,
        "allowed_countries": allowed_countries,
        "allowed_os": allowed_os,
        "skip_captcha": skip_captcha,
        "post_submit_wait": post_submit_wait,
        "invalid_detection_enabled": invalid_detection_enabled,
        "invalid_data_retry_limit": max(1, min(50, int(invalid_data_retry_limit or 10))),
        "step_timeout_multiplier": max(0.5, min(5.0, float(step_timeout_multiplier or 1.0))),
        # 2026-06-25 — Per-job watchdog inactivity ceiling (seconds).
        # Clamped 30..1800. Default 240 preserves existing behaviour.
        "stuck_watchdog_seconds": max(30.0, min(1800.0, float(stuck_watchdog_seconds or 600.0))),
        "target_screenshot_threshold": target_screenshot_threshold,
        "target_screenshot_upload_id": target_screenshot_upload_id,
        "target_screenshot_bytes": target_screenshot_bytes,
        "target_screenshot_path": persisted_screenshot_path,
        "file_bytes": file_bytes,
        "file_path": persisted_file_path,
        "file_name": file_name,
        "total_clicks": total_clicks,
        "concurrency": concurrency,
        "duration_minutes": duration_minutes,
        "target_mode": target_mode,
        "target_conversions": target_conversions,
        "max_attempts": max_attempts,
        "force_tracker_url": force_tracker_url,
        "use_proxyjet_auto": bool(use_proxyjet_auto),
        "proxyjet_country": (proxyjet_country or "US").strip().upper() or "US",
        "proxyjet_state": (proxyjet_state or "").strip().upper() or None,
        # ── 2026-06-11: ProxyJet Multi-Geo MIX + Multi-batch proxies ─
        # Parsed as CSV-or-newline tokens (case-insensitive, deduped).
        # When 2+ countries: per-visit ProxyJet picks one at random.
        # When 2+ states (US): same. Single-entry pools degrade silently.
        "proxyjet_countries": [
            x.strip().upper()
            for x in (proxyjet_countries or "").replace(",", "\n").splitlines()
            if x.strip()
        ],
        "proxyjet_states": [
            x.strip().upper()
            for x in (proxyjet_states or "").replace(",", "\n").splitlines()
            if x.strip()
        ],
        "upload_proxy_ids": upload_proxy_ids,
        "paste_proxy_lines": paste_proxy_lines,
        "paste_ua_lines": paste_ua_lines,
        "smoke_test": bool(smoke_test),
        # 2026-02 v2.1.31 — Anti-Detect Phase 1 wiring
        "pacing_per_hour": max(0, int(pacing_per_hour or 0)),
        "identity_label": (identity_label or "").strip()[:120],
        "tls_prewarm": bool(tls_prewarm),
        # 2026-02 v2.1.31 — Step 3 wiring
        "proxy_chain_enabled": bool(proxy_chain_enabled),
        "proxy_chain_use_tor": bool(proxy_chain_use_tor),
        "proxy_chain_extra_hops": [
            ln.strip() for ln in (proxy_chain_extra_hops or "").splitlines()
            if ln.strip()
        ][:6],  # cap at 6 extra hops
        "browser_variant": (browser_variant or "auto").strip().lower()[:32],
        # 2026-02 v2.1.31 — Step 4 wiring
        "behavioral_bio_enabled": bool(behavioral_bio_enabled),
        "ip_warmup_enabled": bool(ip_warmup_enabled),
        # 2026-06 — User-configurable Referrer override
        "referer_override_enabled": bool(referer_override_enabled),
        "referer_mode": (referer_mode or "auto").strip().lower()[:32],
        "referer_value": (referer_value or "")[:8000],          # newline-separated lists
        "referer_platform_pool": (referer_platform_pool or "")[:512],
        "referer_brand": (referer_brand or "")[:64],
        # 2026-06-11 — Referrer Pro-Mode (weighted, realism layers)
        "referer_pro_mode": bool(referer_pro_mode),
        "referer_platform_weights": (referer_platform_weights or "")[:4096],
        "referer_email_weights": (referer_email_weights or "")[:4096],
        "referer_social_wrapper": bool(referer_social_wrapper),
        "referer_inapp_deep": bool(referer_inapp_deep),
        "referer_search_engine": (referer_search_engine or "google").strip().lower()[:24],
        "referer_search_keywords": (referer_search_keywords or "")[:8000],
        "referer_strip_search_path": bool(referer_strip_search_path),
        "referer_network_click_chain": bool(referer_network_click_chain),
        # 2026-01 — Pass-Referer-To-Offer (direct offer navigation)
        "referer_pass_to_offer": bool(referer_pass_to_offer),
        # 2026-06-14 — UA ↔ Referer coercion (anti-fraud, default ON).
        "referer_match_ua_to_platform": bool(referer_match_ua_to_platform),
    }
    # A job is auto-resumable on backend restart only if it has no in-memory
    # bytes attached (Mongo can't store huge UploadFile blobs efficiently
    # and they'd never survive a restart anyway). Inline-file submissions
    # are a tiny minority since the frontend pre-uploads via /uploads/*.
    # ── Auto-resume opt-OUT (2026-01) ──────────────────────────────
    # Per repeated user feedback ("mein chahta hun job ek sequence
    # mein chale, resume na ho"), auto-resume is now DEFAULT OFF.
    # Behaviour:
    #   • is_resumable = False (this default)    → backend restart →
    #     reaper marks job `failed` with a friendly stop_reason
    #     pointing the user to "Retry this job" — NO re-spawning of
    #     the BG task. User-controlled lifecycle.
    #   • is_resumable = True (opt-in via the request param) →
    #     legacy auto-resume behaviour (rc reset on prep success,
    #     up to 100 attempts with exp backoff, etc).
    # Inline-file submissions used to be non-resumable but we now persist
    # them to disk in step 5a above, so they're resumable too as long as
    # the persisted paths exist.
    is_resumable = (
        bool(auto_resume_enabled)
        and (
            (file_bytes is None) or bool(persisted_file_path)
        )
        and (
            (target_screenshot_bytes is None) or bool(persisted_screenshot_path)
        )
    )
    persisted_params = {k: v for k, v in params_dict.items()
                        if k not in ("file_bytes", "target_screenshot_bytes")}

    queued_at = datetime.now(timezone.utc).isoformat()
    await db.real_user_traffic_jobs.update_one(
        {"job_id": job_id},
        {"$set": {
            "job_id": job_id,
            "user_id": user["id"],
            "target_url": target,
            "total": total_clicks,
            "form_fill_enabled": form_fill_enabled,
            "status": "queued",
            "preparing": True,
            "created_at": queued_at,
            "queued_at": queued_at,
            "concurrency": concurrency,
            "duration_minutes": duration_minutes,
            "target_mode": target_mode,
            "target_conversions": target_conversions if target_mode == "conversions" else 0,
            "max_attempts": max_attempts if target_mode == "conversions" else 0,
            "link_id": link.get("id"),
            "link_short_code": link.get("short_code"),
            "link_owner_id": link.get("user_id") or user["id"],
            "post_submit_wait": max(3, min(600, int(post_submit_wait))),
            "self_heal": self_heal,
            "pure_json_mode": bool(pure_json_mode),
            "state_match_enabled": state_match_enabled,
            "skip_duplicate_ip": skip_duplicate_ip,
            "skip_vpn": skip_vpn,
            "follow_redirect": follow_redirect,
            "no_repeated_proxy": no_repeated_proxy,
            "skip_captcha": skip_captcha,
            "invalid_detection_enabled": invalid_detection_enabled,
            "invalid_data_retry_limit": max(1, min(50, int(invalid_data_retry_limit or 10))),
            "step_timeout_multiplier": max(0.5, min(5.0, float(step_timeout_multiplier or 1.0))),
            # 2026-06-25 — Per-job watchdog inactivity ceiling (persisted)
            "stuck_watchdog_seconds": max(30.0, min(1800.0, float(stuck_watchdog_seconds or 600.0))),
            "force_tracker_url": force_tracker_url,
            "use_proxyjet_auto": bool(use_proxyjet_auto),
            "proxyjet_country": (proxyjet_country or "US").strip().upper() or "US",
            "proxyjet_state": (proxyjet_state or "").strip().upper() or None,
            "data_source": data_source,
            # Counts will be updated by the BG task after it loads from
            # gsheet / upload batches. Set to paste-mode counts now so
            # the UI shows something immediately for paste-only jobs.
            "proxies_count": len(paste_proxy_lines),
            "user_agents_count": len(paste_ua_lines),
            "rows_loaded": 0,
            "custom_automation": bool((automation_json or "").strip() or upload_automation_json_id),
            # ── Auto-resume support ──────────────────────────────────
            # If `is_resumable` is True and the backend restarts before
            # this job actually started running visits, the startup
            # reaper will RE-SCHEDULE the BG task instead of marking it
            # failed. submit_params is everything _rut_prepare_and_run
            # needs to do its job from scratch (minus inline file bytes,
            # which are unfortunately not resumable).
            "is_resumable": is_resumable,
            "submit_params": persisted_params if is_resumable else None,
            "restart_count": 0,
            # 2026-05 — Smoke-test marker (used by the frontend to render
            # the validation result panel instead of the regular full-job
            # report).
            "smoke_test": bool(smoke_test),
            # 2026-02 v2.1.31 — Anti-Detect Phase 1 wiring (persisted so
            # Past Jobs + retry see the settings used for the run)
            "pacing_per_hour": max(0, int(pacing_per_hour or 0)),
            "identity_label": (identity_label or "").strip()[:120],
            "tls_prewarm": bool(tls_prewarm),
            # 2026-02 v2.1.31 — Step 3 wiring (persisted)
            "proxy_chain_enabled": bool(proxy_chain_enabled),
            "proxy_chain_use_tor": bool(proxy_chain_use_tor),
            "proxy_chain_extra_hops": [
                ln.strip() for ln in (proxy_chain_extra_hops or "").splitlines()
                if ln.strip()
            ][:6],
            "browser_variant": (browser_variant or "auto").strip().lower()[:32],
            # 2026-02 v2.1.31 — Step 4 wiring (persisted)
            "behavioral_bio_enabled": bool(behavioral_bio_enabled),
            "ip_warmup_enabled": bool(ip_warmup_enabled),
            # 2026-06 — Referrer override (persisted so Past-Jobs + retry
            # see the exact settings used for the run)
            "referer_override_enabled": bool(referer_override_enabled),
            "referer_mode": (referer_mode or "auto").strip().lower()[:32],
            "referer_value": (referer_value or "")[:8000],
            "referer_platform_pool": (referer_platform_pool or "")[:512],
            "referer_brand": (referer_brand or "")[:64],
            # 2026-06-11 — Referrer Pro-Mode (persisted)
            "referer_pro_mode": bool(referer_pro_mode),
            "referer_platform_weights": (referer_platform_weights or "")[:4096],
            "referer_email_weights": (referer_email_weights or "")[:4096],
            "referer_social_wrapper": bool(referer_social_wrapper),
            "referer_inapp_deep": bool(referer_inapp_deep),
            "referer_search_engine": (referer_search_engine or "google").strip().lower()[:24],
            "referer_search_keywords": (referer_search_keywords or "")[:8000],
            "referer_strip_search_path": bool(referer_strip_search_path),
            "referer_network_click_chain": bool(referer_network_click_chain),
            # 2026-06-14 — UA ↔ Referer coercion (persisted)
            "referer_match_ua_to_platform": bool(referer_match_ua_to_platform),
        }},
        upsert=True,
    )

    # 6. Schedule heavy prep + run in background — endpoint returns now
    background.add_task(
        _rut_prepare_and_run,
        job_id=job_id,
        user=user,
        link=link,
        target=target,
        params=params_dict,
    )

    # 7. Fast response — frontend gets job_id within ~1-2s, regardless of
    # how big the gsheet / Excel / dup-IP scan is.
    return {
        "job_id": job_id,
        "total": total_clicks if target_mode == "clicks" else (max_attempts or target_conversions * 20),
        "target_url": target,
        "proxies": len(paste_proxy_lines),  # actual count for upload-mode is filled in by BG task
        "user_agents": len(paste_ua_lines),
        "form_fill_enabled": form_fill_enabled,
        "state_match_enabled": state_match_enabled,
        "target_mode": target_mode,
        "target_conversions": target_conversions if target_mode == "conversions" else 0,
        "max_attempts": max_attempts if target_mode == "conversions" else 0,
        "imported_from_job": import_pending_from_job_id or "",
        "rows_loaded": 0,  # will be updated by BG task
        "custom_automation": bool((automation_json or "").strip() or upload_automation_json_id),
        "post_submit_wait": max(3, min(600, int(post_submit_wait))),
        "concurrency": concurrency,
        "duration_minutes": duration_minutes,
        "preparing": True,  # signals UI that BG prep is in flight
    }


