@api_router.get("/real-user-traffic/jobs/{job_id}")
async def rut_get_job(job_id: str, user: dict = Depends(get_current_user)):
    check_user_feature(user, "real_user_traffic")
    j = _RUT_JOBS.get(job_id)
    if not j:
        j = await db.real_user_traffic_jobs.find_one(
            {"job_id": job_id, "user_id": user["id"]}, {"_id": 0}
        )
    if not j or j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    # Strip internal keys (asyncio.Event, raw browser refs, etc.) — these
    # aren't JSON-serializable and shouldn't leak to the UI. Also surface
    # `is_draining` so the UI can show "🎯 Target reached — draining N
    # in-flight visits…" while in-flight work wraps up.
    cleaned = {k: v for k, v in j.items() if not k.startswith("_")}
    drain_ev = j.get("_target_drain_event")
    cancel_ev = j.get("_cancel_event")
    cleaned["is_draining"] = bool(
        drain_ev is not None
        and getattr(drain_ev, "is_set", lambda: False)()
        and not (cancel_ev is not None and getattr(cancel_ev, "is_set", lambda: False)())
    )
    return cleaned


