@api_router.get("/real-user-traffic/jobs/{job_id}/diagnostics")
async def rut_job_diagnostics(
    job_id: str,
    user: dict = Depends(get_current_user),
):
    """Return per-job diagnostics: which URLs leaked unfilled tracker
    macros (`{{ccpa}}` etc.) and where individual visits got stuck.
    Powers the "Diagnostics" tab on the Real-User-Traffic job-detail
    page so the operator can see WHY an offer isn't reaching its final
    page without scraping log files.

    2026-05 — ALSO returns `script_diagnostics`: Smart Replay Diagnostics
    (anti-pattern detection + wrapper-kind summary + top-3 slowest
    recommendation) computed via static analysis of the recorded
    automation script. Helps the operator spot brittle/slow steps in
    their recording without ever opening a log file.
    """
    check_user_feature(user, "real_user_traffic")
    # Ownership check
    db_job = await db.real_user_traffic_jobs.find_one(
        {"job_id": job_id, "user_id": user["id"]},
        {"_id": 0, "user_id": 1, "script": 1, "submit_params": 1, "name": 1},
    )
    if not db_job:
        # Allow in-flight jobs too (not yet persisted)
        from real_user_traffic import RUT_JOBS as _RJ
        live = _RJ.get(job_id) or {}
        if live.get("user_id") != user["id"]:
            raise HTTPException(status_code=404, detail="Job not found")
        # We still want to surface script diagnostics for in-flight jobs;
        # pull the script from the live object if persisted form is missing.
        if not db_job:
            db_job = {
                "script": live.get("script"),
                "submit_params": live.get("submit_params"),
            }

    macro_cursor = db.rut_diagnostics.find(
        {"job_id": job_id, "kind": "macro_leak"},
        {"_id": 0},
    ).sort("timestamp", 1).limit(500)
    stuck_cursor = db.rut_diagnostics.find(
        {"job_id": job_id, "kind": "stuck"},
        {"_id": 0},
    ).sort("timestamp", 1).limit(500)

    macro_events: List[dict] = []
    async for e in macro_cursor:
        macro_events.append(e)
    stuck_events: List[dict] = []
    async for e in stuck_cursor:
        stuck_events.append(e)

    # Aggregate top blocked hosts so the UI can show a "Most common
    # macro-leak hosts" panel without re-doing the work client-side.
    from collections import Counter
    from urllib.parse import urlparse
    host_counter: Counter = Counter()
    for ev in macro_events:
        try:
            host_counter[urlparse(ev.get("blocked_url", "")).netloc or "(unknown)"] += 1
        except Exception:
            host_counter["(unknown)"] += 1
    top_hosts = [{"host": h, "count": c} for h, c in host_counter.most_common(10)]

    stuck_host_counter: Counter = Counter()
    for ev in stuck_events:
        try:
            stuck_host_counter[urlparse(ev.get("stuck_url", "")).netloc or "(unknown)"] += 1
        except Exception:
            stuck_host_counter["(unknown)"] += 1
    top_stuck_hosts = [{"host": h, "count": c} for h, c in stuck_host_counter.most_common(10)]

    # ── 2026-05: Smart Replay Diagnostics (static analysis) ────────
    # Pull the recorded script from either the persisted job doc or its
    # submit_params, then run analyse_steps on it.
    script_steps: List[Dict[str, Any]] = []
    if isinstance(db_job.get("script"), list):
        script_steps = db_job["script"]
    elif isinstance(db_job.get("submit_params"), dict):
        s = db_job["submit_params"].get("steps") or db_job["submit_params"].get("script")
        if isinstance(s, list):
            script_steps = s
    script_diag: Dict[str, Any] = {}
    try:
        if vr is not None and hasattr(vr, "analyse_steps") and script_steps:
            script_diag = vr.analyse_steps(script_steps, None)
    except Exception as e:  # noqa: BLE001
        logger.warning(f"[rut_job_diagnostics] analyse_steps failed: {e}")

    return {
        "job_id": job_id,
        "macro_leaks": macro_events,
        "macro_leak_count": len(macro_events),
        "top_macro_leak_hosts": top_hosts,
        "stuck_events": stuck_events,
        "stuck_event_count": len(stuck_events),
        "top_stuck_hosts": top_stuck_hosts,
        "script_diagnostics": script_diag,
        "script_step_count": len(script_steps),
    }





@api_router.get("/real-user-traffic/jobs/{job_id}/live-log")
async def rut_live_log(
    job_id: str,
    since: int = 0,
    user: dict = Depends(get_current_user),
):
    """Return live step-by-step activity log for a running job. Polled by
    the 'Show live activity' modal in the UI. Only returns new steps after
    the given cursor so traffic stays tiny. If the job is not in memory,
    returns running=False so the UI can stop polling."""
    check_user_feature(user, "real_user_traffic")
    # Ownership check — either via in-memory dict or DB
    j = _RUT_JOBS.get(job_id)
    if j is None:
        db_job = await db.real_user_traffic_jobs.find_one(
            {"job_id": job_id, "user_id": user["id"]}, {"_id": 0, "user_id": 1}
        )
        if not db_job:
            raise HTTPException(status_code=404, detail="Job not found")
    elif j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    return _rut_get_live_steps(job_id, since=int(since or 0))


# 2026-01: Per-visit live activity feed — mirrors the Visual Recorder's
# live-test visual feed but for RUT visits. Returns a snapshot of the
# `live_visits` dict so the UI can show a grid of concurrent visit
# tiles, each with its latest browser frame + current step.
@api_router.get("/real-user-traffic/jobs/{job_id}/live-visits")
async def rut_live_visits(
    job_id: str,
    include_frames: bool = True,
    user: dict = Depends(get_current_user),
):
    """Return current live-visits state for a running RUT job. Each
    entry contains the latest browser screenshot (base64 JPEG) + the
    most recent step event for that visit.

    Args:
        include_frames: when False, strips the (heavy) screenshot bytes
            so the frontend can do a lightweight "are any visits still
            updating" probe.
    """
    check_user_feature(user, "real_user_traffic")
    j = _RUT_JOBS.get(job_id)
    if j is None:
        # Job not running OR not owned — DB fallback so we don't 404
        # for completed jobs (UI can still show empty state).
        db_job = await db.real_user_traffic_jobs.find_one(
            {"job_id": job_id, "user_id": user["id"]}, {"_id": 0, "user_id": 1}
        )
        if not db_job:
            raise HTTPException(status_code=404, detail="Job not found")
        return {"visits": {}, "job_running": False}
    if j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    live_visits = j.get("live_visits") or {}
    if not include_frames:
        # Slim copy without screenshot bytes
        slim = {}
        for k, v in live_visits.items():
            slim[k] = {kk: vv for kk, vv in v.items() if kk != "latest_frame_b64"}
        return {
            "visits": slim,
            "job_running": j.get("status") in ("running", "queued", "preparing"),
            "concurrency": j.get("concurrency", 0),
            "processed": j.get("processed", 0),
            "total": j.get("total", 0),
        }
    return {
        "visits": live_visits,
        "job_running": j.get("status") in ("running", "queued", "preparing"),
        "concurrency": j.get("concurrency", 0),
        "processed": j.get("processed", 0),
        "total": j.get("total", 0),
    }


@api_router.post("/real-user-traffic/jobs/{job_id}/visits/{visit_index}/cancel")
async def rut_cancel_visit(
    job_id: str,
    visit_index: int,
    user: dict = Depends(get_current_user),
):
    """2026-05 — Manually kill ONE in-flight visit in the Live Visual
    Grid without stopping the whole job. The concurrency slot is freed
    automatically so the dispatcher spawns the next pending visit.

    Used by the per-tile "kill" button when a profile is stuck on an
    ineligible / error page and the user wants to skip it instead of
    waiting out the timeout.
    """
    check_user_feature(user, "real_user_traffic")
    j = _RUT_JOBS.get(job_id)
    if j is None:
        raise HTTPException(status_code=404, detail="Job not found or not running")
    if j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    try:
        from real_user_traffic import cancel_visit as _cancel_visit
        result = _cancel_visit(job_id, visit_index)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"cancel_failed: {e}")
    if not result.get("ok"):
        raise HTTPException(status_code=400, detail=result.get("reason") or "cancel_failed")
    return result


# ──────────────────────────────────────────────────────────────────────
# 2026-06 — Live Visual Grid: Manual Takeover + Hybrid Streaming endpoints
# ──────────────────────────────────────────────────────────────────────
# Customer ask (Roman Urdu):
#   "live visual grid mein sab smoothly live dikhe na k screenshot k mood
#    mein… or live visual grid mein manually kam krne ka b option ho jese
#    profile khol kr kam krte hien… agr stuck ho jay to manuualy wo kaam
#    kr liya jay."
#
# Six endpoints, all owner-gated against _RUT_JOBS[job_id]["user_id"]:
#
#   POST /visits/{idx}/pause   → suspend the automation step loop for THIS
#                                visit (the rest of the job keeps running).
#   POST /visits/{idx}/resume  → lift the pause; step loop continues from
#                                where it was waiting.
#   POST /visits/{idx}/stream  → switch streaming cadence ("off" | "grid"
#                                | "expanded") for THIS visit. Drives the
#                                per-visit screenshot daemon — covers the
#                                idle gaps between script-emitted frames
#                                that used to make a working visit look
#                                "stuck" in the UI.
#   POST /visits/{idx}/input   → unified input-forwarding endpoint. Body
#                                `{"kind": "click|type|key|scroll|nav|back",
#                                  "payload": {...}}`. Pushes the input
#                                straight to the live Playwright page so
#                                the operator can finish a stuck visit by
#                                hand (e.g. click a deal the recorded
#                                automation missed).
#
# Everything is ADDITIVE — no existing endpoint, no existing flow, no
# existing customer behaviour changes if the new UI is never opened.
# ──────────────────────────────────────────────────────────────────────
def _rut_lookup_visit(job_id: str, visit_index: int, user: dict) -> Dict[str, Any]:
    """Owner-gated lookup. Raises HTTPException on miss."""
    j = _RUT_JOBS.get(job_id)
    if j is None:
        raise HTTPException(status_code=404, detail="Job not found or not running")
    if j.get("user_id") != user["id"]:
        raise HTTPException(status_code=404, detail="Job not found")
    lv = j.get("live_visits") or {}
    v = lv.get(str(visit_index))
    if v is None:
        raise HTTPException(status_code=404, detail="Visit not found in this job")
    return v


@api_router.post("/real-user-traffic/jobs/{job_id}/visits/{visit_index}/pause")
async def rut_visit_pause(
    job_id: str,
    visit_index: int,
    user: dict = Depends(get_current_user),
):
    check_user_feature(user, "real_user_traffic")
    v = _rut_lookup_visit(job_id, visit_index, user)
    try:
        from real_user_traffic import set_visit_paused, get_live_page
        if get_live_page(job_id, visit_index) is None:
            raise HTTPException(status_code=409, detail="Visit has no live page (already finished)")
        set_visit_paused(job_id, visit_index, True)
        # Mirror into the visit snapshot so the UI reflects it immediately
        v["paused"] = True
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"pause_failed: {e}")
    return {"ok": True, "paused": True, "visit_idx": visit_index}


@api_router.post("/real-user-traffic/jobs/{job_id}/visits/{visit_index}/resume")
async def rut_visit_resume(
    job_id: str,
    visit_index: int,
    user: dict = Depends(get_current_user),
):
    check_user_feature(user, "real_user_traffic")
    v = _rut_lookup_visit(job_id, visit_index, user)
    try:
        from real_user_traffic import set_visit_paused
        set_visit_paused(job_id, visit_index, False)
        v["paused"] = False
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"resume_failed: {e}")
    return {"ok": True, "paused": False, "visit_idx": visit_index}


@api_router.post("/real-user-traffic/jobs/{job_id}/visits/{visit_index}/stream")
async def rut_visit_stream(
    job_id: str,
    visit_index: int,
    request: Request,
    user: dict = Depends(get_current_user),
):
    """Switch the per-visit screenshot daemon between off / grid (low fps,
    cheap, covers idle gaps) / expanded (high fps, focused single tile).
    The frontend calls this when the user opens the grid, opens an
    expanded tile, or closes either — so CPU/bandwidth scales with what
    the operator is actually watching."""
    check_user_feature(user, "real_user_traffic")
    _ = _rut_lookup_visit(job_id, visit_index, user)
    try:
        body = await request.json()
    except Exception:
        body = {}
    mode = (body.get("mode") or "off").lower().strip()
    if mode not in ("off", "grid", "expanded"):
        raise HTTPException(status_code=400, detail="mode must be off|grid|expanded")
    try:
        from real_user_traffic import set_stream_mode
        await set_stream_mode(job_id, visit_index, mode)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"stream_failed: {e}")
    return {"ok": True, "mode": mode, "visit_idx": visit_index}


@api_router.post("/real-user-traffic/jobs/{job_id}/visits/{visit_index}/input")
async def rut_visit_input(
    job_id: str,
    visit_index: int,
    request: Request,
    user: dict = Depends(get_current_user),
):
    """Forward a single input action to the live Playwright page. Body:

        {"kind": "click",  "payload": {"x": 800, "y": 450,
                                       "frame_w": 1280, "frame_h": 720}}
        {"kind": "type",   "payload": {"text": "hello world",
                                       "delay_ms": 18}}
        {"kind": "key",    "payload": {"key": "Enter"}}
        {"kind": "scroll", "payload": {"dx": 0, "dy": 400}}
        {"kind": "nav",    "payload": {"url": "https://..."}}
        {"kind": "back",   "payload": {}}

    Coordinates are in the frame the operator clicked on — we scale
    them to the live page's viewport so a click on a downscaled
    thumbnail still lands on the correct DOM element.

    Safety: this endpoint REFUSES to send input if the visit is NOT
    paused (409 Conflict). That avoids the race where the recorded
    automation is mid-click while the operator's hand is also moving.
    Operator must call /pause first, perform manual actions, then
    /resume."""
    check_user_feature(user, "real_user_traffic")
    _ = _rut_lookup_visit(job_id, visit_index, user)
    try:
        from real_user_traffic import (
            is_visit_paused, get_live_page,
        )
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"engine_unavailable: {e}")
    if not is_visit_paused(job_id, visit_index):
        raise HTTPException(
            status_code=409,
            detail="Visit must be paused before forwarding manual input"
        )
    page = get_live_page(job_id, visit_index)
    if page is None:
        raise HTTPException(status_code=410, detail="Visit page has closed")
    try:
        body = await request.json()
    except Exception:
        body = {}
    kind = (body.get("kind") or "").lower().strip()
    payload = body.get("payload") or {}
    try:
        if kind == "click":
            # Scale frame coordinates → viewport coordinates so a click on
            # the downscaled <img> in the UI lands on the right DOM node.
            try:
                vp = page.viewport_size or {"width": 1280, "height": 720}
            except Exception:
                vp = {"width": 1280, "height": 720}
            fw = float(payload.get("frame_w") or vp["width"] or 1280)
            fh = float(payload.get("frame_h") or vp["height"] or 720)
            sx = float(vp["width"]) / fw if fw else 1.0
            sy = float(vp["height"]) / fh if fh else 1.0
            x = float(payload.get("x") or 0) * sx
            y = float(payload.get("y") or 0) * sy
            button = (payload.get("button") or "left").lower()
            await page.mouse.move(x, y)
            await page.mouse.click(x, y, button=button, delay=int(payload.get("delay_ms") or 35))
            result = {"x": round(x, 1), "y": round(y, 1)}
        elif kind == "type":
            text = str(payload.get("text") or "")
            if not text:
                raise HTTPException(status_code=400, detail="type.payload.text required")
            await page.keyboard.type(text, delay=int(payload.get("delay_ms") or 18))
            result = {"typed": len(text)}
        elif kind == "key":
            key = str(payload.get("key") or "").strip()
            if not key:
                raise HTTPException(status_code=400, detail="key.payload.key required")
            await page.keyboard.press(key)
            result = {"key": key}
        elif kind == "scroll":
            dx = float(payload.get("dx") or 0)
            dy = float(payload.get("dy") or 0)
            await page.mouse.wheel(dx, dy)
            result = {"dx": dx, "dy": dy}
        elif kind == "nav":
            url = str(payload.get("url") or "").strip()
            if not url:
                raise HTTPException(status_code=400, detail="nav.payload.url required")
            await page.goto(url, timeout=30000, wait_until="domcontentloaded")
            result = {"url": page.url}
        elif kind == "back":
            try:
                await page.go_back(timeout=15000, wait_until="domcontentloaded")
            except Exception:
                pass
            result = {"url": page.url}
        else:
            raise HTTPException(status_code=400, detail=f"unknown input kind: {kind!r}")
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"input_failed: {type(e).__name__}: {e}")
    return {"ok": True, "kind": kind, "result": result, "visit_idx": visit_index}


@api_router.get("/real-user-traffic/jobs/{job_id}/screenshot/{filename}")
async def rut_screenshot(
    job_id: str,
    filename: str,
    request: Request,
    t: Optional[str] = None,
):
    """Serve a single visit screenshot (PNG) from the RUT results folder.
    Used by the Live Activity modal to show proof thumbnails next to each
    step. Auth is accepted via EITHER the standard Authorization header
    (for API clients) OR a ?t=<jwt> query param (so <img> tags can embed
    the URL without needing a header). Ownership is enforced against the
    in-memory job OR the DB doc. Only plain basenames are allowed — no
    path traversal."""
    # Manual auth — support both header and query-param token
    token_value = None
    auth_header = request.headers.get("Authorization")
    if auth_header and auth_header.startswith("Bearer "):
        token_value = auth_header.split(" ", 1)[1]
    elif t:
        token_value = t
    if not token_value:
        raise HTTPException(status_code=401, detail="Not authenticated")
    try:
        payload = jwt.decode(token_value, SECRET_KEY, algorithms=[ALGORITHM])
        email = payload.get("sub")
        is_sub_user = payload.get("is_sub_user", False)
        parent_user_id = payload.get("parent_user_id")
        if not email:
            raise HTTPException(status_code=401, detail="Invalid token")
    except JWTError:
        # v2.1.16 — Cloud-Auth Bridge fallback for inline JWT decode.
        # On desktop installs the token was signed by krexion.com so
        # local decode fails. Resolve via cloud /api/auth/me.
        cloud_user = await _resolve_cloud_user_dict(f"Bearer {token_value}")
        if not cloud_user:
            raise HTTPException(status_code=401, detail="Invalid token")
        email = cloud_user.get("email")
        is_sub_user = False
        parent_user_id = None

    # Resolve user id (main or sub-user)
    user_id = None
    if is_sub_user and parent_user_id:
        user_id = parent_user_id
    else:
        u = await db.users.find_one({"email": email}, {"_id": 0, "id": 1, "status": 1, "features": 1})
        if not u or u.get("status") != "active" or not (u.get("features") or {}).get("real_user_traffic"):
            raise HTTPException(status_code=403, detail="Forbidden")
        user_id = u["id"]

    # Ownership
    j = _RUT_JOBS.get(job_id)
    if j is None:
        db_job = await db.real_user_traffic_jobs.find_one(
            {"job_id": job_id, "user_id": user_id}, {"_id": 0, "user_id": 1}
        )
        if not db_job:
            raise HTTPException(status_code=404, detail="Job not found")
    elif j.get("user_id") != user_id:
        raise HTTPException(status_code=404, detail="Job not found")

    # Basename-only — defence against "../" path traversal
    safe = os.path.basename(filename)
    if not safe.endswith(".png") or "/" in filename or "\\" in filename or safe != filename:
        raise HTTPException(status_code=400, detail="Invalid filename")

    from real_user_traffic import RESULTS_ROOT
    path = RESULTS_ROOT / job_id / "screenshots" / safe
    if not path.exists() or not path.is_file():
        raise HTTPException(status_code=404, detail="Screenshot not found")
    return FileResponse(path, media_type="image/png")


