@api_router.post("/visual-recorder/start")
async def vr_start(
    req: VRStartReq,
    user: dict = Depends(get_current_user),
    _cloud_gate: bool = Depends(require_local_mode),
):
    check_user_feature(user, "real_user_traffic")
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder module not available")
    try:
        sess = await vr.start_session(
            user_id=user["id"],
            url=req.url,
            proxy=req.proxy,
            user_agent=req.user_agent,
            headers=req.headers or [],
            sample_row=req.sample_row or None,
            device_type=(req.device_type or "auto"),
            country=(req.country or ""),
            locale=(req.locale or ""),
            timezone_id=(req.timezone or ""),
            accept_language=(req.accept_language or ""),
            viewport_w=int(req.viewport_w or 0),
            viewport_h=int(req.viewport_h or 0),
            device_scale_factor=float(req.device_scale_factor or 0.0),
        )
    except RuntimeError as e:
        raise HTTPException(status_code=429, detail=str(e))
    except Exception as e:
        logger.exception("vr_start failed")
        raise HTTPException(status_code=500, detail=f"Failed to start recorder: {e}")
    return {
        "session_id": sess.session_id,
        "url": sess.url,
        "viewport": {"width": sess.viewport[0], "height": sess.viewport[1]},
        "headers": sess.headers,
        "step_count": len(sess.steps),
        "state": sess.state,
        "error_message": sess.error_message or "",
    }


def _vr_require_ready(sess) -> None:
    """Raise 409 if the session isn't ready yet (still starting / errored)."""
    if sess.state == "ready":
        return
    if sess.state == "starting":
        raise HTTPException(status_code=409, detail="Session is still connecting — please wait")
    if sess.state == "error":
        raise HTTPException(status_code=409, detail=f"Session failed: {sess.error_message}")
    raise HTTPException(status_code=409, detail=f"Session not ready (state={sess.state})")


# ── List all active sessions for current user ──────────────────────────
# Powers the "Active Sessions" panel on the Visual Recorder setup screen.
# The user can see every recorder currently running under their account,
# switch to any one of them, or stop the ones they no longer need — so
# the MAX_CONCURRENT_SESSIONS=5 cap is never hit silently.
@api_router.get("/visual-recorder/sessions")
async def vr_list_sessions(user: dict = Depends(get_current_user)):
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    try:
        items = vr.list_user_sessions(user["id"])
        stats = vr.get_global_session_stats()
    except Exception as e:
        logger.exception("vr_list_sessions failed")
        raise HTTPException(status_code=500, detail=f"Failed to list sessions: {e}")
    return {
        "sessions": items,
        "user_session_count": len(items),
        "total_running": stats["total_running"],
        "max_concurrent": stats["max_concurrent"],
    }


@api_router.get("/visual-recorder/{session_id}/screenshot")
async def vr_screenshot(
    session_id: str,
    request: Request,
    t: Optional[str] = None,  # token via query param so <img src> can load directly (no fetch/blob plumbing)
):
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    # Resolve user either from Authorization header OR ?t=<jwt> query param.
    user = None
    auth_header = request.headers.get("Authorization") or ""
    token_str = None
    if auth_header.startswith("Bearer "):
        token_str = auth_header.split(" ", 1)[1]
    elif t:
        token_str = t
    if not token_str:
        raise HTTPException(status_code=401, detail="Not authenticated")
    try:
        payload = jwt.decode(token_str, SECRET_KEY, algorithms=[ALGORITHM])
        email = payload.get("sub")
        if not email:
            raise HTTPException(status_code=401, detail="Invalid token")
    except JWTError:
        # v2.1.16 — Cloud-Auth Bridge fallback for inline JWT decode.
        cloud_user = await _resolve_cloud_user_dict(f"Bearer {token_str}")
        if not cloud_user:
            raise HTTPException(status_code=401, detail="Invalid token")
        email = cloud_user.get("email")
    user_doc = await db.users.find_one({"email": email}, {"_id": 0})
    if not user_doc:
        raise HTTPException(status_code=401, detail="User not found")
    user = user_doc
    try:
        sess = vr.get_session(session_id, user["id"])
    except KeyError:
        raise HTTPException(status_code=404, detail="Session not found")
    if sess.state != "ready":
        # Frontend treats 202 as "still connecting" — don't show toast errors.
        from fastapi.responses import JSONResponse as _JR
        return _JR(
            status_code=202,
            content={"state": sess.state, "error_message": sess.error_message or ""},
        )
    data = await vr.take_screenshot(sess)
    if not data:
        raise HTTPException(status_code=503, detail="Screenshot unavailable")
    from fastapi.responses import Response as _Resp
    return _Resp(content=data, media_type="image/jpeg", headers={"Cache-Control": "no-store"})


@api_router.post("/visual-recorder/{session_id}/reload")
async def vr_reload(session_id: str, user: dict = Depends(get_current_user)):
    """2026-05 — Reload the live page when stuck on chrome-error://.

    Surfaced via the new error banner in the Visual Recorder UI when
    `page_status != "ok"`. Re-issues `page.goto(sess.url)` with a 30s
    timeout — keeps all recorded steps intact.
    """
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    try:
        sess = vr.get_session(session_id, user["id"])
    except KeyError:
        raise HTTPException(status_code=404, detail="Session not found")
    return await vr.reload_page(sess)


# ── 2026-01 (multi-tab support) ────────────────────────────────────────
# Endpoints so the Visual Recorder UI can render a tabs bar AND let the
# user switch between / close tabs that the offer page spawned via
# target="_blank" / window.open. Without these, clicks that open a new
# tab silently navigate the (invisible) new page while the user keeps
# staring at the old one — making it impossible to record steps on the
# offer's destination page. See visual_recorder._attach_page_listeners.
@api_router.get("/visual-recorder/{session_id}/tabs")
async def vr_list_tabs(session_id: str, user: dict = Depends(get_current_user)):
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    try:
        sess = vr.get_session(session_id, user["id"])
    except KeyError:
        raise HTTPException(status_code=404, detail="Session not found")
    if sess.state != "ready":
        return {"tabs": [], "active_index": 0, "state": sess.state}
    tabs = await vr.list_tabs(sess)
    return {
        "tabs": tabs,
        "active_index": sess.active_page_index,
        "total": len(tabs),
        "state": sess.state,
    }


