@api_router.get("/visual-recorder/{session_id}/state")
async def vr_state(session_id: str, user: dict = Depends(get_current_user)):
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    try:
        sess = vr.get_session(session_id, user["id"])
    except KeyError:
        raise HTTPException(status_code=404, detail="Session not found")
    meta = await vr.get_page_meta(sess)
    elapsed = int(time.time() - sess.created_at)
    return {
        "session_id": sess.session_id,
        "state": sess.state,                  # starting | ready | error | stopped
        "error_message": sess.error_message or "",
        "elapsed_seconds": elapsed,
        "page": meta,
        "steps": sess.steps,
        "step_count": len(sess.steps),
        "headers": sess.headers,
        "target_screenshot_set": bool(sess.target_screenshot_path),
        "final_url": sess.final_url,
        "idle_seconds": int(time.time() - sess.last_activity),
    }


class VRClickReq(BaseModel):
    x: int
    y: int
    mode: str = "default"          # default | form_fill | random | final
    header_name: Optional[str] = None
    group_id: Optional[str] = None


@api_router.post("/visual-recorder/{session_id}/click")
async def vr_click(session_id: str, req: VRClickReq, user: dict = Depends(get_current_user)):
    if vr is None:
        raise HTTPException(status_code=500, detail="Visual recorder unavailable")
    try:
        sess = vr.get_session(session_id, user["id"])
    except KeyError:
        raise HTTPException(status_code=404, detail="Session not found")
    _vr_require_ready(sess)
    out = await vr.click_at(sess, req.x, req.y, mode=req.mode, header_name=req.header_name, group_id=req.group_id)
    if req.mode in ("random", "random_click") and out.get("element"):
        # Track for later /group-random call (same pool serves both
        # Random Pick and Random Click tools — they emit the same
        # random-pick evaluate step).
        if not hasattr(sess, "_pending_random"):
            sess._pending_random = []
        txt = (out["element"].get("text") or "").strip()
        if txt:
            sess._pending_random.append(txt)
            out["pending_random_count"] = len(sess._pending_random)
    return out


