# ─── Response compression ──────────────────────────────────────────────
# JSON-heavy endpoints (uploads list, jobs list, click stats) shrink
# 60-80 % over the wire when gzip-compressed. Browser & axios handle
# `accept-encoding: gzip` automatically, so the frontend needs zero
# changes. `minimum_size=512` skips tiny responses where compression
# overhead would dominate.
app.add_middleware(GZipMiddleware, minimum_size=512, compresslevel=5)


# ─── v1.0.19: Visual Recorder bridge middleware ──────────────────────
# Visual Recorder is stateful — start/screenshot/click/state/etc all
# operate on the SAME in-memory Playwright session. When the cloud
# proxies only /start to the desktop, the session lives on the desktop
# only, but the subsequent screenshot/state/click calls hit the cloud
# (which has no such session) and 404. The customer sees "Spinning up
# Chromium directly..." spin forever.
#
# Fix: a single middleware that — on the cloud edge — bridges every
# /api/visual-recorder/* request to the user's online desktop PC and
# returns the desktop's response verbatim. The middleware short-circuits
# only when:
#   - IS_CLOUD is true (this is the public edge), AND
#   - the request targets /api/visual-recorder/* (any verb), AND
#   - we can resolve the user from Authorization header OR ?t= JWT, AND
#   - that user has an online local PC (sync_heartbeat within 90s).
# Otherwise it falls through to the original endpoint (no change for
# desktop-mode customers, dev runs, or users without an online PC).
@app.middleware("http")
async def _vr_bridge_middleware(request: Request, call_next):
    try:
        if not IS_CLOUD:
            return await call_next(request)
        path = request.url.path or ""
        # v2.1.8: extend to also bridge real-user-traffic job
        # polling endpoints. After v2.1.7 the bridged RUT job is
        # created in the DESKTOP's local DB only, so the cloud's
        # GET /api/real-user-traffic/jobs/{id}* returns 404 for
        # the user's own job. Bridge them.
        is_vr = path.startswith("/api/visual-recorder/")
        is_rut_job = (
            path.startswith("/api/real-user-traffic/jobs/")
            or path.rstrip("/") == "/api/real-user-traffic/jobs"
        )
        if not (is_vr or is_rut_job):
            return await call_next(request)
        # Don't bridge the VR listing endpoint — cloud serves its OWN
        # listing from MongoDB-replicated session metadata (or returns
        # empty list, which is correct from cloud's POV).
        if path.rstrip("/") == "/api/visual-recorder/sessions":
            return await call_next(request)
        # /start (VR) and /jobs (POST RUT) are already gated by
        # Depends(require_local_mode) which bridges via _BridgeDone —
        # let them through unchanged.
        if path.endswith("/visual-recorder/start"):
            return await call_next(request)
        if path.rstrip("/") == "/api/real-user-traffic/jobs" and request.method.upper() == "POST":
            return await call_next(request)
        # 2026-06 CRITICAL FIX: when STRICT_CLOUD_HEAVY_BLOCK is OFF
        # (admin disabled strict mode), the POST endpoint runs INLINE
        # on the cloud (require_local_mode short-circuits at line ~687).
        # In that case the job lives in the CLOUD's
        # real_user_traffic_jobs collection, NOT the desktop's. Bridging
        # the polling GETs to the desktop would return an empty list /
        # 404 "Job not found" because the desktop never created the job.
        # When strict is OFF we MUST serve polling GETs from the cloud
        # directly so the user can see their jobs. This also covers the
        # case where the customer's desktop is on a stale version
        # (v2.1.4) that doesn't know how to run modern v2.1.62 RUT prep.
        # Visual Recorder is unaffected — it always bridges to desktop
        # because chromium can only run there.
        if is_rut_job:
            try:
                _strict_now = await get_effective_strict_heavy_block()
            except Exception:
                _strict_now = STRICT_CLOUD_HEAVY_BLOCK
            if not _strict_now:
                return await call_next(request)
        # Resolve user from header OR ?t= query param (screenshot uses
        # ?t= so <img src> can load without a custom fetch).
        token_str = None
        auth_header = request.headers.get("Authorization") or ""
        if auth_header.startswith("Bearer "):
            token_str = auth_header.split(" ", 1)[1]
        else:
            token_str = request.query_params.get("t")
        if not token_str:
            return await call_next(request)
        try:
            jwt_payload = jwt.decode(token_str, SECRET_KEY, algorithms=[ALGORITHM])
            email = jwt_payload.get("sub")
        except Exception:  # noqa: BLE001
            return await call_next(request)
        if not email:
            return await call_next(request)
        user_doc = await db.users.find_one({"email": email}, {"_id": 0, "id": 1, "email": 1})
        if not user_doc:
            return await call_next(request)
        uid = user_doc["id"]
        if is_user_local_online is None or enqueue_bridge_job is None:
            return await call_next(request)
        local_status = await is_user_local_online(uid)
        if not local_status.get("online"):
            return await call_next(request)

        # ── v2.1.73 — Cloud-side cache for slow desktop bridges ──
        # Read-only GET LIST endpoints (`/jobs` and `/pending-candidates`)
        # on heavy customer DBs (10k+ records) sometimes take >60s on
        # the desktop's local Mongo even with the (user_id, created_at)
        # compound index — typically when the index page has been
        # evicted from RAM. We cache the LAST successful bridge response
        # per (user_id, path, query) for 30 s fresh + 5 min stale.
        # Behaviour:
        #   • Cache hit (< 30 s old) → instant return, NO bridge fire
        #   • Bridge succeeds (200)  → refresh cache, return live data
        #   • Bridge times out (202) → return STALE cache (if < 5 min)
        #     so the user sees their data instead of "Loading…" forever
        # Only `GET` requests for the two safe LIST endpoints are cached
        # to avoid masking action results (start/cancel/stream).
        _cache_eligible = (
            request.method.upper() == "GET"
            and (
                path.rstrip("/") == "/api/real-user-traffic/jobs"
                or path.rstrip("/") == "/api/real-user-traffic/jobs/pending-candidates"
            )
        )
        _cache_key = None
        if _cache_eligible:
            try:
                import hashlib as _h
                import json as _j
                _qs = _j.dumps(sorted(dict(request.query_params).items()), separators=(",", ":"))
                _cache_key = f"{uid}:{path}:{_h.md5(_qs.encode()).hexdigest()[:12]}"
                # FRESH hit (< 30 s) — return without bridging
                _now_utc = datetime.now(timezone.utc)
                _hit = await db.bridge_response_cache.find_one(
                    {"_id": _cache_key, "fresh_until": {"$gt": _now_utc}},
                    {"body": 1, "status_code": 1, "_id": 0},
                )
                if _hit and isinstance(_hit.get("body"), dict):
                    from fastapi.responses import JSONResponse as _JRcached
                    logger.debug(f"[bridge-cache] HIT fresh {_cache_key[:30]}")
                    return _JRcached(
                        status_code=int(_hit.get("status_code") or 200),
                        content={**_hit["body"], "_cache": "fresh"},
                    )
            except Exception as _ce:
                logger.debug(f"[bridge-cache] fresh-lookup err: {_ce}")
                _cache_key = None
        # ── end v2.1.73 cache fresh-check ──

        # Capture body + content-type + auth for faithful replay.
        import base64 as _b64
        try:
            raw_body = await request.body()
        except Exception:  # noqa: BLE001
            raw_body = b""
        content_type = request.headers.get("content-type", "")
        body_json: dict = {}
        if "application/json" in content_type.lower() and raw_body:
            try:
                import json as _json
                body_json = _json.loads(raw_body.decode("utf-8") or "{}")
                if not isinstance(body_json, dict):
                    body_json = {}
            except Exception:  # noqa: BLE001
                body_json = {}
        feature = path
        if feature.startswith("/api/"):
            feature = feature[5:]
        payload = {
            "method": request.method.upper(),
            "path": path,
            "body": body_json,
            "query": dict(request.query_params),
            "raw_body_b64": _b64.b64encode(raw_body).decode("ascii") if raw_body else "",
            "content_type": content_type,
            "authorization": auth_header if auth_header else f"Bearer {token_str}",
        }
        logger.info(
            f"[vr-bridge] {request.method} {path} → user={uid[:8]} bridging to desktop"
        )
        # Visual Recorder operations are usually quick (<2s) but allow
        # up to 30s for the chromium spin-up call inside the session.
        # v2.1.72: bump 35s → 60s. Customers with large
        # real_user_traffic_jobs collections (10k+ records) need a bit
        # more headroom for the desktop's local Mongo sort to complete
        # before the cloud middleware gives up and returns queued. The
        # added index on (user_id, created_at) makes 99% of queries
        # finish in <2s anyway — this is just a safety buffer for the
        # remaining cold-cache slow tail.
        bridge_resp = await enqueue_bridge_job(
            {"id": uid, "email": user_doc.get("email")},
            feature,
            payload,
            wait_for_result=True,
            wait_timeout=60,
        )
        from fastapi.responses import JSONResponse as _JR, Response as _Resp
        if not bridge_resp:
            return _JR(status_code=502, content={"error": "bridge_no_response"})
        status_s = bridge_resp.get("status")
        if status_s == "done":
            result = bridge_resp.get("result") or {}
            sc = int(result.get("status") or 200)
            body_back = result.get("body")
            # If the desktop returned an image (screenshot endpoint),
            # it serialised text body of bytes. Detect & forward.
            # Heuristic: body is a dict with {"text": "<jpeg-bytes-decoded>"}
            # when sync_client couldn't json-parse. In that case re-encode
            # as image/jpeg. For the normal JSON path, just pass through.
            if isinstance(body_back, dict) and "__binary_b64__" in body_back:
                # Desktop returned non-JSON content (image/jpeg from
                # /screenshot, video bytes from /export, etc.). Decode
                # the b64 and forward as the original media type so
                # <img src> tags load identically to direct-cloud
                # serving.
                import base64 as _b64dec
                try:
                    raw_bytes = _b64dec.b64decode(body_back["__binary_b64__"])
                except Exception:  # noqa: BLE001
                    return _JR(status_code=502, content={"error": "binary_decode_failed"})
                return _Resp(
                    content=raw_bytes,
                    media_type=body_back.get("__content_type__", "application/octet-stream"),
                    status_code=sc,
                    headers={"Cache-Control": "no-store"},
                )
            # v2.1.73 — populate cache on successful bridge response so
            # subsequent calls (within 30 s fresh / 5 min stale) skip the
            # slow desktop roundtrip.
            if (
                _cache_eligible
                and _cache_key
                and 200 <= sc < 300
                and isinstance(body_back, dict)
            ):
                try:
                    _now_utc = datetime.now(timezone.utc)
                    await db.bridge_response_cache.update_one(
                        {"_id": _cache_key},
                        {
                            "$set": {
                                "body": body_back,
                                "status_code": sc,
                                "fresh_until": _now_utc + timedelta(seconds=30),
                                "stale_until": _now_utc + timedelta(seconds=300),
                                "updated_at": _now_utc,
                                "user_id": uid,
                                "path": path,
                            }
                        },
                        upsert=True,
                    )
                except Exception as _wc:
                    logger.debug(f"[bridge-cache] write err: {_wc}")
            return _JR(status_code=sc, content=body_back if body_back is not None else {"ok": True, "via": "bridge"})
        if status_s == "failed":
            return _JR(status_code=500, content={"error": "bridge_execution_failed", "reason": bridge_resp.get("error")})
        # ── v2.1.73 — Stale-cache fallback when bridge times out ──
        # Bridge took longer than 60 s. Instead of returning a useless
        # {queued:true} placeholder that the frontend then has to retry,
        # serve the LAST successful response for this user+path if it
        # is < 5 min old. UX win: user sees their (slightly stale) jobs
        # list immediately. Cache miss → still return queued (existing
        # behaviour).
        if _cache_eligible and _cache_key:
            try:
                _now_utc = datetime.now(timezone.utc)
                _stale = await db.bridge_response_cache.find_one(
                    {"_id": _cache_key, "stale_until": {"$gt": _now_utc}},
                    {"body": 1, "status_code": 1, "fresh_until": 1, "_id": 0},
                )
                if _stale and isinstance(_stale.get("body"), dict):
                    logger.info(
                        f"[bridge-cache] STALE fallback {_cache_key[:30]} "
                        f"(bridge timeout — serving cached)"
                    )
                    return _JR(
                        status_code=int(_stale.get("status_code") or 200),
                        content={**_stale["body"], "_cache": "stale"},
                    )
            except Exception as _se:
                logger.debug(f"[bridge-cache] stale-lookup err: {_se}")
        # ── end v2.1.73 stale-cache fallback ──
        # pending after 60s with no cache → original behaviour
        return _JR(
            status_code=202,
            content={
                "queued": True,
                "via": "bridge",
                "job_id": bridge_resp.get("job_id"),
                "state": "starting",
                "message": "Bridged to your PC, still running",
            },
        )
    except Exception as _vrm_err:  # noqa: BLE001
        logger.warning(f"[vr-bridge] middleware error: {_vrm_err}; falling through")
        return await call_next(request)




# ──────────────────────────────────────────────────────────────────────
# /api/diagnostics — instant-visibility health endpoint
# ──────────────────────────────────────────────────────────────────────
# Surfaces the exact health of every moving piece in one HTTP call so the
# user can see at a glance whether their environment is the bottleneck.
# Public (no auth) so it works even if Mongo/JWT is broken — production
# should put this behind Cloudflare Access if the host is internet-facing.
# Registered directly on `app` (not the api_router) because it's defined
# AFTER `app.include_router(api_router)` and we want it picked up without
# re-ordering the file.

@app.get("/api/diagnostics/health")
async def diagnostics_health():
    """Single-shot health snapshot. Returns a JSON object with one entry
    per subsystem: status (ok|warn|fail), value, hint. Frontend can render
    this as a coloured grid; humans can curl it for quick triage."""
    import os as _os
    import shutil as _sh
    import platform as _plat
    out: Dict[str, Any] = {
        "checked_at": datetime.now(timezone.utc).isoformat(),
        "checks": {},
    }

    # 1. MongoDB
    try:
        await asyncio.wait_for(db.command("ping"), timeout=3.0)
        out["checks"]["mongodb"] = {"status": "ok", "value": "ping OK"}
    except Exception as e:
        out["checks"]["mongodb"] = {"status": "fail", "value": str(e)[:120],
                                     "hint": "Mongo container unreachable. `docker compose ps mongo`."}

    # 2. Playwright chromium
    try:
        from real_user_traffic import get_engine_status
        info = get_engine_status()
        out["checks"]["playwright"] = {
            "status": "ok" if info.get("status") == "ready" else "warn",
            "value": f"rev {info.get('expected_revision','?')} {info.get('status','?')}",
            "hint": "First RUT job will trigger background install (~60s) if not ready."
                    if info.get("status") != "ready" else "",
        }
    except Exception as e:
        out["checks"]["playwright"] = {"status": "fail", "value": str(e)[:120]}

    # 3. Google Sheets SA
    try:
        import gsheet_writer
        enabled = gsheet_writer.is_write_enabled()
        out["checks"]["gsheet_sa"] = {
            "status": "ok" if enabled else "warn",
            "value": "write_enabled" if enabled else "read-only (SA missing)",
            "hint": "" if enabled else (
                "Drop a Service Account JSON at /app/backend/secrets/gsheets-sa.json "
                "and set GOOGLE_SHEETS_SA_PATH in .env. Live row-delete won't work "
                "until enabled."
            ),
        }
    except Exception as e:
        out["checks"]["gsheet_sa"] = {"status": "fail", "value": str(e)[:120]}

    # 4. Memory headroom — backend RSS as % of mem_limit (ZERO-OOM throttle)
    try:
        pct = _backend_rss_pct()
        rss_mb = _psutil.Process().memory_info().rss / (1024 * 1024)
        is_throttled = _MEM_THROTTLED_AT is not None
        # Where did the cap come from? Helps debugging when the user is
        # unsure whether the throttle is using their docker-compose limit
        # or the env-var override or the safe 6 GB fallback.
        if "RUT_MEM_LIMIT_MB" in _os.environ:
            cap_source = "env"
        elif _default_cap_mb == 6144:
            # Neither cgroup nor psutil produced a value — pure fallback
            cap_source = "default 6 GB"
        elif os.path.exists("/sys/fs/cgroup/memory.max") or os.path.exists("/sys/fs/cgroup/memory/memory.limit_in_bytes"):
            cap_source = "auto (cgroup)"
        else:
            # Native install — value derived from psutil.virtual_memory()
            cap_source = "auto (psutil — native install)"
        if is_throttled:
            status = "warn"
            hint = (
                f"Memory throttle ACTIVE — pausing new visit dispatch until RSS "
                f"drops below {_RUT_MEM_RESUME_PCT}%. In-flight visits keep running."
            )
        elif pct < 70:
            status = "ok"
            hint = ""
        elif pct < _RUT_MEM_THROTTLE_PCT:
            status = "warn"
            hint = f"Approaching throttle threshold ({_RUT_MEM_THROTTLE_PCT}%)."
        else:
            status = "warn"
            hint = "RSS at or above throttle threshold — new visits paused."
        out["checks"]["memory"] = {
            "status": status,
            "value": (
                f"RSS {rss_mb:.0f} MB ({pct:.0f}% of {_RUT_MEM_LIMIT_MB} MB cap · {cap_source})"
                + (" · THROTTLED" if is_throttled else "")
            ),
            "hint": hint,
        }
    except Exception as e:
        out["checks"]["memory"] = {"status": "warn", "value": str(e)[:120]}

    # 5. Disk space (results / uploads)
    try:
        free, _, _ = _sh.disk_usage("/app/backend"), 0, 0
        # Re-call properly — _sh.disk_usage returns (total, used, free)
        usage = _sh.disk_usage("/app/backend")
        free_gb = usage.free / (1024**3)
        status = "ok" if free_gb > 5 else "warn" if free_gb > 1 else "fail"
        out["checks"]["disk"] = {
            "status": status,
            "value": f"{free_gb:.1f} GB free on /app",
            "hint": "Old RUT result ZIPs eat disk. Delete old jobs from Past Jobs."
                    if status != "ok" else "",
        }
    except Exception as e:
        out["checks"]["disk"] = {"status": "warn", "value": str(e)[:120]}

    # 6. Active RUT jobs in this worker
    try:
        from real_user_traffic import RUT_JOBS as _RJ
        active = [j for j in _RJ.values() if j.get("status") in ("running", "queued")]
        out["checks"]["active_rut_jobs"] = {
            "status": "ok",
            "value": f"{len(active)} active in this worker",
            "hint": "Multi-worker: jobs may run on a different worker — check `docker exec krexion-backend python3 -c 'from pymongo import MongoClient; c=MongoClient(...); print(c[\"krexion\"][\"real_user_traffic_jobs\"].count_documents({\"status\":\"running\"}))'`"
                    if len(active) == 0 else "",
        }
    except Exception as e:
        out["checks"]["active_rut_jobs"] = {"status": "warn", "value": str(e)[:120]}

    # 7. Process info
    out["checks"]["process"] = {
        "status": "ok",
        "value": f"pid={_os.getpid()} python={_plat.python_version()} platform={_plat.system()} {_plat.release()}",
    }

    # Roll up overall status
    statuses = [c.get("status") for c in out["checks"].values()]
    if "fail" in statuses:
        out["overall"] = "fail"
    elif "warn" in statuses:
        out["overall"] = "warn"
    else:
        out["overall"] = "ok"
    return out


# ──────────────────────────────────────────────────────────────────────
# /api/diagnostics/hardware-profile  —  detected tier + applied tuning
# ──────────────────────────────────────────────────────────────────────
# Returns the SAME tier that the installer (scripts/detect-hardware.*)
# uses to pick the docker-compose override. The frontend Settings page
# renders this so the user can see *why* RUT concurrency is capped at N.
#
# Tiers:
#   MICRO  RAM <= 6 GB   -> 1 RUT worker
#   LOW    7-10 GB       -> 2 RUT workers
#   MID    11-16 GB      -> 4 RUT workers
#   HIGH   17-32 GB      -> 8 RUT workers
#   BEAST  > 32 GB       -> 16 RUT workers
#
# CPU cores act as a HARD ceiling: actual = min(tier, cores*2)
# ──────────────────────────────────────────────────────────────────────
@app.get("/api/diagnostics/hardware-profile")
async def diagnostics_hardware_profile():
    """Detect the host machine's RAM + CPU and report the chosen
    performance tier + actual applied tuning (RUT concurrency, mem cap, etc.).
    Public endpoint — no auth required (no sensitive data exposed)."""
    import os as _os
    try:
        import psutil as _ps
        total_ram_gb = round(_ps.virtual_memory().total / (1024 ** 3))
        cpu_cores = _ps.cpu_count(logical=True) or _os.cpu_count() or 1
    except Exception:
        total_ram_gb = 0
        cpu_cores = _os.cpu_count() or 1

    if   total_ram_gb <= 6:   tier, rut, mongo, be, fe, wsl = "MICRO", 1,  "512m",  "1536m", "128m", "4GB"
    elif total_ram_gb <= 10:  tier, rut, mongo, be, fe, wsl = "LOW",   2,  "1g",    "2560m", "192m", "5GB"
    elif total_ram_gb <= 16:  tier, rut, mongo, be, fe, wsl = "MID",   4,  "2g",    "4g",    "256m", "10GB"
    elif total_ram_gb <= 32:  tier, rut, mongo, be, fe, wsl = "HIGH",  8,  "4g",    "8g",    "384m", "20GB"
    else:                     tier, rut, mongo, be, fe, wsl = "BEAST", 16, "8g",    "16g",   "512m", "32GB"

    # CPU ceiling
    cpu_ceiling = max(1, cpu_cores * 2)
    if rut > cpu_ceiling:
        rut = cpu_ceiling

    # What concurrency is actually enforced *right now* by the backend env?
    env_concurrency = _os.environ.get("RUT_MAX_CONCURRENCY")
    actual_concurrency = int(env_concurrency) if env_concurrency and env_concurrency.isdigit() else rut

    compose_override = {
        "MICRO": "docker-compose.micro.yml",
        "LOW":   "docker-compose.lowram.yml",
        "MID":   "docker-compose.mid.yml",
        "HIGH":  "docker-compose.high.yml",
        "BEAST": "docker-compose.beast.yml",
    }[tier]

    return {
        "detected": {
            "total_ram_gb": total_ram_gb,
            "cpu_cores": cpu_cores,
            "platform": _os.uname().sysname if hasattr(_os, "uname") else "Windows",
        },
        "recommended_tier": tier,
        "recommended_settings": {
            "rut_concurrency": rut,
            "mongo_mem_limit": mongo,
            "backend_mem_limit": be,
            "frontend_mem_limit": fe,
            "wsl_memory": wsl,
            "compose_override": compose_override,
        },
        "applied": {
            "rut_concurrency": actual_concurrency,
            "rut_mem_limit_mb": _os.environ.get("RUT_MEM_LIMIT_MB"),
            "matches_recommendation": actual_concurrency == rut,
        },
        "hint": (
            "Run Krexion-RETUNE.bat (Windows) or sudo bash Krexion-RETUNE.sh "
            "(Linux/macOS) to apply the recommended tier."
            if actual_concurrency != rut
            else "Backend is already running with the recommended tuning."
        ),
    }


# ──────────────────────────────────────────────────────────────────────
# /api/diagnostics/repair  —  one-click auto-fix for common health issues
# ──────────────────────────────────────────────────────────────────────
# Surfaced in the new "System Health" page as the green "Auto Repair"
# button. The user clicks it and we attempt to fix every subsystem that
# reported `warn` or `fail` in /diagnostics/health. We never silently
# touch user data — only stateless infra (caches, browser binaries,
# old result archives).
#
# Auth: requires a valid logged-in user (NOT admin-only — every owner
# should be able to self-heal their stack before launching a job).
# ──────────────────────────────────────────────────────────────────────
@app.post("/api/diagnostics/repair")
async def diagnostics_repair(current_user: dict = Depends(get_current_user)):
    """Best-effort self-repair. Returns a per-action result list."""
    import gc as _gc
    import shutil as _sh
    actions: List[Dict[str, Any]] = []

    # 1. Memory pressure → force GC + clear in-process caches
    try:
        before_mb = _psutil.Process().memory_info().rss / (1024 * 1024)
        # Clear duplicate-IP cache (rebuilt lazily on next RUT job)
        try:
            global _DUP_IP_CACHE
            _DUP_IP_CACHE = None  # type: ignore[name-defined]
        except Exception:
            pass
        # Drop any cached gsheet refresh state — forces fresh fetch on
        # next /api/uploads call.
        try:
            await db.uploaded_resources.update_many(
                {"gsheet_url": {"$exists": True, "$ne": ""}},
                {"$unset": {"last_synced_at": ""}},
            )
        except Exception:
            pass
        # Run two GC passes — first frees most cycles, second cleans up
        # weakrefs the first pass produced.
        _gc.collect()
        _gc.collect()
        # If we were throttled, attempt to clear the flag (it'll re-set
        # itself on next throttle-check if RSS is still high).
        global _MEM_THROTTLED_AT
        was_throttled = _MEM_THROTTLED_AT is not None
        _MEM_THROTTLED_AT = None
        after_mb = _psutil.Process().memory_info().rss / (1024 * 1024)
        actions.append({
            "name": "memory",
            "status": "ok",
            "detail": (
                f"Cleared dup-IP cache + gsheet sync state, ran GC. "
                f"RSS {before_mb:.0f} → {after_mb:.0f} MB"
                + (" (throttle reset)" if was_throttled else "")
            ),
        })
    except Exception as e:
        actions.append({"name": "memory", "status": "fail", "detail": str(e)[:200]})

    # 2. Playwright chromium-headless-shell → ensure binary is present
    try:
        rev_path = Path("/root/.cache/ms-playwright/chromium-headless-shell-1148")
        if rev_path.exists() and rev_path.is_dir():
            actions.append({
                "name": "playwright",
                "status": "ok",
                "detail": f"chromium-headless-shell already installed at {rev_path}",
            })
        else:
            # Fire the existing installer in a background thread so the
            # request returns fast.
            # v2.1.18 — use sys.executable -m playwright (Windows-safe).
            import subprocess, sys as _sys
            proc = await asyncio.create_subprocess_exec(
                _sys.executable, "-m", "playwright", "install", "chromium-headless-shell",
                stdout=subprocess.PIPE, stderr=subprocess.PIPE,
            )
            try:
                await asyncio.wait_for(proc.communicate(), timeout=120)
                actions.append({
                    "name": "playwright",
                    "status": "ok" if proc.returncode == 0 else "fail",
                    "detail": (
                        "Re-installed chromium-headless-shell"
                        if proc.returncode == 0
                        else f"playwright install exited rc={proc.returncode}"
                    ),
                })
            except asyncio.TimeoutError:
                proc.kill()
                actions.append({
                    "name": "playwright",
                    "status": "fail",
                    "detail": "playwright install timed out after 120 s",
                })
    except Exception as e:
        actions.append({"name": "playwright", "status": "fail", "detail": str(e)[:200]})

    # 3. Disk → archive RUT job ZIPs older than 30 days
    try:
        cutoff = datetime.now(timezone.utc) - timedelta(days=30)
        deleted_count = 0
        deleted_bytes = 0
        results_root = Path("/tmp/rut_results")
        if results_root.exists():
            for p in results_root.glob("**/*.zip"):
                try:
                    mtime = datetime.fromtimestamp(p.stat().st_mtime, tz=timezone.utc)
                    if mtime < cutoff:
                        sz = p.stat().st_size
                        p.unlink()
                        deleted_count += 1
                        deleted_bytes += sz
                except Exception:
                    pass
        usage = _sh.disk_usage("/")
        free_gb = usage.free / (1024**3)
        actions.append({
            "name": "disk",
            "status": "ok",
            "detail": (
                f"Archived {deleted_count} old result ZIPs "
                f"({deleted_bytes/1024/1024:.1f} MB freed). "
                f"{free_gb:.1f} GB free now."
            ),
        })
    except Exception as e:
        actions.append({"name": "disk", "status": "fail", "detail": str(e)[:200]})

    # 4. MongoDB → simple ping/reconnect verification (real reconnects
    # happen automatically via motor — we just confirm the link is alive)
    try:
        await asyncio.wait_for(db.command("ping"), timeout=5.0)
        actions.append({
            "name": "mongodb",
            "status": "ok",
            "detail": "Mongo ping OK — connection healthy",
        })
    except Exception as e:
        actions.append({
            "name": "mongodb",
            "status": "fail",
            "detail": (
                f"Mongo unreachable: {str(e)[:150]}. Restart the krexion-mongo "
                "container manually via Docker Desktop."
            ),
        })

    # 5. Stuck-RUT-jobs sweep — flip jobs in `running` for >2 hours with no
    # heartbeat to `stopped` so the user can retry them. Mostly cosmetic
    # since the auto-resume reaper handles real restarts, but this catches
    # truly orphaned ones.
    try:
        cutoff_iso = (datetime.now(timezone.utc) - timedelta(hours=2)).isoformat()
        res = await db.real_user_traffic_jobs.update_many(
            {
                "status": "running",
                "$or": [
                    {"last_progress_at": {"$lt": cutoff_iso}},
                    {"last_progress_at": {"$exists": False}, "started_at": {"$lt": cutoff_iso}},
                ],
            },
            {
                "$set": {
                    "status": "stopped",
                    "stop_reason": "Stuck >2 h without progress — auto-cleared via System Health repair.",
                    "finished_at": datetime.now(timezone.utc).isoformat(),
                }
            },
        )
        actions.append({
            "name": "active_rut_jobs",
            "status": "ok",
            "detail": f"Cleared {res.modified_count} stuck job(s) (>2 h no progress)",
        })
    except Exception as e:
        actions.append({"name": "active_rut_jobs", "status": "fail", "detail": str(e)[:200]})

    ok_count = sum(1 for a in actions if a["status"] == "ok")
    fail_count = sum(1 for a in actions if a["status"] == "fail")
    return {
        "repaired_at": datetime.now(timezone.utc).isoformat(),
        "ok_count": ok_count,
        "fail_count": fail_count,
        "actions": actions,
    }


@app.on_event("startup")
async def startup_db_indexes():
    """Create database indexes for faster queries - OPTIMIZED FOR HIGH TRAFFIC"""
    try:
        # Clicks collection indexes for fast duplicate IP checking
        await db.clicks.create_index([("link_id", 1), ("created_at", -1)])
        await db.clicks.create_index([("created_at", -1)])
        await db.clicks.create_index([("ip_address", 1)])
        await db.clicks.create_index([("ipv4", 1)])
        await db.clicks.create_index([("ipv6", 1)])
        await db.clicks.create_index([("click_id", 1)], unique=True)
        # Compound index for fast duplicate checking
        await db.clicks.create_index([("ip_address", 1), ("created_at", -1)])
        
        # Links collection indexes - short_code is critical for redirects
        await db.links.create_index([("user_id", 1)])
        await db.links.create_index([("short_code", 1)], unique=True)
        
        # Users collection indexes
        await db.users.create_index([("email", 1)], unique=True)
        await db.users.create_index([("id", 1)], unique=True)
        
        # Sub-users collection indexes
        await db.sub_users.create_index([("parent_user_id", 1)])
        await db.sub_users.create_index([("email", 1)], unique=True)
        
        # Proxies collection indexes
        await db.proxies.create_index([("user_id", 1), ("status", 1)])
        await db.proxies.create_index([("proxy_ip", 1)])

        # Real-user-traffic jobs — hottest collection, polled by every
        # open RealUserTrafficPage tab + admin dashboard. Without these
        # indexes, every list call full-scans a growing collection.
        await db.real_user_traffic_jobs.create_index([("user_id", 1), ("created_at", -1)])
        await db.real_user_traffic_jobs.create_index([("job_id", 1)], unique=True)
        await db.real_user_traffic_jobs.create_index([("status", 1)])
        await db.real_user_traffic_jobs.create_index([("status", 1), ("user_id", 1)])
        # Compound for the recovery-poll branch (after-network-abort)
        await db.real_user_traffic_jobs.create_index([("user_id", 1), ("link_id", 1), ("created_at", -1)])

        # ── ProxyJet auto-mode collections (one-time setup, idempotent) ──
        try:
            await _pj.ensure_indexes(db)
        except Exception as _pj_err:
            logger.warning(f"ProxyJet index init skipped: {_pj_err}")

        logger.info("Database indexes created successfully")
    except Exception as e:
        logger.error(f"Error creating indexes: {e}")

    # Kick off the UA-versions auto-refresh background task
    try:
        asyncio.create_task(_auto_refresh_ua_versions_task())
        logger.info("UA versions auto-refresh task scheduled (runs on startup + every 24h)")
    except Exception as e:
        logger.warning(f"Could not schedule UA versions auto-refresh: {e}")

    # ── License heartbeat (this locally-installed app phones home to
    # the central license server every 6 h to confirm subscription is
    # still active). If LICENSE_KEY is empty the check is skipped.
    async def _license_heartbeat_task():
        import httpx as _httpx
        # 2026-02 — accept LICENSE_KEY from either:
        #   1. env var (legacy Docker .env injection)
        #   2. LICENSE_KEY_FILE path (new white-label installer writes
        #      %PROGRAMDATA%\Krexion\license-key.txt during install)
        key = os.environ.get("LICENSE_KEY", "").strip()
        if not key:
            key_file = os.environ.get("LICENSE_KEY_FILE", "").strip()
            if key_file and os.path.isfile(key_file):
                try:
                    with open(key_file, "r", encoding="utf-8") as _f:
                        # Tolerate either a bare key on the first non-
                        # comment line, or a multi-line `# header\nKRX-..`
                        # file written by the installer's Inno Setup
                        # GetLicenseKey hook.
                        for _line in _f:
                            _line = _line.strip()
                            if _line and not _line.startswith("#"):
                                key = _line.upper()
                                # Inject for downstream code that still
                                # reads os.environ["LICENSE_KEY"]
                                os.environ["LICENSE_KEY"] = key
                                break
                except Exception as _exc:  # noqa: BLE001
                    logger.warning(f"Could not read LICENSE_KEY_FILE: {_exc}")
        server = os.environ.get("LICENSE_SERVER_URL", "").rstrip("/")
        if not key or not server:
            logger.info("License heartbeat: skipped (no LICENSE_KEY/LICENSE_SERVER_URL set)")
            return
        # Same machine_id format the installer used
        try:
            import platform as _plat
            machine_id = f"WIN-{_plat.node()}"
        except Exception:  # noqa: BLE001
            machine_id = "GUID-" + uuid.uuid4().hex
        while True:
            try:
                async with _httpx.AsyncClient(timeout=20.0) as cx:
                    r = await cx.post(
                        f"{server}/api/license/validate",
                        json={"license_key": key, "machine_id": machine_id},
                    )
                    if r.status_code == 200:
                        data = r.json()
                        logger.info(f"License heartbeat: ok={data.get('ok')} status={data.get('status')}")
                    else:
                        logger.warning(f"License heartbeat returned {r.status_code}: {r.text[:120]}")
            except Exception as e:  # noqa: BLE001
                logger.warning(f"License heartbeat failed (offline?): {e}")
            await asyncio.sleep(6 * 3600)

    try:
        asyncio.create_task(_license_heartbeat_task())
        logger.info("License heartbeat task scheduled (every 6h)")
    except Exception as e:
        logger.warning(f"Could not start license heartbeat: {e}")

    # Ensure Playwright Chromium (headless-shell) is installed for
    # Real-User-Traffic / Form-Filler. We do a STRICT revision check
    # (reading the exact revision Playwright pins in browsers.json). If
    # the correct binary is already present we skip the install entirely
    # so server boot is instant and users never see an "install in
    # progress" delay on their first job. Only when the binary is truly
    # missing we run the install in a background task.
    #
    # 2026-05 — On the cloud edge (KREXION_MODE=cloud) with strict heavy
    # block enabled (the new default), heavy features (RUT / Form
    # Filler) refuse to execute on the VPS — they're handled by the
    # customer's desktop app via the bridge. So we must NOT waste ~150MB
    # of bandwidth + disk + boot time downloading a Chromium binary the
    # cloud edge will never use. The legacy opt-out
    # (STRICT_CLOUD_HEAVY_BLOCK=false) still installs Chromium so cloud
    # fallback execution keeps working for customers without the desktop
    # app yet.
    async def _ensure_playwright_chromium():
        try:
            from real_user_traffic import _ensure_chromium_available, get_engine_status
            info = get_engine_status()
            if info.get("status") == "ready":
                logger.info(
                    f"Playwright chromium-headless-shell already present "
                    f"(rev {info.get('expected_revision')}) — skipping install."
                )
                return
            logger.warning(
                f"Playwright chromium-headless-shell not ready "
                f"(status={info.get('status')}, rev={info.get('expected_revision')}) "
                f"— installing now in background."
            )
            ok = await _ensure_chromium_available()
            if ok:
                logger.info("Playwright chromium-headless-shell install: OK")
            else:
                logger.warning("Playwright chromium-headless-shell install FAILED")
        except Exception as e:
            logger.warning(f"Playwright install startup hook failed (non-fatal): {e}")

    if IS_CLOUD and STRICT_CLOUD_HEAVY_BLOCK:
        logger.info(
            "Cloud edge with STRICT_CLOUD_HEAVY_BLOCK=true — skipping "
            "Playwright Chromium install on startup. Heavy features run "
            "on customer desktop app, not on VPS."
        )
    else:
        try:
            asyncio.create_task(_ensure_playwright_chromium())
        except Exception as e:
            logger.warning(f"Could not schedule Playwright install check: {e}")

    # Reap orphan Real-User-Traffic jobs whose worker died before they could
    # mark themselves done. Without this, the UI keeps showing a permanent
    # "running" job that can never be stopped (the in-memory entry is gone).
    #
    # IMPORTANT — distinguish between THREE cases:
    #   1. RESUMABLE — `is_resumable` is True AND `processed == 0` AND
    #      `restart_count < 3`. The backend died during prep / before
    #      the engine started a single visit. Re-spawn the BG task.
    #      This is the common case when the user runs KREXION-FORCE-SYNC
    #      while a job was queued — they expect the job to survive.
    #   2. PARTIAL RUN — status was "running" with `processed > 0`.
    #      Genuine partial run; preserve results, mark "stopped" with
    #      a clear stop_reason.
    #   3. NON-RESUMABLE / restart-count exhausted — mark "failed" with
    #      an actionable error_message. Won't auto-retry.
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        orphan_q = {"status": {"$in": ["running", "queued", "preparing"]}}
        # NOTE: projection MUST include every field the resume preload
        # block (Case 1 below) wants to copy back into RUT_JOBS — most
        # importantly `live_steps` (powers "Recent Visits" in the UI),
        # all the per-status counters (succeeded / failed / skipped_*),
        # plus engine state like target_reached + pending_leads_*.
        # Missing one here = silent loss on resume = user sees "Waiting
        # for first visit…" even though processed=20.
        orphan_jobs = await db.real_user_traffic_jobs.find(
            orphan_q, {"_id": 0, "job_id": 1, "user_id": 1, "status": 1, "processed": 1,
                       "total": 1, "preparing": 1, "is_resumable": 1, "submit_params": 1,
                       "target_url": 1, "link_id": 1, "restart_count": 1,
                       "succeeded": 1, "failed": 1,
                       "skipped_captcha": 1, "skipped_country": 1,
                       "skipped_os": 1, "skipped_duplicate_ip": 1, "skipped_vpn": 1,
                       "conversions": 1, "max_attempts": 1,
                       "target_reached": 1, "target_reached_at": 1,
                       "pending_leads_count": 1, "pending_leads_path": 1,
                       "state_match_enabled": 1, "state_match_column": 1,
                       "consume_upload_ids": 1, "consumed_upload_ids_final": 1,
                       "live_steps": 1}
        ).to_list(length=500)
        reaped_running = 0
        reaped_queued = 0
        resumed = 0
        if orphan_jobs:
            for j in orphan_jobs:
                jid = j.get("job_id")
                if not jid:
                    continue
                prev_status = j.get("status")
                processed = int(j.get("processed") or 0)
                rc = int(j.get("restart_count") or 0)

                # ─── Case 1: RESUMABLE — ANY job (mid-run or not yet started) ─
                # If the original submit params are persisted and the
                # restart-counter is under the cap, re-spawn the prep + run
                # so the job continues automatically. This applies to:
                #   • status="queued" / "preparing" — never started visits;
                #     resume is loss-less.
                #   • status="running" with processed > 0 — partial run.
                #     Live-removed proxies / UAs / gsheet rows are already
                #     gone from the source uploads (no duplicates). For
                #     static Excel form-fill data, a few rows may be
                #     reprocessed which is acceptable — better than the
                #     user finding the job dead and having to re-submit.
                #
                # IMPORTANT: `restart_count` is RESET to 0 in
                # `_rut_prepare_and_run` immediately after prep finishes
                # (see the "PREP-SUCCESS rc-RESET" block). That means
                # any job that ever got past prep starts the next
                # restart with rc=0 → unlimited resume budget across
                # the lifetime of a healthy job. Only crash-loops
                # entirely INSIDE prep accumulate rc and eventually
                # exhaust the cap below — exactly the scenario where
                # giving up is correct (something is genuinely broken
                # with the inputs).
                #
                # Cap bumped from 10 → 100. Combined with the
                # exponential backoff between resumes, this gives the
                # job ~1 hour of crash-loop cushion before we give up.
                #
                # 2026-05 — On the cloud edge (KREXION_MODE=cloud) with
                # STRICT_CLOUD_HEAVY_BLOCK=true (the new default), heavy
                # RUT work must NOT execute on the VPS — the customer's
                # desktop app handles it via the bridge. So we skip the
                # in-process auto-resume entirely and just leave the job
                # in `queued` status (with a clear prep_step) so the
                # customer's bridge worker picks it up on next poll.
                # Without this gate, every VPS restart would re-launch
                # Playwright/Chromium on the cloud for every queued RUT
                # job — the exact overload scenario STRICT mode exists
                # to prevent.
                if IS_CLOUD and STRICT_CLOUD_HEAVY_BLOCK:
                    try:
                        await db.real_user_traffic_jobs.update_one(
                            {"job_id": jid},
                            {"$set": {
                                "status": "queued",
                                "preparing": True,
                                "prep_step": (
                                    "Waiting for your desktop app to pick up "
                                    "this job (heavy work runs on your PC, "
                                    "not on the cloud)…"
                                ),
                                "prep_step_at": now_iso,
                            }},
                        )
                    except Exception:
                        pass
                    logger.info(
                        f"[cloud-strict] Skipped auto-resume of RUT job {jid} "
                        f"(user={j['user_id'][:8]}) — will be handled by "
                        f"customer's desktop bridge worker."
                    )
                    continue
                if j.get("is_resumable") and j.get("submit_params") and rc < 100:
                    # Exponential backoff between auto-resume attempts:
                    # rc=0 → 0 s, rc=1 → 2 s, rc=2 → 4 s, rc=3 → 8 s,
                    # capped at 30 s. Stops the backend from burning
                    # through the 100-attempt budget in a tight crash
                    # loop while still recovering quickly from a single
                    # transient OOM/restart.
                    backoff = min(30, 2 ** rc) if rc > 0 else 0
                    # Re-fetch user + link from DB and re-schedule the
                    # BG task. Done in a fire-and-forget asyncio.task so
                    # the rest of startup isn't blocked by N concurrent
                    # gsheet fetches.
                    try:
                        user_doc = await db.users.find_one(
                            {"id": j["user_id"]}, {"_id": 0}
                        )
                        link_doc = None
                        if j.get("link_id"):
                            link_doc = await db.links.find_one(
                                {"id": j["link_id"]}, {"_id": 0}
                            )
                        if not user_doc or not link_doc:
                            raise RuntimeError("user or link record missing — original may have been deleted")
                        prev_processed = processed
                        # Decide what status to write: if the previous
                        # run had ANY processed visits, we keep it as
                        # `running` so the UI doesn't visibly bounce
                        # back to "Preparing" (which would make the
                        # user think the job restarted from scratch).
                        # Only jobs that died BEFORE their first visit
                        # ran flip to `preparing` — those genuinely
                        # need to be re-prepped from zero.
                        resume_status = "running" if prev_processed > 0 else "preparing"
                        await db.real_user_traffic_jobs.update_one(
                            {"job_id": jid},
                            {"$set": {
                                "status": resume_status,
                                "restart_count": rc + 1,
                                "last_resume_at": now_iso,
                                "preparing": prev_processed == 0,
                                # Reset live counters so the engine starts
                                # fresh; previous results stay packaged
                                # in the per-job results folder on disk.
                                "resumed_from_processed": prev_processed,
                                # Soft hint shown in the existing
                                # "Preparing: ..." banner — prevents
                                # the user from feeling the job is
                                # restarting from scratch.
                                "prep_step": (
                                    f"Reloading state after restart "
                                    f"(visit #{prev_processed} already done)…"
                                    if prev_processed > 0
                                    else "Resuming queued job…"
                                ),
                                "prep_step_at": now_iso,
                            }},
                        )
                        # CRITICAL — re-create the in-memory RUT_JOBS
                        # entry BEFORE the BG task fires. Without this,
                        # any code inside _rut_prepare_and_run that does
                        # `RUT_JOBS[job_id][...]` raises KeyError(job_id),
                        # which surfaces to the user as the cryptic
                        # "Prep/run crashed: '<uuid>'" error.
                        try:
                            create_rut_job(
                                job_id=jid,
                                user_id=j["user_id"],
                                target_url=j.get("target_url") or "",
                                total=int(j.get("total") or 0),
                                form_fill_enabled=bool(j.get("form_fill_enabled")),
                            )
                            # PRELOAD all the previously-progressed
                            # counters from DB so the UI doesn't briefly
                            # bounce to 0/100 during resume. The next
                            # progress increment continues from the
                            # current values seamlessly.
                            #
                            # 2026-01 EXPANDED: also restore `live_steps`
                            # (the ring-buffer that powers "Recent
                            # Visits" + Live Activity dialog) plus the
                            # other engine-side state fields that
                            # `_persist()` saves on every progress tick.
                            # Without live_steps preload, the UI would
                            # show "Waiting for first visit…" after
                            # resume even though processed=20 — which is
                            # exactly the 0-from-scratch symptom the
                            # user reported.
                            try:
                                from real_user_traffic import RUT_JOBS as _RJ
                                if jid in _RJ:
                                    # Counters + conversion totals
                                    for fld in (
                                        "processed", "succeeded", "failed",
                                        "skipped_captcha", "skipped_country",
                                        "skipped_os", "skipped_duplicate_ip",
                                        "skipped_vpn", "conversions",
                                        # Engine-side job state
                                        "total", "max_attempts",
                                        "target_reached", "target_reached_at",
                                        "pending_leads_count", "pending_leads_path",
                                        "state_match_enabled", "state_match_column",
                                        "consume_upload_ids",
                                        "consumed_upload_ids_final",
                                        # UI feed — this is the KEY one
                                        # that brings back "Recent Visits"
                                        "live_steps",
                                    ):
                                        if j.get(fld) is not None:
                                            _RJ[jid][fld] = j.get(fld)
                                    # Status starts as `running` for
                                    # jobs that already had visits done
                                    # (matches resume_status above) so
                                    # the live-log status badge doesn't
                                    # flash "queued" momentarily.
                                    _RJ[jid]["status"] = resume_status
                            except Exception:
                                pass
                            # Push a friendly resume marker into the
                            # live-log so the Live Activity dialog and
                            # the Recent Visits list show WHY the job
                            # was paused — instead of the scary "Backend
                            # container restarted" diagnosis.
                            try:
                                from real_user_traffic import push_live_step as _push
                                if prev_processed > 0:
                                    _push(jid, 0, "resume", "info",
                                          f"⟳ Auto-resumed after restart (attempt #{rc + 1}/100"
                                          + (f", waited {backoff}s for backoff" if backoff > 0 else "")
                                          + f") — {prev_processed} already processed, continuing")
                                else:
                                    _push(jid, 0, "resume", "info",
                                          f"⟳ Auto-resumed after restart (attempt #{rc + 1}/100"
                                          + (f", waited {backoff}s for backoff" if backoff > 0 else "")
                                          + ") — job was queued, starting fresh")
                            except Exception:
                                pass
                        except Exception:
                            pass
                        # Schedule via asyncio.create_task — doesn't need
                        # the FastAPI BackgroundTasks (which only works
                        # in a request scope). Wrapper applies the
                        # exponential backoff before invoking prep so we
                        # don't dog-pile a still-recovering Mongo / WSL
                        # right after a crash.
                        async def _resume_with_backoff(_user, _link, _params, _delay):
                            if _delay > 0:
                                await asyncio.sleep(_delay)
                            return await _rut_prepare_and_run(
                                job_id=jid,
                                user=_user,
                                link=_link,
                                target=j.get("target_url") or "",
                                params=_params,
                            )
                        asyncio.create_task(_resume_with_backoff(
                            user_doc, link_doc, j["submit_params"], backoff,
                        ))
                        resumed += 1
                        logger.info(
                            f"Auto-resumed RUT job {jid} (restart #{rc + 1}/100, "
                            f"prev_processed={prev_processed}, backoff={backoff}s) — "
                            f"user={j['user_id'][:8]} target={(j.get('target_url') or '')[:60]}"
                        )
                        continue
                    except Exception as e:
                        logger.warning(
                            f"Could not auto-resume RUT job {jid}: {e}. Marking failed."
                        )

                # ─── Case 2: PARTIAL RUN — preserve results ─────────
                # Reached only when auto-resume failed (couldn't find user/link
                # or restart_count maxed out). Try to package any partial
                # results left on disk and show a friendly explanation.
                zip_path = await _package_partial_results(jid)
                if prev_status == "running" and processed > 0:
                    updates = {
                        "status": "stopped",
                        "finished_at": now_iso,
                        "stop_reason": (
                            f"Job interrupted by repeated backend restarts. "
                            f"Auto-resume tried {rc} times with exponential backoff "
                            f"but prep kept failing — something fundamental is broken "
                            f"(check System Health page for red tiles + click "
                            f"'Auto Repair All'). Partial results ({processed} processed) "
                            f"have been packaged. Click 'Retry this job' once the "
                            f"underlying issue is fixed — your live-deleted gsheet "
                            f"rows are already removed so no duplicates will run."
                        ),
                    }
                    reaped_running += 1
                else:
                    # ─── Case 3: NON-RESUMABLE — mark failed ─────────
                    if rc >= 10:
                        msg = (
                            f"Auto-resume gave up after {rc} attempts. "
                            "Backend keeps restarting before this job can complete. "
                            "Click 'Retry this job' to try again with a fresh restart counter, "
                            "or check `/api/diagnostics/health` and recent backend logs."
                        )
                    elif not j.get("is_resumable"):
                        msg = (
                            "Backend container restarted before this job could start. "
                            "Job had inline file uploads (Excel / target screenshot) "
                            "which can't be auto-resumed across restarts. "
                            "Please re-submit the job — your uploads are still saved."
                        )
                    else:
                        msg = (
                            "Backend container restarted before this job could start. "
                            "Auto-resume metadata was incomplete. "
                            "Check `/api/diagnostics/health` and re-submit."
                        )
                    updates = {
                        "status": "failed",
                        "finished_at": now_iso,
                        "error_message": msg,
                        "preparing": False,
                    }
                    reaped_queued += 1
                if zip_path:
                    updates["zip_path"] = zip_path
                await db.real_user_traffic_jobs.update_one(
                    {"job_id": jid}, {"$set": updates}
                )
            logger.info(
                f"Reaped real-user-traffic jobs on startup: "
                f"{resumed} auto-resumed, {reaped_running} running→stopped, "
                f"{reaped_queued} queued→failed"
            )
    except Exception as e:
        logger.warning(f"Could not reap orphan real-user-traffic jobs: {e}")

@app.on_event("shutdown")
async def shutdown_db_client():
    client.close()

# WebSocket endpoint for real-time click updates
@app.websocket("/ws/clicks/{token}")
async def websocket_clicks(websocket: WebSocket, token: str):
    """WebSocket endpoint for real-time click updates"""
    try:
        # Verify token — try local JWT first, then v2.1.16 cloud fallback.
        user = None
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
            email = payload.get("sub")
            if not email:
                await websocket.close(code=4001)
                return
            user = await db.users.find_one({"email": email}, {"_id": 0})
        except JWTError:
            cloud_user = await _resolve_cloud_user_dict(f"Bearer {token}")
            if not cloud_user:
                await websocket.close(code=4003)
                return
            user = cloud_user

        if not user or user.get("status") != "active":
            await websocket.close(code=4002)
            return
        
        user_id = user["id"]
        await manager.connect(websocket, user_id)
        
        try:
            while True:
                # Keep connection alive, listen for any client messages
                data = await websocket.receive_text()
                if data == "ping":
                    await websocket.send_text("pong")
        except WebSocketDisconnect:
            manager.disconnect(websocket, user_id)
    except JWTError:
        await websocket.close(code=4003)


# ════════════════════════════════════════════════════════════════════════
# 2026-01 Customer-launch readiness — startup hooks
# ════════════════════════════════════════════════════════════════════════
# Pure-additive — these hooks run AFTER all existing startup logic so
# nothing existing is changed. Each is independently safe-failed so a
# single component issue can never block backend boot.

@app.on_event("startup")
async def _krexion_customer_startup_tasks():
    """Customer-launch readiness tasks. Safe-failed individually.

    Tasks:
      1. Kick off background install of the FULL Playwright chromium
         binary if it is missing. Lets fresh customer installs reach
         maximum RUT stealth (--headless=new mode) on the very first
         job without the customer needing to run any extra command.
      2. Run the license-module hardening checks (HWID derive, anti-debug
         scan, integrity self-check). License module supplies a no-op
         function if any check is unavailable so nothing breaks.
    """
    # v2.1.70 — Silence noisy "Future exception was never retrieved:
    # TargetClosedError(...)" log lines that come from RUT browser
    # tear-down races (an internal Playwright watcher future resolves
    # AFTER the page/context was already closed by the engine). They
    # are harmless cleanup-order races, not real failures — but the
    # default asyncio handler logs them at ERROR level, which scares
    # both ops and customers. Demote to debug.
    try:
        import asyncio as _aio
        _loop = _aio.get_running_loop()
        def _kx_excl_handler(loop, context):
            exc = context.get("exception")
            if exc is not None and type(exc).__name__ == "TargetClosedError":
                logger.debug(f"[playwright cleanup race] {exc} — ignored")
                return
            loop.default_exception_handler(context)
        _loop.set_exception_handler(_kx_excl_handler)
    except Exception as _eh_e:
        logger.debug(f"could not install playwright exc filter: {_eh_e}")
    # 1. Auto-install full chromium in the background
    try:
        # Respect the existing VPS safety flag — cloud edge / shared
        # hosts use STRICT_CLOUD_HEAVY_BLOCK=true (default) to skip the
        # ~165 MB chromium download because heavy features run on the
        # customer desktop app, not on the VPS. Only auto-install when
        # this flag is False (i.e. customer-binary / native install).
        # Uses the existing module-level constant computed at import.
        if STRICT_CLOUD_HEAVY_BLOCK:
            logger.info("Krexion: STRICT_CLOUD_HEAVY_BLOCK=true — skipping auto chromium install (VPS mode)")
        else:
            import real_user_traffic as _rut_mod
            # Only trigger if the helper exists AND the full binary is not
            # already present — keeps idempotent across hot-reloads.
            if hasattr(_rut_mod, "_install_full_chromium_background") and \
               hasattr(_rut_mod, "_full_chromium_binary_path"):
                try:
                    if _rut_mod._full_chromium_binary_path() is None:
                        # Fire-and-forget; never blocks startup. Logs its own
                        # success/failure inside the helper.
                        asyncio.create_task(_rut_mod._install_full_chromium_background())
                        logger.info("Krexion: full chromium auto-install scheduled in background")
                    else:
                        logger.info("Krexion: full chromium already present — --headless=new mode active")
                except Exception as _ch_e:
                    logger.debug(f"Auto chromium install skipped: {_ch_e}")
    except Exception as _imp_e:
        logger.debug(f"Chromium import error: {_imp_e}")

    # 2. ── 2026-02 Step 6 — Zero-touch browser bootstrap ──────────────
    # Auto-download Brave portable + ensure Chromium so Browser Binary
    # Rotation (Step 3) works on day-1 across Electron / Native / VPS
    # without ANY manual customer install. Fire-and-forget; safe-fails.
    try:
        import browser_bootstrap as _bb
        asyncio.create_task(_bb.bootstrap_browsers_async())
        logger.info("Krexion: browser auto-bootstrap scheduled (Brave + Chromium)")
    except Exception as _bb_err:  # noqa: BLE001
        logger.warning(f"Krexion: browser bootstrap scheduling failed: {_bb_err}")

    # 2. License hardening — best-effort
    try:
        import license_module as _lm
        if hasattr(_lm, "run_customer_launch_hardening"):
            try:
                _lm.run_customer_launch_hardening()
            except Exception as _lm_e:
                logger.debug(f"License hardening skipped: {_lm_e}")
    except Exception as _imp_e:
        logger.debug(f"License hardening hook skipped: {_imp_e}")



# ─── Local UI static mount — DISABLED in v1.0.14 ─────────────────────
# Per customer requirement: "heavy job k liye local link use ni ho ga
# always krexion.com he use ho ga". The local backend's job is to
# RUN heavy jobs (executed via the bridge worker which polls cloud
# for queued jobs) - not to serve a UI. Customer always opens
# krexion.com in their browser; cloud auto-routes their heavy jobs to
# the desktop bridge worker on the customer's PC.
# (v1.0.13 mounted /static + a SPA catch-all here; that block is
# removed to restore the simple cloud-only UI flow.)
